import styles from './AggregatedAssetDistribution.module.scss';
import { renderBase } from '@/components/tables/TableCellRenderer';

type TopNOption = 5 | 10 | 0;
type MinPctOption = 0 | 1 | 5 | 10;
type Mode = 'single' | 'aggregate';

interface AssetItem {
    name: string;
    value: number;
    percentage: number;
    color?: string;
    logoUri?: string;
    tokenAddress?: string;
    symbol?: string;
}

interface WalletRow {
    walletName: string;
    walletAddress: string;
    netWorth: number;
    uniqueTokenCount: number;
    data: AssetItem[];
}

interface WalletIdentityCellValue {
    label: string;
    walletAddress: string;
    toString: () => string;
}

function shortAddress(address: string): string {
    if (!address) return '';
    if (address.length <= 12) return address;
    return `${address.slice(0, 6)}...${address.slice(-4)}`;
}

function compactWalletLabel(label: string, walletAddress: string): string {
    const normalized = (label || walletAddress || '').trim();
    if (!normalized) return '';

    const looksLikeAddress = /^[1-9A-HJ-NP-Za-km-z]{24,}$/.test(normalized) || normalized === walletAddress;
    if (looksLikeAddress) {
        return shortAddress(normalized);
    }

    const maxLen = 18;
    if (normalized.length <= maxLen) return normalized;
    return `${normalized.slice(0, maxLen - 3)}...`;
}

function tokenKey(asset: AssetItem): string {
    return asset.tokenAddress || asset.symbol || asset.name;
}

function applyGrouping(
    raw: AssetItem[],
    topN: TopNOption,
    minPct: MinPctOption,
    othersLabel: string,
): (AssetItem & { hiddenNames?: string[] })[] {
    if (raw.length === 0) return [];

    const rawTotal = raw.reduce((s, a) => s + a.value, 0);
    const withPct = raw
        .map(a => ({ ...a, percentage: rawTotal > 0 ? (a.value / rawTotal) * 100 : 0 }))
        .sort((a, b) => b.value - a.value);

    const afterMinPct = minPct > 0
        ? withPct.filter(a => a.percentage >= minPct)
        : withPct;

    const kept = topN > 0 ? afterMinPct.slice(0, topN) : afterMinPct;

    const keptSet = new Set(kept.map(a => a.name));
    const hidden = withPct.filter(a => !keptSet.has(a.name));

    if (hidden.length === 0) return kept;

    const othersValue = hidden.reduce((s, a) => s + a.value, 0);
    const newTotal = kept.reduce((s, a) => s + a.value, 0) + othersValue;

    const recalcKept = kept.map(a => ({
        ...a,
        percentage: newTotal > 0 ? (a.value / newTotal) * 100 : 0,
    }));

    const othersItem = {
        name: othersLabel,
        value: othersValue,
        percentage: newTotal > 0 ? (othersValue / newTotal) * 100 : 0,
        hiddenNames: hidden.map(a => a.name),
    };

    return [...recalcKept, othersItem];
}

function aggregateWallets(wallets: WalletRow[]): AssetItem[] {
    if (wallets.length === 0) return [];

    const aggregate = new Map<string, AssetItem>();

    wallets.forEach((wallet) => {
        wallet.data.forEach((asset) => {
            const key = tokenKey(asset);
            const existing = aggregate.get(key);
            if (existing) {
                existing.value += asset.value;
            } else {
                aggregate.set(key, {
                    name: asset.name,
                    value: asset.value,
                    percentage: 0,
                    color: asset.color,
                    logoUri: asset.logoUri,
                    tokenAddress: asset.tokenAddress,
                    symbol: asset.symbol,
                });
            }
        });
    });

    return Array.from(aggregate.values());
}

type AssetDistributionData = InferFetcherData<typeof fetchAssetDistribution>;

export const AggregatedAssetDistribution: React.FC<ChartProps> = ({
    minHeight = 400,
    initialFilters,
    autoRefresh = true,
    refreshInterval = 30000,
    fetchEnabled = true,
    className,
}) => {
    const { tr, fmt } = useLocalization();
    const baseOption = useCarbonChartBaseOption();
    const { selectedTimezone: timezone } = useChartContext();

    const tokens = useCarbonTokens({ background: cds.background });
    const chartTitle = tr('charts.aggregatedAssetDistributionChart.title');
    const othersLabel = tr('charts.aggregatedAssetDistributionChart.others');

    const chartRef = useRef<ReactECharts>(null);

    const [mode, setMode] = useState<Mode>('single');
    const [topN, setTopN] = useState<TopNOption>(5);
    const [minPct, setMinPct] = useState<MinPctOption>(0);
    const [activeWalletAddress, setActiveWalletAddress] = useState<string>('');
    const [selectedWallets, setSelectedWallets] = useState<Set<string>>(new Set());

    const { filters, walletsString } = useChartFiltersSync({
        initialFilters,
        debounceDelay: 300,
    });

    const query = useMemo<DistributionRequestParams>(
        () => ({
            period: filters.timePeriod,
            wallets: walletsString,
        }),
        [filters.timePeriod, walletsString],
    );

    const { data, loadingState, refetch } =
        useStandardChartController<AssetDistributionData, DistributionRequestParams>({
            fetcher: fetchAssetDistribution,
            query,
            autoRefresh,
            refreshInterval,
            enabled: fetchEnabled,
        });

    const walletRows = useMemo<WalletRow[]>(() => {
        if (!data) return [];

        if ('wallets' in data && data.wallets && data.wallets.length > 0) {
            return data.wallets.map((wallet) => {
                const tokenData = wallet.data as AssetItem[];
                const netWorth = typeof wallet.totalValue === 'number'
                    ? wallet.totalValue
                    : tokenData.reduce((sum, item) => sum + item.value, 0);

                const uniqueTokenCount = new Set(tokenData.map(item => tokenKey(item))).size;

                return {
                    walletName: wallet.walletAddress,
                    walletAddress: wallet.walletAddress,
                    netWorth,
                    uniqueTokenCount,
                    data: tokenData,
                };
            });
        }

        if ('data' in data && Array.isArray(data.data) && data.data.length > 0) {
            const fallbackAddress = filters.wallets?.[0] ?? tr('charts.aggregatedAssetDistributionChart.walletTable.unknownWallet');
            const tokenData = data.data as AssetItem[];
            const netWorth = tokenData.reduce((sum, item) => sum + item.value, 0);

            return [
                {
                    walletName: fallbackAddress,
                    walletAddress: fallbackAddress,
                    netWorth,
                    uniqueTokenCount: new Set(tokenData.map(item => tokenKey(item))).size,
                    data: tokenData,
                },
            ];
        }

        return [];
    }, [data, filters.wallets, tr]);

    useEffect(() => {
        if (walletRows.length === 0) {
            setActiveWalletAddress('');
            setSelectedWallets(new Set());
            return;
        }

        const walletSet = new Set(walletRows.map(wallet => wallet.walletAddress));

        setActiveWalletAddress((prev) => {
            if (prev && walletSet.has(prev)) return prev;
            return walletRows[0].walletAddress;
        });

        setSelectedWallets((prev) => {
            const next = new Set(Array.from(prev).filter(address => walletSet.has(address)));
            if (next.size === 0) {
                walletRows.forEach((wallet) => next.add(wallet.walletAddress));
            }
            return next;
        });
    }, [walletRows]);

    useEffect(() => {
        if (mode !== 'aggregate' || walletRows.length === 0) return;
        setSelectedWallets((prev) => {
            if (prev.size > 0) return prev;
            return new Set(walletRows.map(wallet => wallet.walletAddress));
        });
    }, [mode, walletRows]);

    const modeWallets = useMemo(() => {
        if (walletRows.length === 0) return [] as WalletRow[];

        if (mode === 'single') {
            const active = walletRows.find(w => w.walletAddress === activeWalletAddress);
            return active ? [active] : [walletRows[0]];
        }

        return walletRows.filter(w => selectedWallets.has(w.walletAddress));
    }, [walletRows, mode, activeWalletAddress, selectedWallets]);

    const modeRawTokens = useMemo<AssetItem[]>(() => {
        if (modeWallets.length === 0) return [];
        if (mode === 'single') return modeWallets[0].data;
        return aggregateWallets(modeWallets);
    }, [modeWallets, mode]);

    const groupedTokens = useMemo(
        () => applyGrouping(modeRawTokens, topN, minPct, othersLabel),
        [modeRawTokens, topN, minPct, othersLabel],
    );

    const displayTotal = useMemo(
        () => groupedTokens.reduce((sum, token) => sum + token.value, 0),
        [groupedTokens],
    );

    const { exportPNG, exportSVG, exportPDF, exportCSV } = useChartExport({
        chartTitle,
        timezone,
        baseFilename: 'aggregated-asset-distribution',
    });

    const handleExport = useCallback(async (format: ExportFormat) => {
        if (!data) return;

        const instance = chartRef.current?.getEchartsInstance() ?? null;
        const csv: ChartDataSeries[] = [
            {
                id: 'aggregated-asset-distribution',
                name: tr('charts.aggregatedAssetDistributionChart.export.name'),
                type: 'pie',
                visible: true,
                data: groupedTokens.map(token => ({
                    name: token.name,
                    value: token.value,
                })),
            },
        ];

        const selectedCountLabel = tr('charts.aggregatedAssetDistributionChart.walletTable.selectedCount')
            .replace('{count}', String(selectedWallets.size));

        await runChartExport(
            {
                format,
                filters,
                chartInstance: instance as any,
                csvData: csv,
                csvFilters: { ...filters, wallets: [] },
                extraFilters: {
                    [tr('charts.aggregatedAssetDistributionChart.mode.label')]: mode === 'single'
                        ? tr('charts.aggregatedAssetDistributionChart.mode.single')
                        : tr('charts.aggregatedAssetDistributionChart.mode.aggregate'),
                    [tr('charts.aggregatedAssetDistributionChart.walletTable.selection')]: mode === 'single'
                        ? shortAddress(activeWalletAddress)
                        : selectedCountLabel,
                    [tr('charts.aggregatedAssetDistributionChart.filters.topN')]: topN === 0
                        ? tr('charts.aggregatedAssetDistributionChart.filters.all')
                        : `${tr('charts.aggregatedAssetDistributionChart.filters.top')} ${topN}`,
                    [tr('charts.aggregatedAssetDistributionChart.filters.minValue')]: minPct === 0
                        ? tr('charts.aggregatedAssetDistributionChart.filters.all')
                        : `>${minPct}%`,
                },
            },
            { exportPNG, exportSVG, exportPDF, exportCSV },
        );
    }, [
        data,
        groupedTokens,
        filters,
        tr,
        mode,
        selectedWallets.size,
        activeWalletAddress,
        topN,
        minPct,
        exportPNG,
        exportSVG,
        exportPDF,
        exportCSV,
    ]);

    const option = useMemo<EChartsOption>(() => {
        return {
            ...baseOption,
            xAxis: undefined,
            yAxis: undefined,
            tooltip: {
                ...baseOption.tooltip,
                trigger: 'item',
                formatter: (p: any) => {
                    const isOthers = p.name === othersLabel;
                    const logoUri: string | undefined = p.data.logoUri;
                    const logoHtml = logoUri
                        ? `<img src="${logoUri}" alt="${p.name}" width="16" height="16" style="border-radius:50%;vertical-align:middle;margin-right:4px;" onerror="this.style.display='none'">`
                        : '';

                    let html = createTooltipHeader(`${logoHtml}${p.name}`);
                    if (isOthers && p.data.hiddenNames?.length > 0) {
                        html += `<div style="max-height:160px;overflow-y:auto;margin-bottom:4px;">`;
                        html += (p.data.hiddenNames as string[])
                            .map((n) => `<div style="padding:1px 0;font-size:11px;color:var(--cds-text-secondary)">• ${n}</div>`)
                            .join('');
                        html += `</div>`;
                    }
                    html += createTooltipRow(
                        tr('charts.aggregatedAssetDistributionChart.value'),
                        fmt.num.compact.currency(Number(p.value ?? 0)),
                    );
                    html += createTooltipRow(
                        tr('charts.aggregatedAssetDistributionChart.percentage'),
                        `${p.data.percentage.toFixed(2)}%`,
                    );
                    return html;
                },
            },
            // legend: {
            //     show: true,
            //     orient: 'horizontal',
            //     bottom: 0,
            //     left: 'center',
            //     data: groupedTokens.map(token => token.name),
            //     icon: 'circle',
            //     textStyle: { color: baseOption.textStyle.color, fontSize: 12 },
            //     tooltip: {
            //         show: true,
            //         formatter: (params: any) => {
            //             const name = params.name ?? params;
            //             const item = groupedTokens.find(g => g.name === name);
            //             const hidden: string[] = (item as any)?.hiddenNames ?? [];
            //             if (name !== othersLabel || hidden.length === 0) return name;
            //             return (
            //                 `<strong>${name}</strong><br/>` +
            //                 hidden.map(n => `• ${n}`).join('<br/>')
            //             );
            //         },
            //     } as any,
            // },
            legend: {
                show: false
            },
            series: [
                {
                    type: 'pie',
                    radius: ['28%', '58%'],
                    center: ['50%', '52%'],
                    data: groupedTokens.map((token, index) => ({
                        name: token.name,
                        value: token.value,
                        percentage: token.percentage,
                        hiddenNames: (token as any).hiddenNames,
                        logoUri: token.logoUri,
                        itemStyle: {
                            color: token.name === othersLabel
                                ? '#6f6f6f'
                                : token.color ?? CHART_COLOR_PALETTE[index % CHART_COLOR_PALETTE.length],
                            borderColor: '#ffffff',
                            borderWidth: 2,
                            borderRadius: 6,
                        },
                    })),
                    label: {
                        formatter: (p: any) => `${p.name}\n${p.data.percentage.toFixed(1)}%`,
                        color: baseOption.textStyle.color,
                        fontSize: 11,
                    },
                },
            ],
            graphic: [
                {
                    type: 'text',
                    left: 'center',
                    top: '46%',
                    style: {
                        text: tr('charts.aggregatedAssetDistributionChart.totalValue'),
                        fill: baseOption.textStyle.color,
                        fontSize: 14,
                        opacity: 0.7,
                    },
                },
                {
                    type: 'text',
                    left: 'center',
                    top: '50%',
                    style: {
                        text: fmt.num.compact.currency(displayTotal),
                        fill: baseOption.textStyle.color,
                        fontSize: 18,
                        fontWeight: 'bold',
                    },
                },
            ],
        };
    }, [baseOption, tokens, groupedTokens, othersLabel, tr, displayTotal, fmt]);

    const toggleWalletSelected = useCallback((walletAddress: string, checked: boolean) => {
        setSelectedWallets((prev) => {
            const next = new Set(prev);
            if (checked) {
                next.add(walletAddress);
            } else if (next.has(walletAddress) && next.size > 1) {
                next.delete(walletAddress);
            }
            return next;
        });
    }, []);

    const tableHeaders = useMemo<TableColumnHeader[]>(() => {
        if (mode === 'aggregate') {
            return [
                { header: tr('charts.aggregatedAssetDistributionChart.walletTable.isSelected'), minWidth: '7rem', align: 'center' },
                { header: tr('charts.aggregatedAssetDistributionChart.walletTable.wallet'), minWidth: '9rem' },
                { header: tr('charts.aggregatedAssetDistributionChart.walletTable.netWorth'), minWidth: '9rem', align: 'end' },
                { header: tr('charts.aggregatedAssetDistributionChart.walletTable.uniqueTokenCount'), minWidth: '8rem', align: 'end' },
            ];
        }

        return [
            { header: tr('charts.aggregatedAssetDistributionChart.walletTable.wallet'), minWidth: '9rem' },
            { header: tr('charts.aggregatedAssetDistributionChart.walletTable.netWorth'), minWidth: '9rem', align: 'end' },
            { header: tr('charts.aggregatedAssetDistributionChart.walletTable.uniqueTokenCount'), minWidth: '8rem', align: 'end' },
        ];
    }, [mode, tr]);

    const tableRows = useMemo<any[][]>(() => {
        return walletRows.map((wallet) => {
            const walletIdentity: WalletIdentityCellValue = {
                label: wallet.walletName || wallet.walletAddress,
                walletAddress: wallet.walletAddress,
                toString: () => wallet.walletName || wallet.walletAddress,
            };

            if (mode === 'aggregate') {
                return [
                    selectedWallets.has(wallet.walletAddress),
                    walletIdentity,
                    wallet.netWorth,
                    wallet.uniqueTokenCount,
                ];
            }

            return [
                walletIdentity,
                wallet.netWorth,
                wallet.uniqueTokenCount,
            ];
        });
    }, [walletRows, mode, selectedWallets]);

    const tableCellRenderers = useMemo(() => {
        const baseRenderers = [
            (value: unknown) => {
                const identity = value as WalletIdentityCellValue | undefined;
                const walletAddress = identity?.walletAddress ?? '';
                const label = identity?.label || walletAddress;
                const displayLabel = compactWalletLabel(label, walletAddress);

                return (
                    <a
                        href={`/wallets/${encodeURIComponent(walletAddress)}`}
                        className={`${styles.walletName} ${styles.walletAddress}`}
                        title={`${walletAddress}`}
                        onClick={(event) => event.stopPropagation()}
                    >
                        {displayLabel}
                    </a>
                );
            },
            (value: unknown) => renderBase(value, (text) => fmt.num.compact.currency(Number(text ?? 0))),
            (value: unknown) => <span className={styles.countValue}>{Number(value ?? 0).toLocaleString()}</span>,
        ] as Array<((value: any, row: any[], rowIndex: number) => React.ReactNode) | null>;

        if (mode === 'aggregate') {
            const selectionRenderer = (_value: unknown, row: any[]) => {
                const walletAddress = String((row[1] as WalletIdentityCellValue | undefined)?.walletAddress ?? '');
                const isChecked = selectedWallets.has(walletAddress);
                const inputId = `agg-wallet-select-${walletAddress.replace(/[^a-zA-Z0-9_-]/g, '')}`;

                return (
                    <Checkbox
                        id={inputId}
                        labelText=""
                        hideLabel
                        checked={isChecked}
                        aria-label={tr('charts.aggregatedAssetDistributionChart.ariaLabels.walletSelector')
                            .replace('{wallet}', walletAddress)}
                        onChange={(event: unknown, state: { checked: boolean }) => {
                            if ((event as React.SyntheticEvent)?.stopPropagation) {
                                (event as React.SyntheticEvent).stopPropagation();
                            }
                            toggleWalletSelected(walletAddress, state.checked);
                        }}
                    />
                );
            };

            return [selectionRenderer, ...baseRenderers];
        }

        return baseRenderers;
    }, [mode, selectedWallets, toggleWalletSelected, tr]);

    const selectedCountText = tr('charts.aggregatedAssetDistributionChart.walletTable.selectedCount')
        .replace('{count}', String(selectedWallets.size));

    const walletTableTitle = mode === 'aggregate'
        ? `${tr('charts.aggregatedAssetDistributionChart.walletTable.title')} (${selectedCountText})`
        : tr('charts.aggregatedAssetDistributionChart.walletTable.title');

    const topNOptions: Array<{ value: TopNOption; label: string }> = [
        { value: 5, label: tr('charts.aggregatedAssetDistributionChart.filters.top5') },
        { value: 10, label: tr('charts.aggregatedAssetDistributionChart.filters.top10') },
        { value: 0, label: tr('charts.aggregatedAssetDistributionChart.filters.all') },
    ];

    const minPctOptions: Array<{ value: MinPctOption; label: string }> = [
        { value: 0, label: tr('charts.aggregatedAssetDistributionChart.filters.allPercent') },
        { value: 1, label: tr('charts.aggregatedAssetDistributionChart.filters.minPct1') },
        { value: 5, label: tr('charts.aggregatedAssetDistributionChart.filters.minPct5') },
        { value: 10, label: tr('charts.aggregatedAssetDistributionChart.filters.minPct10') },
    ];

    const isEmpty = !data || walletRows.length === 0 || groupedTokens.length === 0 || (filters.wallets && filters.wallets.length === 0);

    const modeOptions = [
        { value: 'single' as const, label: tr('charts.aggregatedAssetDistributionChart.mode.single') },
        { value: 'aggregate' as const, label: tr('charts.aggregatedAssetDistributionChart.mode.aggregate') },
    ];

    const headerControls = (
        <Flex gap={8} align="center" wrap="wrap">
            <div style={{ width: 160 }}>
                <FilterSwitch
                    options={modeOptions}
                    value={mode}
                    onChange={(v) => setMode(v as Mode)}
                />
            </div>
            <div style={{ width: 180 }}>
                <FilterSwitch
                    options={topNOptions}
                    value={topN}
                    onChange={(v) => setTopN(v as TopNOption)}
                />
            </div>
            <div style={{ width: 200 }}>
                <FilterSwitch
                    options={minPctOptions}
                    value={minPct}
                    onChange={(v) => setMinPct(v as MinPctOption)}
                />
            </div>
        </Flex>
    );

    return (
        <ChartWrapper
            title={chartTitle}
            toolbarLayout="stacked"
            loadingState={loadingState}
            isEmpty={false}
            onRetry={() => refetch(false)}
            onExport={handleExport}
            className={className}
            actions={headerControls}
        >
            <div className={styles.layout}>
                <div className={styles.panel}>
                    <Table
                        title={walletTableTitle}
                        headers={tableHeaders}
                        initialFilters={{}}
                        fetcher={Promise.resolve([])}
                        dataEntries={tableRows}
                        filterSchema={mode === 'aggregate'
                            ? {
                                2: {
                                    type: FilterType.Range,
                                    min: 0,
                                    max: Math.max(1000, ...walletRows.map((wallet) => wallet.netWorth || 0)),
                                    step: Math.max(1, Math.floor(Math.max(1000, ...walletRows.map((wallet) => wallet.netWorth || 0)) / 100)),
                                },
                                3: {
                                    type: FilterType.Range,
                                    min: 0,
                                    max: Math.max(100, ...walletRows.map((wallet) => wallet.uniqueTokenCount || 0)),
                                    step: 1,
                                },
                            }
                            : {
                                1: {
                                    type: FilterType.Range,
                                    min: 0,
                                    max: Math.max(1000, ...walletRows.map((wallet) => wallet.netWorth || 0)),
                                    step: Math.max(1, Math.floor(Math.max(1000, ...walletRows.map((wallet) => wallet.netWorth || 0)) / 100)),
                                },
                                2: {
                                    type: FilterType.Range,
                                    min: 0,
                                    max: Math.max(100, ...walletRows.map((wallet) => wallet.uniqueTokenCount || 0)),
                                    step: 1,
                                },
                            }}
                        isSortable={mode === 'aggregate'
                            ? [false, false, true, true]
                            : [false, true, true]}
                        sortConfigs={mode === 'aggregate'
                            ? {
                                2: { type: SortType.Number },
                                3: { type: SortType.Number },
                            }
                            : {
                                1: { type: SortType.Number },
                                2: { type: SortType.Number },
                            }}
                        cellRenderers={tableCellRenderers}
                        enableExport={false}
                        loading={loadingState.status === 'loading'}
                        onRowClick={mode === 'single'
                            ? (row) => setActiveWalletAddress(String((row[0] as WalletIdentityCellValue | undefined)?.walletAddress ?? ''))
                            : undefined}
                        // rowClassName={mode === 'single'
                        //     ? (row) => (String((row[0] as WalletIdentityCellValue | undefined)?.walletAddress ?? '') === activeWalletAddress ? tableStyles.activeRow : undefined)
                        //     : undefined}
                        maxHeight={Math.max(minHeight, 300)}
                    />
                </div>

                <div className={styles.panel}>
                    {
                        isEmpty && (
                            <div className={styles.emptyState}>
                                <p className={styles.emptyStateTitle}>
                                    {tr('charts.noDataTitle')}
                                </p>
                                <p className={styles.emptyStateMessage}>
                                    {tr('charts.noDataMessage')}
                                </p>
                            </div>
                        ) || (
                            <ReactECharts
                                ref={chartRef}
                                option={option}
                                className={styles.chartHost}
                                style={{ height: '100%', width: '100%', minHeight: `${minHeight}px` }}
                                notMerge
                                lazyUpdate
                            />
                        )
                    }

                </div>
            </div>
        </ChartWrapper>
    );
};

// client/src/components/charts/CandleStickChart/CandleStickChart.tsx

import React, { useEffect, useRef } from 'react';
import * as echarts from 'echarts';
import { useChartTheme } from '../../../hooks/useChartTheme.js';
import type { OHLCData } from '../../../util/finance-helpers.js';
import { calculateMA } from '../../../util/finance-helpers.js';

interface CandleStickChartProps {
    data: OHLCData[];
    title?: string;
    height?: number;
}

export const CandleStickChart = ({ data, title, height = 500 }: CandleStickChartProps) => {
    const chartRef = useRef<HTMLDivElement>(null);
    const chartInstance = useRef<echarts.ECharts | null>(null);

    const chartTheme = useChartTheme() as { isDark?: boolean; theme?: string; mode?: string };
    const isDark: boolean =
        typeof chartTheme?.isDark === 'boolean'
            ? chartTheme.isDark
            : chartTheme?.theme === 'dark' || chartTheme?.mode === 'dark';

    const categoryData = data.map(item => item.time);
    const values = data.map(item => [item.open, item.close, item.low, item.high]);

    useEffect(() => {
        if (!chartRef.current) return;

        if (chartInstance.current) {
            chartInstance.current.dispose();
        }

        chartInstance.current = echarts.init(chartRef.current, isDark ? 'dark' : undefined);

        const upColor = '#ec0000';
        const upBorderColor = '#8A0000';
        const downColor = '#00da3c';
        const downBorderColor = '#008F28';

        const option: echarts.EChartsOption = {
            backgroundColor: 'transparent',
            title: {
                text: title || '',
                left: 0,
                textStyle: {
                    color: isDark ? '#f4f4f4' : '#161616'
                }
            },
            tooltip: {
                trigger: 'axis',
                axisPointer: { type: 'cross' },
                backgroundColor: isDark ? '#262626' : '#ffffff',
                borderColor: '#8d8d8d',
                textStyle: {
                    color: isDark ? '#f4f4f4' : '#161616'
                }
            },
            legend: {
                data: ['Candle', 'MA5', 'MA10', 'MA20', 'MA30'],
                top: 20,
                textStyle: {
                    color: isDark ? '#c6c6c6' : '#525252'
                }
            },
            grid: {
                left: '3%',
                right: '3%',
                bottom: '15%',
                containLabel: true
            },
            xAxis: {
                type: 'category',
                data: categoryData,
                boundaryGap: false,
                axisLine: { onZero: false, lineStyle: { color: '#8d8d8d' } },
                splitLine: { show: false },
                min: 'dataMin',
                max: 'dataMax'
            },
            yAxis: {
                scale: true,
                splitArea: { show: false },
                splitLine: { show: true, lineStyle: { color: isDark ? '#393939' : '#e0e0e0' } }
            },
            dataZoom: [
                { type: 'inside', start: 50, end: 100 },
                { type: 'slider', show: true, top: '90%', start: 50, end: 100 }
            ],
            series: [
                {
                    name: 'Candle',
                    type: 'candlestick',
                    data: values,
                    itemStyle: {
                        color: upColor,
                        color0: downColor,
                        borderColor: upBorderColor,
                        borderColor0: downBorderColor
                    }
                },
                {
                    name: 'MA5',
                    type: 'line',
                    data: calculateMA(5, data),
                    smooth: true,
                    lineStyle: { opacity: 0.5 }
                },
                {
                    name: 'MA10',
                    type: 'line',
                    data: calculateMA(10, data),
                    smooth: true,
                    lineStyle: { opacity: 0.5 }
                },
                {
                    name: 'MA20',
                    type: 'line',
                    data: calculateMA(20, data),
                    smooth: true,
                    lineStyle: { opacity: 0.5 }
                },
                {
                    name: 'MA30',
                    type: 'line',
                    data: calculateMA(30, data),
                    smooth: true,
                    lineStyle: { opacity: 0.5 }
                }
            ]
        };

        chartInstance.current.setOption(option);

        const handleResize = () => chartInstance.current?.resize();
        window.addEventListener('resize', handleResize);

        return () => {
            window.removeEventListener('resize', handleResize);
            chartInstance.current?.dispose();
        };
    }, [data, isDark, title]);

    return <div ref={chartRef} style={{ width: '100%', height: `${height}px` }} />;
};

import { useChartContext } from "@/contexts/ChartContext";
import { useLocalization } from "@/contexts/LocalizationContext";
import { useChartFiltersSync } from "@/hooks/useChartFiltersSync";
import {
  CHART_COLOR_PALETTE,
  useCarbonChartBaseOption,
} from "@/util/carbon-chart-base";
import {
  fetchDrawdown,
  type InferFetcherData,
} from "@/services/chart/chartApi";
import type { DrawdownRequestParams } from "@/types/chart-api.types";
import { formatTimestampWithTimezone } from "@/util/chart-helpers";
import type { EChartsOption } from "echarts";
import ReactECharts from "echarts-for-react";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import styles from "./Drawdown.module.scss";

type DrawdownData = InferFetcherData<typeof fetchDrawdown>;

type WalletSeriesMeta = {
  walletAddress: string;
  walletName: string;
  drawdownResult: Array<{
    timestamp: number;
    drawdown: number;
    value?: number;
    peak?: number;
    trough?: number;
    date?: string;
  }>;
  color: string;
};

import { useStandardChartController } from "@/hooks/useChartController";
import { ChartWrapper, ChartContainer, ChartGridItem, ChartSection, ChartStatsHeader } from "../shared";
import type { ChartProps } from "../shared/ChartProp";
import type { StatCard } from "../shared/ChartStatsHeader";

export function DrawdownChart({
  title,
  minHeight = 400,
  initialFilters = {
    timePeriod: "30D",
    wallets: [],
  },
  autoRefresh = true,
  refreshInterval = 30000,
  fetchEnabled = true,
  actions,
}: ChartProps) {
  const { tr, fmt } = useLocalization();
  const chartTitle = title || tr("charts.drawdownChart.title");

  const chartRef = useRef<ReactECharts>(null);
  const baseOption = useCarbonChartBaseOption();
  const { selectedTimezone: timezone } = useChartContext();

  const { filters, walletsString } = useChartFiltersSync({
    initialFilters,
    debounceDelay: 300,
  });

  const query = useMemo<DrawdownRequestParams>(
    () => ({
      period: filters.timePeriod,
      wallets: walletsString,
    }),
    [filters.timePeriod, walletsString],
  );

  const { data, loadingState, refetch } = useStandardChartController<
    DrawdownData,
    DrawdownRequestParams
  >({
    fetcher: fetchDrawdown,
    query,
    autoRefresh,
    refreshInterval,
    enabled: fetchEnabled,
  });

  const getSeriesColor = useCallback(
    (index: number) => CHART_COLOR_PALETTE[index % CHART_COLOR_PALETTE.length],
    [],
  );

  const walletSeriesMeta = useMemo<WalletSeriesMeta[]>(() => {
    if (
      !data ||
      "error" in data ||
      !data.wallets ||
      !Array.isArray(data.wallets) ||
      data.wallets.length === 0
    ) {
      return [];
    }

    return data.wallets.map((wallet: any, index: number) => ({
      walletAddress: String(wallet.walletAddress || ""),
      walletName: String(wallet.walletName || wallet.walletAddress || ""),
      drawdownResult: Array.isArray(wallet.drawdownResult)
        ? wallet.drawdownResult
          .map((item: any) => ({
            timestamp: Number(item.timestamp),
            drawdown: Number(item.drawdown),
            value: item.value != null ? Number(item.value) : undefined,
            peak: item.peak != null ? Number(item.peak) : undefined,
            trough: item.trough != null ? Number(item.trough) : undefined,
            date: item.date,
          }))
          .filter((item: any) => Number.isFinite(item.timestamp) && Number.isFinite(item.drawdown))
        : [],
      color: getSeriesColor(index),
    }));
  }, [data, getSeriesColor]);

  const [visibleWalletAddresses, setVisibleWalletAddresses] = useState<Set<string>>(new Set());

  useEffect(() => {
    if (walletSeriesMeta.length === 0) {
      setVisibleWalletAddresses(new Set());
      return;
    }

    setVisibleWalletAddresses((prev) => {
      const validWallets = walletSeriesMeta.map((wallet) => wallet.walletAddress);
      const next = new Set(validWallets.filter((walletAddress) => prev.has(walletAddress)));

      if (next.size === 0) {
        validWallets.forEach((walletAddress) => next.add(walletAddress));
      }

      return next;
    });
  }, [walletSeriesMeta]);

  const toggleWalletVisibility = useCallback((walletAddress: string) => {
    setVisibleWalletAddresses((prev) => {
      const next = new Set(prev);

      if (next.has(walletAddress)) {
        if (next.size === 1) {
          return prev;
        }
        next.delete(walletAddress);
        return next;
      }

      next.add(walletAddress);
      return next;
    });
  }, []);

  const visibleWalletSeriesMeta = useMemo(
    () => walletSeriesMeta.filter((wallet) => visibleWalletAddresses.has(wallet.walletAddress)),
    [walletSeriesMeta, visibleWalletAddresses],
  );

  const compactWalletLabel = useCallback((label: string, walletAddress: string) => {
    const normalized = (label || walletAddress || "").trim();
    if (!normalized) return "";

    const looksLikeAddress =
      /^[1-9A-HJ-NP-Za-km-z]{24,}$/.test(normalized) || normalized === walletAddress;
    if (looksLikeAddress) {
      if (normalized.length <= 12) return normalized;
      return `${normalized.slice(0, 6)}...${normalized.slice(-4)}`;
    }

    const maxLen = 18;
    if (normalized.length <= maxLen) return normalized;
    return `${normalized.slice(0, maxLen - 3)}...`;
  }, []);

  const chartOption = useMemo((): EChartsOption | null => {
    if (visibleWalletSeriesMeta.length === 0) {
      return null;
    }

    const series = visibleWalletSeriesMeta.map((wallet) => ({
      name: wallet.walletName,
      type: "line" as const,
      data: wallet.drawdownResult.map((d) => [d.timestamp, d.drawdown * 100]),
      smooth: false,
      lineStyle: {
        color: wallet.color,
        width: 2,
      },
      itemStyle: {
        color: wallet.color,
      },
      areaStyle: {
        color: {
          type: "linear" as const,
          x: 0,
          y: 0,
          x2: 0,
          y2: 1,
          colorStops: [
            {
              offset: 0,
              color: `${wallet.color}80`,
            },
            {
              offset: 1,
              color: `${wallet.color}20`,
            },
          ],
        },
      },
      symbol: "none" as const,
      emphasis: {
        focus: "series" as const,
      },
    }));

    return {
      ...baseOption,
      legend: { show: false },
      xAxis: {
        ...baseOption.xAxis,
        type: "time",
        axisLabel: {
          ...baseOption.xAxis.axisLabel,
          formatter: (value: number) =>
            formatTimestampWithTimezone(value, timezone, "MM/dd"),
        },
      },
      yAxis: {
        ...baseOption.yAxis,
        type: "value",
        name: "Drawdown (%)",
        max: 0,
        axisLabel: {
          ...baseOption.yAxis.axisLabel,
          formatter: "{value}%",
        },
      },
      series,
      tooltip: {
        ...baseOption.tooltip,
        trigger: "axis",
        axisPointer: {
          type: "cross",
        },
        formatter: (params: any) => {
          if (!Array.isArray(params)) return "";
          let tooltip = "";

          params.forEach((p: any) => {
            const timestamp = Number(p?.value?.[0]);
            const drawdownPct = Number(p?.value?.[1]);
            const wallet = visibleWalletSeriesMeta.find((w) => w.walletName === p.seriesName);
            const drawdownObj = wallet?.drawdownResult.find((d) => d.timestamp === timestamp);

            tooltip += `<div><strong>${p.seriesName}</strong></div>`;
            tooltip += `<div>${formatTimestampWithTimezone(timestamp, timezone, "yyyy-MM-dd HH:mm")}</div>`;
            if (Number.isFinite(drawdownPct)) {
              tooltip += `<div>Drawdown: ${drawdownPct.toFixed(2)}%</div>`;
            }
            if (drawdownObj?.value != null) {
              tooltip += `<div>Value: ${fmt.num.compact.currency(drawdownObj.value)}</div>`;
            }
            if (drawdownObj?.peak != null) {
              tooltip += `<div>Peak: ${fmt.num.compact.currency(drawdownObj.peak)}</div>`;
            }
            if (drawdownObj?.trough != null) {
              tooltip += `<div>Trough: ${fmt.num.compact.currency(drawdownObj.trough)}</div>`;
            }
            if (drawdownObj?.date) {
              tooltip += `<div>Date: ${drawdownObj.date}</div>`;
            }
            tooltip += '<hr style="margin:2px 0;opacity:0.2">';
          });

          return tooltip;
        },
      },
    };
  }, [visibleWalletSeriesMeta, baseOption, timezone, fmt]);

  const statsCards = useMemo<StatCard[]>(() => {
    if (walletSeriesMeta.length === 0) {
      return [];
    }

    return walletSeriesMeta.map((wallet) => {
      const { drawdownResult, walletAddress, walletName, color } = wallet;
      const isVisible = visibleWalletAddresses.has(walletAddress);

      const cardTitle = (
        <div className={styles.cardTitleRow}>
          <div className={styles.walletTitleWrap}>
            <span className={styles.walletColorDot} style={{ backgroundColor: color }} />
            <span className={styles.walletTitleText} title={walletName}>
              {compactWalletLabel(walletName, walletAddress)}
            </span>
          </div>
          <span className={`${styles.walletActiveIndicator} ${isVisible ? styles.walletActiveIndicatorOn : styles.walletActiveIndicatorOff}`}>
            {isVisible
              ? tr("charts.drawdownChart.visibility.active")
              : tr("charts.drawdownChart.visibility.hidden")}
          </span>
        </div>
      );

      if (!Array.isArray(drawdownResult) || drawdownResult.length === 0) {
        return {
          title: cardTitle,
          onClick: () => toggleWalletVisibility(walletAddress),
          isActive: isVisible,
          stats: [
            {
              label: "No data",
              value: "-",
              suffix: "",
              valueClassName: "text-muted",
            },
          ],
        };
      }

      const latest = drawdownResult[drawdownResult.length - 1];
      const maxDrawdown = Math.min(...drawdownResult.map((d) => d.drawdown));
      const maxDrawdownEntry = drawdownResult.find((d) => d.drawdown === maxDrawdown);
      const maxDrawdownTimestamp = maxDrawdownEntry ? maxDrawdownEntry.timestamp : null;
      const currentDrawdown = latest?.drawdown ?? 0;

      let daysSinceMaxDrawdown: number | null = null;
      if (maxDrawdownTimestamp) {
        const now = Date.now();
        const msPerDay = 24 * 60 * 60 * 1000;
        daysSinceMaxDrawdown = Math.floor((now - maxDrawdownTimestamp) / msPerDay);
      }

      return {
        title: cardTitle,
        onClick: () => toggleWalletVisibility(walletAddress),
        isActive: isVisible,
        stats: [
          {
            label: tr("charts.drawdownChart.stats.maxDrawdown"),
            value: (maxDrawdown * 100).toFixed(2),
            suffix: "%",
            valueClassName: "text-danger",
          },
          {
            label: tr("charts.drawdownChart.stats.daysSinceMaxDD"),
            value: daysSinceMaxDrawdown != null ? daysSinceMaxDrawdown : "-",
            suffix: tr("charts.drawdownChart.stats.days"),
          },
          {
            label: tr("charts.drawdownChart.stats.currentDrawdown"),
            value: (currentDrawdown * 100).toFixed(2),
            suffix: "%",
          },
          {
            label: tr("charts.drawdownChart.stats.maxDDDate"),
            value: maxDrawdownTimestamp
              ? formatTimestampWithTimezone(maxDrawdownTimestamp, timezone, "yyyy-MM-dd")
              : "-",
          },
        ],
      };
    });
  }, [walletSeriesMeta, visibleWalletAddresses, compactWalletLabel, toggleWalletVisibility, tr, timezone]);

  return (
    <ChartWrapper
      title={chartTitle}
      loadingState={loadingState}
      isEmpty={walletSeriesMeta.length === 0}
      onRetry={() => refetch(false)}
      actions={actions}
      enableFullscreen={false}
      enableExport={false}
    >
      <ChartContainer gap="0">
        <ChartStatsHeader cards={statsCards} minColumnWidth="300px" />
        <ChartSection minHeight={`${minHeight}px`}>
          {chartOption && (
            <ChartGridItem minHeight={minHeight}>
              <ReactECharts
                ref={chartRef}
                option={chartOption}
                style={{
                  height: "100%",
                  width: "100%",
                  minHeight: `${minHeight}px`,
                }}
                notMerge
                lazyUpdate
              />
            </ChartGridItem>
          )}
        </ChartSection>
      </ChartContainer>
    </ChartWrapper>
  );
}

import { useLocalization } from "@/contexts/LocalizationContext";
import { useCarbonTokens } from "@/hooks/useCarbonToken";
import { cds } from "@/util/carbon-theme";
import { attachChartDayClick } from "@/util/chart-click";
import { hashColor } from "@/util/color";
import { InlineLoading, Stack } from "@carbon/react";
import type { EChartsOption } from "echarts";
import ReactECharts from "echarts-for-react";
import { useEffect, useMemo, useRef } from "react";

export type TimeSeriesDataPoint = { unixTimeMs: number; value: number };

export type Series = {
  key: string;
  label?: string;
  data: TimeSeriesDataPoint[];
  color?: string;
  logoUri?: string;
};

export interface MultiTimeSeriesChartProps {
  series: Series[] | undefined;
  loading?: boolean;
  height?: number | string;
  className?: string;
  valueFormatter?: (v: number | null) => string;
  showLegend?: boolean;
  onClickDay?: (timestamp: number) => void;
  stacked?: boolean;
}

export function MultiTimeSeriesLineChart({
  series,
  loading = false,
  height = 300,
  className,
  valueFormatter,
  showLegend = true,
  onClickDay,
  stacked = false,
}: MultiTimeSeriesChartProps) {
  const { fmt, tr } = useLocalization();
  const chartRef = useRef<ReactECharts>(null);
  const tokens = useCarbonTokens({
    textPrimary: cds.textPrimary,
    textSecondary: cds.textSecondary,
    textHelper: cds.textHelper,
    borderSubtle: cds.borderSubtle00,
    bgInverse: cds.backgroundInverse,
    textInverse: cds.textInverse,
    success: cds.supportSuccess,
    error: cds.supportError,
    interactive: cds.interactive,
    layer: cds.layer02,
  });

  const prepared = useMemo(() => {
    if (!series || series.length == 0) return [];
    return series.map((s) => {
      const sorted = [...s.data].sort((a, b) => a.unixTimeMs - b.unixTimeMs);
      return {
        ...s,
        chartData: sorted.map((p) => [p.unixTimeMs, p.value]),
      } as const;
    });
  }, [series]);

  const allPoints = useMemo(
    () => prepared.flatMap((s) => s.chartData),
    [prepared],
  );

  const option = useMemo((): EChartsOption => {
    if (allPoints.length == 0) return {};

    const startTime = allPoints[0][0];
    const endTime = allPoints[allPoints.length - 1][0];
    const range = endTime - startTime;

    return {
      backgroundColor: "transparent",
      tooltip: {
        trigger: "axis",
        backgroundColor: tokens.bgInverse,
        borderColor: "transparent",
        borderRadius: 4,
        padding: 0,
        textStyle: { color: tokens.textInverse, fontSize: 12 },
        formatter: (params) => {
          if (!Array.isArray(params) || params.length == 0) return "";
          const ts = (params[0].data as [number, number])[0];
          const dateStr =
            range < 86_400_000 * 90
              ? fmt.datetime.datetime(ts)
              : fmt.datetime.date(ts);

          const rows = params
            .map((p) => {
              const name = p.seriesName;
              const val = (p.data as [number, number])[1];
              const color = p.color;
              const formatted = valueFormatter ? valueFormatter(val) : val;
              return (
                `<div style="display:flex;gap:8px;align-items:center;margin-bottom:6px">` +
                `<span style="width:10px;height:10px;border-radius:50%;background:${color};display:inline-block"></span>` +
                `<div style="color:${tokens.textInverse};font-size:13px"><strong style="display:inline-block;min-width:90px;color:${tokens.textInverse}">${name}</strong> ${formatted}</div>` +
                `</div>`
              );
            })
            .join("");

          return `
            <div style="padding:8px 12px; border-radius:4px; background:${tokens.bgInverse}">
              <div style="color:${tokens.textInverse}; opacity:0.7; margin-bottom:4px; font-size:11px">${dateStr}</div>
              <div style="font-size:13px; color:${tokens.textInverse}">${rows}</div>
            </div>`;
        },
      },
      legend: showLegend
        ? {
            show: true,
            data: prepared.map((s) => s.label ?? s.key),
            textStyle: { color: tokens.textPrimary },
            backgroundColor: tokens.layer,
            padding: 8,
          }
        : undefined,
      grid: { left: 10, right: 10, top: 20, bottom: 30, containLabel: true },
      xAxis: {
        type: "time",
        axisLine: { show: true },
        axisTick: { show: true },
        axisLabel: {
          color: tokens.textPrimary,
          formatter: (val) => {
            if (range > 86_400_000 * 30) return fmt.datetime.date(val);
            if (range < 86_400_000) return fmt.datetime.time(val);
            return fmt.datetime.date(val);
          },
          hideOverlap: true,
        },
        splitLine: {
          show: true,
          lineStyle: { color: tokens.borderSubtle, type: "dashed" },
        },
      },
      yAxis: {
        type: "value",
        position: "right",
        axisLabel: {
          color: tokens.textSecondary,
          formatter: valueFormatter,
        },
        splitLine: {
          lineStyle: { color: tokens.borderSubtle, type: "dashed" },
        },
        min: (v) => v.min - (v.max - v.min) * 0.15,
        max: (v) => v.max + (v.max - v.min) * 0.15,
      },
      series: prepared.map((s) => {
        const color = s.color ?? hashColor(s.key);

        return {
          name: s.label ?? s.key,
          type: "line",
          data: s.chartData,
          showSymbol: true,
          smooth: 0.1,
          lineStyle: { width: 2, color },
          areaStyle: {
            color: {
              type: "linear" as const,
              x: 0,
              y: 0,
              x2: 0,
              y2: 1,
              colorStops: [
                { offset: 0, color: `${color}4D` },
                { offset: 1, color: `${color}0D` },
              ],
            },
          },
          color,
          stack: stacked ? "total" : undefined, 
        } as const;
      }),
    };
  }, [prepared, allPoints, fmt, tokens, valueFormatter, showLegend]);

  const allTimestamps = useMemo(
    () =>
      series
        ? [...new Set(series.flatMap((s) => s.data.map((p) => p.unixTimeMs)))].sort(
            (a, b) => a - b,
          )
        : [],
    [series],
  );

  useEffect(() => {
    if (!onClickDay || !chartRef.current) return;
    if (allTimestamps.length === 0) return;

    const chartInstance = chartRef.current.getEchartsInstance();
    return attachChartDayClick(chartInstance, allTimestamps, onClickDay, "time");
  }, [onClickDay, allTimestamps]);

  if (loading)
    return (
      <Stack style={{ height, alignItems: "center", justifyContent: "center" }}>
        <InlineLoading description={tr("common.loading")} />
      </Stack>
    );

  if (allPoints.length == 0)
    return (
      <div
        style={{
          height,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          color: tokens.textHelper,
        }}
      >
        {tr("common.noData")}
      </div>
    );

  return (
    <div className={className}>
      <ReactECharts
        ref={chartRef}
        option={option}
        style={{ height }}
        notMerge
        opts={{ renderer: "canvas" }}
      />
    </div>
  );
}

import { useMemo, useState } from "react";
import type { EChartsOption } from "echarts";
import ReactECharts from "echarts-for-react";
import { BaseChart } from "@/components/charts/Base/BaseChart";
import { ChartContainer, ChartGridItem, ChartSection } from "@/components/charts/shared";
import { getThemedChartBaseOption, useChartTheme } from "@/hooks/useChartTheme";
import type { ActivityHeatmapCell } from "@/types/profile";
import sharedStyles from "@/components/charts/shared/ChartStyle.module.scss";

type HeatmapWindow = "3D" | "7D";

interface ProfileTradeFrequencyHeatmapProps {
    cells: ActivityHeatmapCell[];
    maxCount?: number;
    title?: string;
    minHeight?: number;
}

function formatDateInput(dateInput: Date): string {
    const year = dateInput.getUTCFullYear();
    const month = String(dateInput.getUTCMonth() + 1).padStart(2, "0");
    const day = String(dateInput.getUTCDate()).padStart(2, "0");
    return `${year}-${month}-${day}`;
}

function parseIsoDate(dateInput: string): Date | null {
    const parsed = new Date(`${dateInput}T00:00:00Z`);
    if (Number.isNaN(parsed.getTime())) {
        return null;
    }
    return parsed;
}

function getLatestDate(cells: ActivityHeatmapCell[]): Date | null {
    const parsed = cells
        .map((cell) => parseIsoDate(cell.date))
        .filter((value): value is Date => value !== null)
        .sort((a, b) => a.getTime() - b.getTime());

    if (parsed.length === 0) {
        return null;
    }

    return parsed[parsed.length - 1];
}

function getWindowDates(latestDate: Date, window: HeatmapWindow): string[] {
    const length = window === "3D" ? 3 : 7;
    const values: string[] = [];

    for (let offset = length - 1; offset >= 0; offset -= 1) {
        const next = new Date(latestDate);
        next.setUTCDate(next.getUTCDate() - offset);
        values.push(formatDateInput(next));
    }

    return values;
}

export function ProfileTradeFrequencyHeatmap({
    cells,
    maxCount,
    title = "Trade frequency heatmap",
    minHeight = 320,
}: ProfileTradeFrequencyHeatmapProps) {
    const chartTheme = useChartTheme();
    const [selectedWindow, setSelectedWindow] = useState<HeatmapWindow>("7D");

    const latestDate = useMemo(() => getLatestDate(cells), [cells]);

    const windowCells = useMemo(() => {
        if (!latestDate) {
            return [] as Array<{ date: string; count: number }>;
        }

        const dateList = getWindowDates(latestDate, selectedWindow);
        const countByDate = new Map<string, number>();

        cells.forEach((cell) => {
            if (!dateList.includes(cell.date)) {
                return;
            }

            const nextCount = Number.isFinite(cell.count) ? cell.count : 0;
            countByDate.set(cell.date, nextCount);
        });

        return dateList.map((date) => ({
            date,
            count: countByDate.get(date) ?? 0,
        }));
    }, [cells, latestDate, selectedWindow]);

    const chartMaxCount = useMemo(() => {
        if (typeof maxCount === "number" && Number.isFinite(maxCount) && maxCount > 0) {
            return maxCount;
        }

        const localMax = windowCells.reduce((largest, cell) => Math.max(largest, cell.count), 0);
        return localMax;
    }, [maxCount, windowCells]);

    const hasNonZeroData = windowCells.some((cell) => cell.count > 0);
    const isEmpty = windowCells.length === 0 || !hasNonZeroData;

    const chartOption = useMemo((): EChartsOption | null => {
        if (isEmpty) {
            return null;
        }

        const baseOption = getThemedChartBaseOption(chartTheme);
        const firstDate = windowCells[0]?.date;
        const lastDate = windowCells[windowCells.length - 1]?.date;

        if (!firstDate || !lastDate) {
            return null;
        }

        return {
            ...baseOption,
            tooltip: {
                ...baseOption.tooltip,
                trigger: "item",
                formatter: (params: any) => {
                    const pointDate = params?.data?.[0] ?? "-";
                    const tradeCount = params?.data?.[1] ?? 0;
                    return `${pointDate}<br/>Trades: ${tradeCount}`;
                },
            },
            visualMap: {
                min: 0,
                max: Math.max(1, chartMaxCount),
                calculable: true,
                orient: "horizontal",
                left: "center",
                bottom: 8,
                text: ["High", "Low"],
                inRange: {
                    color: ["#edf5ff", "#0f62fe"],
                },
                textStyle: {
                    color: chartTheme.textColorSecondary,
                },
            },
            calendar: {
                top: 56,
                left: 24,
                right: 24,
                range: [firstDate, lastDate],
                cellSize: ["auto", 32],
                splitLine: {
                    show: true,
                    lineStyle: {
                        color: chartTheme.borderColor,
                        width: 1,
                    },
                },
                dayLabel: {
                    firstDay: 1,
                    nameMap: ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"],
                    color: chartTheme.textColorSecondary,
                },
                monthLabel: {
                    show: false,
                },
                yearLabel: {
                    show: false,
                },
                itemStyle: {
                    color: chartTheme.backgroundColor,
                    borderColor: chartTheme.borderColor,
                    borderWidth: 1,
                },
            },
            series: [
                {
                    type: "heatmap",
                    coordinateSystem: "calendar",
                    data: windowCells.map((cell) => [cell.date, cell.count]),
                },
            ],
        };
    }, [chartMaxCount, chartTheme, isEmpty, windowCells]);

    const loadingState = {
        status: "success" as const,
        retryCount: 0,
    };

    const controls = (
        <div className={sharedStyles.filterSegmentedGroup}>
            <button
                type="button"
                className={`${sharedStyles.filterSegmentedButton} ${selectedWindow === "3D" ? sharedStyles.filterSegmentedButtonActive : ""}`}
                onClick={() => setSelectedWindow("3D")}
                aria-pressed={selectedWindow === "3D"}
            >
                3D
            </button>
            <button
                type="button"
                className={`${sharedStyles.filterSegmentedButton} ${selectedWindow === "7D" ? sharedStyles.filterSegmentedButtonActive : ""}`}
                onClick={() => setSelectedWindow("7D")}
                aria-pressed={selectedWindow === "7D"}
            >
                7D
            </button>
        </div>
    );

    return (
        <BaseChart
            title={title}
            loadingState={loadingState}
            isEmpty={isEmpty}
            onRetry={() => undefined}
            actions={controls}
        >
            <ChartContainer gap="0">
                <ChartSection minHeight={`${minHeight}px`}>
                    {chartOption && (
                        <ChartGridItem minHeight={minHeight}>
                            <ReactECharts
                                option={chartOption}
                                style={{
                                    height: "100%",
                                    width: "100%",
                                    minHeight: `${minHeight}px`,
                                }}
                                notMerge
                                lazyUpdate
                            />
                        </ChartGridItem>
                    )}
                </ChartSection>
            </ChartContainer>
        </BaseChart>
    );
}

export default ProfileTradeFrequencyHeatmap;

import { useLocalization } from "@/contexts/LocalizationContext";
import type { EChartsOption } from "echarts";
import ReactECharts from "echarts-for-react";
import React, { useEffect, useMemo, useState } from "react";

import { useChartContext } from "@/contexts/ChartContext";
import { useChartFiltersSync } from "@/hooks/useChartFiltersSync";
import {
  getChartGridConfig,
  getThemedChartBaseOption,
  useChartTheme,
} from "@/hooks/useChartTheme";
import {
  fetchRollingAnnualReturn,
  type InferFetcherData,
} from "@/services/chart/chartApi";
import type {
  RollingAnnualReturnRequestParams,
  RollingProfitAndLossResponse,
} from "@/types/chart-api.types";
import type { TimePeriod } from "@/types/chart-filters.types";

type ValueType = "total" | "realized" | "unrealized";

import { ChartGrid, ChartGridItem } from "@/components/charts/shared";
import { useStandardChartController } from "@/hooks/useChartController";
import { BaseChart } from "../Base/BaseChart";
import type { ChartProps } from "../shared/ChartProp";
import sharedStyles from "../shared/ChartStyle.module.scss";

type Data = InferFetcherData<typeof fetchRollingAnnualReturn>;

export const RollingProfitAndLoss: React.FC<ChartProps> = ({
  title,
  minHeight = 360,
  initialFilters = {
    timePeriod: "30D",
    wallets: [],
  },
  autoRefresh = false,
  refreshInterval = 30000,
  fetchEnabled = true,
  actions,
}) => {
  const { tr, fmt } = useLocalization();
  const chartTitle =
    title || tr("charts.rollingAnnualReturn.title") || "Rolling P&L";
  const TIME_PERIOD_LABELS = [
    tr("charts.last7Days"),
    tr("charts.last30Days"),
    tr("charts.last90Days"),
    tr("charts.allTime"),
  ];

  const chartTheme = useChartTheme();
  const { selectedTimezone: timezone } = useChartContext();

  const initialWallets = Array.isArray(initialFilters?.wallets)
    ? initialFilters.wallets
    : undefined;

  const { filters, walletsString, setTimePeriod } = useChartFiltersSync({
    initialFilters: {
      timePeriod: initialFilters?.timePeriod || "30D",
      wallets: initialWallets,
    },
    debounceDelay: 300,
  });

  const query = useMemo<RollingAnnualReturnRequestParams>(
    () => ({
      period: filters.timePeriod,
      wallets: walletsString,
      timezone,
    }),
    [filters.timePeriod, walletsString, timezone],
  );

  const { data, loadingState, refetch } = useStandardChartController<
    Data,
    RollingAnnualReturnRequestParams
  >({
    fetcher: fetchRollingAnnualReturn,
    query,
    autoRefresh,
    refreshInterval,
    enabled: fetchEnabled,
  });

  // Determine available value types from metadata
  const availableValueTypes: ValueType[] = ((data &&
    (data as RollingProfitAndLossResponse).metadata?.availableValueTypes) as
    | ValueType[]
    | undefined) || ["total", "realized", "unrealized"];
  const defaultValueType: ValueType = availableValueTypes.includes("total")
    ? "total"
    : (availableValueTypes[0] ?? "total");
  const [valueType, setValueType] = useState<ValueType>(defaultValueType);

  // Ensure local valueType remains valid when availableValueTypes changes
  useEffect(() => {
    const defaultVT: ValueType = availableValueTypes.includes("total")
      ? "total"
      : (availableValueTypes[0] ?? "total");
    setValueType((prev) =>
      availableValueTypes.includes(prev) ? prev : defaultVT,
    );
  }, [availableValueTypes]);

  const createPerWalletOption = (
    payload: RollingProfitAndLossResponse,
  ): EChartsOption => {
    const base = getThemedChartBaseOption(chartTheme);
    const wallets = payload.wallets ?? [];
    const labels = wallets.map(
      (w) =>
        w.walletName ??
        (w.walletAddress
          ? `${w.walletAddress.slice(0, 6)}...${w.walletAddress.slice(-4)}`
          : "Unknown"),
    );
    const values = wallets.map((w) => (w.metrics as any)[valueType] ?? 0);

    return {
      ...base,
      ...getChartGridConfig,
      xAxis: {
        ...base.xAxis,
        type: "category",
        data: labels,
        axisLabel: { rotate: 30 },
      },
      yAxis: {
        ...base.yAxis,
        type: "value",
        name: "USD",
        axisLabel: {
          ...(base.yAxis as any)?.axisLabel,
          formatter: (value: number) => fmt.num.compact.currency(value),
        },
      },
      tooltip: {
        ...base.tooltip,
        trigger: "axis",
        axisPointer: { type: "shadow" },
      },
      series: [
        {
          name: valueType,
          type: "bar",
          data: values,
          itemStyle: { color: chartTheme.colorPalette[0] },
        },
      ],
    };
  };

  const createAggregatedOption = (
    payload: RollingProfitAndLossResponse,
  ): EChartsOption => {
    const base = getThemedChartBaseOption(chartTheme);
    const m = payload.metrics ?? { total: 0, realized: 0, unrealized: 0 };
    const labels = ["Total", "Realized", "Unrealized"];
    const values = [m.total ?? 0, m.realized ?? 0, m.unrealized ?? 0];

    return {
      ...base,
      ...getChartGridConfig,
      xAxis: { ...base.xAxis, type: "category", data: labels },
      yAxis: {
        ...base.yAxis,
        type: "value",
        name: "USD",
        axisLabel: {
          ...(base.yAxis as any)?.axisLabel,
          formatter: (value: number) => fmt.num.compact.currency(value),
        },
      },
      tooltip: {
        ...base.tooltip,
        trigger: "axis",
        axisPointer: { type: "shadow" },
      },
      series: [
        {
          name: "Metric",
          type: "bar",
          data: values,
          itemStyle: { color: chartTheme.colorPalette[0] },
        },
      ],
    };
  };

  const chartRender = useMemo(() => {
    if (!data) return null;

    // If data is already timeseries (back-compat), don't try to render here
    if (!("wallets" in (data as any)) && !("metrics" in (data as any))) {
      return null; // upstream component should handle timeseries case
    }

    const payload = data as RollingProfitAndLossResponse;

    // Per-wallet view
    if (payload.wallets && payload.wallets.length > 0) {
      const option = createPerWalletOption(payload);
      return (
        <ChartGrid itemCount={1} multiItemColumns={1}>
          <ChartGridItem itemKey="pnl" minHeight={minHeight}>
            <ReactECharts
              option={option}
              style={{
                height: "100%",
                width: "100%",
                minHeight: `${minHeight}px`,
              }}
              notMerge
              lazyUpdate
            />
          </ChartGridItem>
        </ChartGrid>
      );
    }

    // Aggregated view
    if (payload.metrics) {
      const option = createAggregatedOption(payload);
      return (
        <ChartGrid itemCount={1} multiItemColumns={1}>
          <ChartGridItem itemKey="pnl-agg" minHeight={minHeight}>
            <ReactECharts
              option={option}
              style={{
                height: "100%",
                width: "100%",
                minHeight: `${minHeight}px`,
              }}
              notMerge
              lazyUpdate
            />
          </ChartGridItem>
        </ChartGrid>
      );
    }

    return null;
  }, [data, valueType, chartTheme, minHeight]);

  const isEmpty =
    !data ||
    (data && !("wallets" in (data as any)) && !("metrics" in (data as any)));

  return (
    <BaseChart
      title={chartTitle}
      loadingState={loadingState}
      isEmpty={isEmpty}
      onRetry={() => refetch(false)}
      actions={actions}
    >
      <div
        className={`${sharedStyles.chartControls} ${sharedStyles["chartControls--end"]} ${sharedStyles["chartControls--withBackground"]}`}
        data-html2canvas-ignore="true"
      >
        <select
          value={filters.timePeriod}
          onChange={(e) => setTimePeriod(e.target.value as TimePeriod)}
          className={sharedStyles.chartSelect}
          aria-label="Time period"
        >
          {(["7D", "30D", "90D", "All"] as TimePeriod[]).map((p, key) => (
            <option key={key} value={p}>
              {TIME_PERIOD_LABELS[key]}
            </option>
          ))}
        </select>

        <select
          value={valueType}
          onChange={(e) => setValueType(e.target.value as ValueType)}
          className={sharedStyles.chartSelect}
          aria-label="Value type"
        >
          {availableValueTypes.map((v) => (
            <option key={v} value={v}>
              {v.charAt(0).toUpperCase() + v.slice(1)}
            </option>
          ))}
        </select>
      </div>

      {chartRender}
    </BaseChart>
  );
};

export default RollingProfitAndLoss;

import { useChartContext } from "@/contexts/ChartContext";
import { useLocalization } from "@/contexts/LocalizationContext";
import { useStandardChartController } from "@/hooks/useChartController";
import { useChartFiltersSync } from "@/hooks/useChartFiltersSync";
import {
  CHART_COLOR_PALETTE,
  useCarbonChartBaseOption,
} from "@/util/carbon-chart-base";
import {
  fetchStablecoinRatio,
  type InferFetcherData,
} from "@/services/chart/chartApi";
import type { StablecoinRatioRequestParams } from "@/types/chart-api.types";
import {
  formatTimestampWithTimezone,
  isChartSuccess,
} from "@/util/chart-helpers";
import { formatAxisTooltip } from "@/util/tooltip-helpers";
import type { EChartsOption } from "echarts";
import ReactECharts from "echarts-for-react";
import { useMemo, useRef } from "react";
import { ChartWrapper, ChartContainer, ChartGridItem, ChartSection, ChartStatsHeader } from "../shared";
import type { ChartProps } from "../shared/ChartProp";
import type { StatCard } from "../shared/ChartStatsHeader";

type StablecoinRatioData = InferFetcherData<typeof fetchStablecoinRatio>;

export function StablecoinRatioChart({
  title,
  minHeight = 400,
  initialFilters = {
    timePeriod: "30D",
    wallets: [],
  },
  autoRefresh = true,
  refreshInterval = 30000,
  fetchEnabled = true,
  actions,
}: ChartProps) {
  const { tr } = useLocalization();
  const chartTitle = title || tr("charts.stablecoinRatioChart.title");

  const chartRef = useRef<ReactECharts>(null);
  const baseOption = useCarbonChartBaseOption();
  const { selectedTimezone: timezone } = useChartContext();

  const { filters, walletsString } = useChartFiltersSync({
    initialFilters,
    debounceDelay: 300,
  });

  const query = useMemo<StablecoinRatioRequestParams>(
    () => ({
      period: filters.timePeriod,
      wallets: walletsString,
    }),
    [filters.timePeriod, walletsString],
  );

  const { data, loadingState, refetch } = useStandardChartController<
    StablecoinRatioData,
    StablecoinRatioRequestParams
  >({
    fetcher: fetchStablecoinRatio,
    query,
    autoRefresh,
    refreshInterval,
    enabled: fetchEnabled,
  });

  const chartOption = useMemo((): EChartsOption | null => {
    const base = baseOption;

    if (!isChartSuccess(data, "wallets")) return null;

    const series = data.wallets.map((wallet, index) => {
      const color =
        CHART_COLOR_PALETTE[index % CHART_COLOR_PALETTE.length];

      return {
        name: wallet.walletName || wallet.walletAddress,
        type: "line" as const,
        data: wallet.data.map((d) => [d.timestamp, d.value]),
        smooth: true,
        lineStyle: {
          color: color,
          width: 2,
        },
        itemStyle: {
          color: color,
        },
        symbol: "circle" as const,
        symbolSize: 6,
        showSymbol: false,
        emphasis: {
          focus: "series" as const,
          showSymbol: true,
        },
      };
    });

    return {
      ...base,
      xAxis: {
        ...base.xAxis,
        type: "time",
        axisLabel: {
          ...base.xAxis.axisLabel,
          formatter: (value: number) =>
            formatTimestampWithTimezone(value, timezone, "MM/dd"),
        },
      },
      yAxis: {
        ...base.yAxis,
        type: "value",
        name: "Stablecoin Ratio (%)",
        min: 0,
        max: 100,
        axisLabel: {
          ...base.yAxis.axisLabel,
          formatter: "{value}%",
        },
      },
      series: series,
      legend: {
        show: true,
        data: data.wallets.map((w) => w.walletAddress),
        textStyle: { color: base.textStyle.color },
      },
      tooltip: {
        ...base.tooltip,
        trigger: "axis",
        axisPointer: {
          type: "cross",
        },
        formatter: (params: any) =>
          formatAxisTooltip(
            params,
            (p) =>
              formatTimestampWithTimezone(
                p.value[0],
                timezone,
                "yyyy-MM-dd HH:mm",
              ),
            (p) => `${p.value[1].toFixed(2)}%`,
          ),
      },
    };
  }, [data, baseOption, timezone]);

  const statsCards = useMemo<StatCard[]>(() => {
    if (!isChartSuccess(data, "wallets") || data.wallets.length === 0)
      return [];

    return data.wallets.map((wallet) => ({
      title: wallet.walletName || wallet.walletAddress,
      stats: [
        {
          label: "Current Ratio",
          value: wallet.currentRatio?.toFixed(2) || "-",
          suffix: "%",
        },
        {
          label: "Average Ratio",
          value: wallet.averageRatio?.toFixed(2) || "-",
          suffix: "%",
        },
      ],
    }));
  }, [data]);

  return (
    <ChartWrapper
      title={chartTitle}
      loadingState={loadingState}
      isEmpty={!isChartSuccess(data, "wallets") || data.wallets.length === 0}
      onRetry={() => refetch(false)}
      actions={actions}
    >
      <ChartContainer>
        <ChartStatsHeader cards={statsCards} minColumnWidth="200px" />
        <ChartSection minHeight={`${minHeight}px`}>
          {chartOption && (
            <ChartGridItem minHeight={minHeight}>
              <ReactECharts
                ref={chartRef}
                option={chartOption}
                style={{
                  height: "100%",
                  width: "100%",
                  minHeight: `${minHeight}px`,
                }}
                notMerge
                lazyUpdate
              />
            </ChartGridItem>
          )}
        </ChartSection>
      </ChartContainer>
    </ChartWrapper>
  );
}

import { useLocalization } from "@/contexts/LocalizationContext";
import { useCarbonTokens } from "@/hooks/useCarbonToken";
import { cds } from "@/util/carbon-theme";
import { InlineLoading, Stack } from "@carbon/react";
import type { EChartsOption } from "echarts";
import ReactECharts from "echarts-for-react";
import { useMemo } from "react";

// Add your specific usecase here and help yourself
export type TimeSeriesChartHelper = "average-buy-sell";

export interface TimeSeriesDataPoint {
  unixTimeMs: number;
  value: number;
}

export interface MarkLineConfig {
  value: number;
  label: string;
  color?: string;
}

export interface TimeSeriesChartProps {
  data: TimeSeriesDataPoint[] | undefined;
  markLines?: MarkLineConfig[];
  loading?: boolean;
  isDataSorted?: boolean;
  title?: string;
  height?: number | string;
  className?: string;
  helper?: TimeSeriesChartHelper;
  valueFormatter?: (val: number | null) => string;
}

export function TimeSeriesLineChart({
  data,
  markLines = [],
  loading = false,
  isDataSorted = false,
  title,
  helper,
  height = 300,
  className,
  valueFormatter,
}: TimeSeriesChartProps) {
  const { fmt, tr } = useLocalization();

  const tokens = useCarbonTokens({
    textPrimary: cds.textPrimary,
    textSecondary: cds.textSecondary,
    textHelper: cds.textHelper,
    bgInverse: cds.backgroundInverse,
    textInverse: cds.textInverse,
    success: cds.supportSuccess,
    error: cds.supportError,
    borderSubtle: cds.borderSubtle00,
    // Default color for markLines
    interactive: cds.interactive,
  });

  const chartData = useMemo(() => {
    if (!data || data.length == 0) return [];
    const sorted = isDataSorted
      ? data
      : [...data].sort((a, b) => a.unixTimeMs - b.unixTimeMs);
    return sorted.map((p) => [p.unixTimeMs, p.value]);
  }, [data, isDataSorted]);

  const isPositive = useMemo(() => {
    if (chartData.length < 2) return true;
    return chartData[chartData.length - 1][1] >= chartData[0][1];
  }, [chartData]);

  const option = useMemo((): EChartsOption => {
    if (chartData.length == 0) return {};

    const trendColor = isPositive ? tokens.success : tokens.error;
    const startTime = chartData[0][0];
    const endTime = chartData[chartData.length - 1][0];
    const range = endTime - startTime;

    return {
      backgroundColor: "transparent",
      title: {
        text: title,
        left: "center",
        textStyle: { fontSize: 14, fontWeight: 600, color: tokens.textPrimary },
      },
      grid: { left: 10, right: 10, top: 40, bottom: 30, containLabel: true },
      tooltip: {
        trigger: "axis",
        backgroundColor: tokens.bgInverse,
        borderColor: "transparent",
        borderRadius: 4,
        padding: 0,
        textStyle: { color: tokens.textInverse, fontSize: 12 },
        formatter: (params) => {
          if (!Array.isArray(params) || !params[0]) return "";
          // only casting we need
          const [ts, val] = params[0].data as [number, number];
          const dateStr =
            range < 86_400_000 * 2
              ? fmt.datetime.datetime(ts)
              : fmt.datetime.date(ts);
          const valStr = valueFormatter ? valueFormatter(val) : val;

          return `
            <div style="padding:8px 12px; border-radius:4px; background:${tokens.bgInverse}">
              <div style="color:${tokens.textInverse}; opacity:0.7; margin-bottom:4px; font-size:11px">${dateStr}</div>
              <div style="font-size:14px; font-weight:700; color:${tokens.textInverse}">${valStr}</div>
            </div>`;
        },
      },
      xAxis: {
        type: "time",
        axisLine: { show: true },
        axisTick: { show: true },
        // Suggest a reasonable number of splits for a 300px-ish height chart
        // splitNumber: 8,
        // Prevent ticks from being too close together
        // minInterval: 3600 * 1000 * 24, // 1 day ms
        axisLabel: {
          color: tokens.textSecondary,
          fontSize: 11,
          // Use hideOverlap to automatically remove clashing labels
          hideOverlap: true,
          formatter: (val) => {
            // If the total range is > 30 days, just show Month/Day
            if (range > 86_400_000 * 30) {
              return fmt.datetime.date(val);
            }
            // If < 24h, show Time
            if (range < 86_400_000) {
              return fmt.datetime.time(val);
            }
            // Default fallback
            return fmt.datetime.date(val);
          },
        },
        splitLine: {
          show: true,
          lineStyle: {
            color: tokens.borderSubtle,
            type: "dashed",
            width: 1,
          },
        },
      },
      yAxis: {
        type: "value",
        scale: true,
        position: "right",
        axisLine: { show: false },
        axisTick: { show: false },
        axisLabel: {
          color: tokens.textSecondary,
          fontSize: 11,
          formatter: (val) => fmt.num.compact.currency(val),
        },
        splitLine: {
          lineStyle: { color: tokens.borderSubtle, type: "dashed" },
        },
        min: (value) => {
          let min = value.min;
          markLines.forEach((ml) => {
            if (ml.value < min) min = ml.value;
          });
          const spread = value.max - value.min || min * 0.1;
          return min - spread * 0.15; // 15% buffer based on spread
        },
        max: (value) => {
          let max = value.max;
          markLines.forEach((ml) => {
            if (ml.value > max) max = ml.value;
          });
          const spread = value.max - value.min || max * 0.1;
          return max + spread * 0.15;
        },
      },
      series: [
        {
          type: "line",
          data: chartData,
          showSymbol: false,
          smooth: 0.1,
          lineStyle: { width: 2, color: trendColor },
          areaStyle: {
            color: {
              type: "linear",
              x: 0,
              y: 0,
              x2: 0,
              y2: 1,
              colorStops: [
                { offset: 0, color: trendColor },
                { offset: 1, color: "transparent" },
              ],
            },
            opacity: 0.15,
          },
          markLine: {
            // Important: Default is 2. For tokens, we need high precision.
            precision: 8,
            lineStyle: {
              width: 1,
              opacity: 0.8,
            },
            data: markLines.map((ml, index) => ({
              name: ml.label,
              yAxis: ml.value,
              lineStyle: { color: ml.color || tokens.interactive },
              label: {
                formatter: () =>
                  `${ml.label}: ${valueFormatter ? valueFormatter(ml.value) : ml.value}`,
                position:
                  helper == "average-buy-sell" && markLines.length == 2
                    ? ml.value > markLines.at(index - 1)!.value
                      ? "insideEndTop"
                      : "insideEndBottom"
                    : "insideEndBottom",
                backgroundColor: ml.color,
                padding: [4, 4],
              },
            })),
          },
        },
      ],
    };
  }, [chartData, isPositive, title, fmt, valueFormatter, tokens, markLines]);

  if (loading)
    return (
      <Stack style={{ height, alignItems: "center", justifyContent: "center" }}>
        <InlineLoading description={tr("common.loading")} />
      </Stack>
    );

  if (chartData.length == 0)
    return (
      <div
        style={{
          height,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          color: tokens.textHelper,
        }}
      >
        {tr("common.noData")}
      </div>
    );

  return (
    <div className={className}>
      <ReactECharts
        option={option}
        style={{ height }}
        notMerge
        opts={{ renderer: "canvas" }}
      />
    </div>
  );
}

import { useLocalization } from "@/contexts/LocalizationContext";
import { useCarbonTokens } from "@/hooks/useCarbonToken";
import { cds } from "@/util/carbon-theme";
import { InlineLoading, Stack } from "@carbon/react";
import type { EChartsOption } from "echarts";
import ReactECharts from "echarts-for-react";
import { useMemo } from "react";

export interface TimeSeriesDataPoint {
  unixTimeMs: number;
  value: number;
}

export interface MarkLineConfig {
  value: number;
  label: string;
  color?: string;
}

export interface TradePoint {
  unixTimeMs: number;
  side: "buy" | "sell";
  volumeUsd: number;
  price: number | null;
  priceSource: "trade" | "mapped" | "missing";
  transactionHash?: string;
}

export interface TradeAggregationConfig {
  timeBucketMs: number;
}

export interface TimeSeriesTradesScatterChartProps {
  data: TimeSeriesDataPoint[] | undefined;
  trades: TradePoint[];
  markLines?: MarkLineConfig[];
  loading?: boolean;
  isDataSorted?: boolean;
  title?: string;
  height?: number | string;
  className?: string;
  valueFormatter?: (val: number | null) => string;
  aggregation?: TradeAggregationConfig;
}

interface TradeBucket {
  buyCount: number;
  sellCount: number;
  buyVolumeUsd: number;
  sellVolumeUsd: number;
  midpointMs: number;
  matchedPrice: number;
}

interface MarkPointDataItem {
  name: string;
  coord: [number, number];
  value: string;
  itemStyle: { color: string };
  symbol: string;
  symbolSize: number;
  label: { show: false } | {
    show: true;
    formatter: string;
    position: "inside";
    fontSize: number;
    fontWeight: "bold";
    color: string;
  };
}

const DEFAULT_AGGREGATION: TradeAggregationConfig = {
  timeBucketMs: 60 * 60 * 1000,
};

function toFiniteNumber(value: unknown): number | null {
  if (typeof value !== "number") {
    return null;
  }
  if (!Number.isFinite(value)) {
    return null;
  }
  return value;
}

function normalizeMarketData(
  marketData: TimeSeriesDataPoint[] | undefined,
  isDataSorted: boolean,
): TimeSeriesDataPoint[] {
  if (!marketData || marketData.length === 0) {
    return [];
  }

  if (isDataSorted) {
    return marketData;
  }

  return [...marketData].sort((a, b) => a.unixTimeMs - b.unixTimeMs);
}

export function findNearestMarketPrice(
  marketData: TimeSeriesDataPoint[],
  targetUnixTimeMs: number,
): number | null {
  if (!marketData.length) {
    return null;
  }

  if (targetUnixTimeMs <= marketData[0].unixTimeMs) {
    return marketData[0].value;
  }

  const last = marketData[marketData.length - 1];
  if (targetUnixTimeMs >= last.unixTimeMs) {
    return last.value;
  }

  let left = 0;
  let right = marketData.length - 1;

  while (left <= right) {
    const mid = Math.floor((left + right) / 2);
    const midTs = marketData[mid].unixTimeMs;

    if (midTs === targetUnixTimeMs) {
      return marketData[mid].value;
    }

    if (midTs < targetUnixTimeMs) {
      left = mid + 1;
    } else {
      right = mid - 1;
    }
  }

  const leftPoint = marketData[left];
  const rightPoint = marketData[right];

  if (!leftPoint) {
    return rightPoint?.value ?? null;
  }

  if (!rightPoint) {
    return leftPoint.value;
  }

  const leftDistance = Math.abs(leftPoint.unixTimeMs - targetUnixTimeMs);
  const rightDistance = Math.abs(rightPoint.unixTimeMs - targetUnixTimeMs);

  return leftDistance < rightDistance ? leftPoint.value : rightPoint.value;
}

export function mapTradesWithFallbackPrice(
  trades: TradePoint[],
  marketData: TimeSeriesDataPoint[] | undefined,
  isMarketDataSorted = false,
): TradePoint[] {
  const sortedMarketData = normalizeMarketData(marketData, isMarketDataSorted);

  return trades.map((trade) => {
    const directPrice = toFiniteNumber(trade.price);
    if (directPrice !== null) {
      return {
        ...trade,
        price: directPrice,
        priceSource: "trade",
      };
    }

    const mappedPrice = findNearestMarketPrice(
      sortedMarketData,
      trade.unixTimeMs,
    );

    if (mappedPrice === null) {
      return {
        ...trade,
        price: null,
        priceSource: "missing",
      };
    }

    return {
      ...trade,
      price: mappedPrice,
      priceSource: "mapped",
    };
  });
}

export function buildTradeBuckets(
  trades: TradePoint[],
  marketData: TimeSeriesDataPoint[],
  startTime: number,
  endTime: number,
  bucketSizeMs: number,
): Map<number, TradeBucket> {
  const bucketMap = new Map<number, TradeBucket>();

  for (const t of trades) {
    if (t.unixTimeMs < startTime || t.unixTimeMs > endTime) {
      continue;
    }

    const volumeUsd = toFiniteNumber(t.volumeUsd);
    if (volumeUsd === null || volumeUsd <= 0) {
      continue;
    }

    const bucketIdx = Math.floor((t.unixTimeMs - startTime) / bucketSizeMs);
    const existing = bucketMap.get(bucketIdx);

    if (existing) {
      if (t.side === "buy") {
        existing.buyCount += 1;
        existing.buyVolumeUsd += volumeUsd;
      } else {
        existing.sellCount += 1;
        existing.sellVolumeUsd += volumeUsd;
      }
    } else {
      const bucketStart = startTime + bucketIdx * bucketSizeMs;
      bucketMap.set(bucketIdx, {
        buyCount: t.side === "buy" ? 1 : 0,
        sellCount: t.side === "sell" ? 1 : 0,
        buyVolumeUsd: t.side === "buy" ? volumeUsd : 0,
        sellVolumeUsd: t.side === "sell" ? volumeUsd : 0,
        midpointMs: bucketStart + bucketSizeMs / 2,
        matchedPrice:
          findNearestMarketPrice(marketData, t.unixTimeMs) ?? t.price ?? 0,
      });
    }
  }

  return bucketMap;
}

function buildMarkPointData(
  bucketMap: Map<number, TradeBucket>,
  minPrice: number,
  maxPrice: number,
  buyLabel: string,
  sellLabel: string,
): MarkPointDataItem[] {
  const priceRange = maxPrice - minPrice || 1;
  const offset = priceRange * 0.12;
  const highThreshold = maxPrice - priceRange * 0.2;
  const result: MarkPointDataItem[] = [];

  for (const bucket of bucketMap.values()) {
    const { buyCount, sellCount, midpointMs, matchedPrice } = bucket;
    const isTooHigh = matchedPrice > highThreshold;

    if (buyCount > 0 && sellCount === 0) {
      const y = isTooHigh
        ? matchedPrice - offset * 1.5
        : matchedPrice + offset * 1.5;
      result.push({
        name: buyLabel,
        coord: [midpointMs, y],
        value: String(buyCount),
        itemStyle: { color: "#24a148" },
        symbol: "circle",
        symbolSize: 10,
        label: { show: false },
      });
    } else if (sellCount > 0 && buyCount === 0) {
      const y = isTooHigh
        ? matchedPrice - offset * 1.5
        : matchedPrice + offset * 1.5;
      result.push({
        name: sellLabel,
        coord: [midpointMs, y],
        value: String(sellCount),
        itemStyle: { color: "#da1e28" },
        symbol: "circle",
        symbolSize: 10,
        label: { show: false },
      });
    } else if (buyCount > 0 && sellCount > 0) {
      const buyY = isTooHigh
        ? matchedPrice - offset
        : matchedPrice + offset * 2;
      const sellY = isTooHigh
        ? matchedPrice - offset * 2
        : matchedPrice + offset;
      result.push({
        name: buyLabel,
        coord: [midpointMs, buyY],
        value: String(buyCount),
        itemStyle: { color: "#24a148" },
        symbol: "circle",
        symbolSize: 10,
        label: { show: false },
      });
      result.push({
        name: sellLabel,
        coord: [midpointMs, sellY],
        value: String(sellCount),
        itemStyle: { color: "#da1e28" },
        symbol: "circle",
        symbolSize: 10,
        label: { show: false },
      });
    }
  }

  return result;
}

export function getDefaultAggregationForDayRange(
  days: "7" | "30" | "90",
): TradeAggregationConfig {
  if (days === "7") {
    return { timeBucketMs: 60 * 60 * 1000 };
  }

  if (days === "30") {
    return { timeBucketMs: 4 * 60 * 60 * 1000 };
  }

  return { timeBucketMs: 12 * 60 * 60 * 1000 };
}

export function TimeSeriesTradesScatterChart({
  data,
  trades,
  markLines = [],
  loading = false,
  isDataSorted = false,
  title,
  height = 300,
  className,
  valueFormatter,
  aggregation = DEFAULT_AGGREGATION,
}: TimeSeriesTradesScatterChartProps) {
  const { fmt, tr } = useLocalization();

  const tokens = useCarbonTokens({
    textPrimary: cds.textPrimary,
    textSecondary: cds.textSecondary,
    textHelper: cds.textHelper,
    bgInverse: cds.backgroundInverse,
    textInverse: cds.textInverse,
    success: cds.supportSuccess,
    error: cds.supportError,
    borderSubtle: cds.borderSubtle00,
    interactive: cds.interactive,
    warning: cds.supportWarning,
  });

  const chartData = useMemo(() => {
    if (!data || data.length === 0) {
      return [] as [number, number][];
    }

    const sorted = isDataSorted
      ? data
      : [...data].sort((a, b) => a.unixTimeMs - b.unixTimeMs);

    return sorted.map(
      (point) => [point.unixTimeMs, point.value] as [number, number],
    );
  }, [data, isDataSorted]);

  const normalizedMarketData = useMemo(
    () => normalizeMarketData(data, isDataSorted),
    [data, isDataSorted],
  );

  const hasChartContent = chartData.length > 0;

  const option = useMemo((): EChartsOption => {
    if (!hasChartContent) {
      return {};
    }

    const startTime = chartData[0][0];
    const endTime = chartData[chartData.length - 1][0];
    const range = Math.max(1, endTime - startTime);

    const trendColor =
      chartData.length >= 2 &&
      chartData[chartData.length - 1][1] >= chartData[0][1]
        ? tokens.success
        : tokens.error;

    const bucketSizeMs = 24 * 60 * 60 * 1000;
    const bucketMap = buildTradeBuckets(
      trades,
      normalizedMarketData,
      startTime,
      endTime,
      bucketSizeMs,
    );

    const allPrices = chartData.map((d) => d[1]);
    const minPrice = Math.min(...allPrices);
    const maxPrice = Math.max(...allPrices);

    const markPointData = buildMarkPointData(
      bucketMap,
      minPrice,
      maxPrice,
      tr("walletPage.buy"),
      tr("walletPage.sell"),
    );

    return {
      backgroundColor: "transparent",
      title: {
        text: title,
        left: "center",
        textStyle: {
          fontSize: 14,
          fontWeight: 600,
          color: tokens.textPrimary,
        },
      },
      grid: { left: 10, right: 10, top: 40, bottom: 30, containLabel: true },
      tooltip: {
        trigger: "item",
        backgroundColor: tokens.bgInverse,
        borderColor: "transparent",
        borderRadius: 4,
        padding: 0,
        textStyle: { color: tokens.textInverse, fontSize: 12 },
        formatter: (params) => {
          if (!params) {
            return "";
          }

          const singleParams = Array.isArray(params) ? params[0] : params;
          const raw = singleParams as unknown as Record<string, unknown>;
          const componentType = raw.componentType as string | undefined;

          if (componentType === "markPoint") {
            const data = raw.data as {
              coord?: [number, number];
              name?: string;
            } | undefined;
            if (!data?.coord) {
              return "";
            }

            const ts = data.coord[0];
            const dateStr =
              range < 86_400_000 * 2
                ? fmt.datetime.datetime(ts)
                : fmt.datetime.date(ts);

            const bucketIdx = Math.floor((ts - startTime) / bucketSizeMs);
            const bucket = bucketMap.get(bucketIdx);

            const isSell = data.name === tr("walletPage.sell");
            const sideLabel = isSell ? tr("walletPage.sell") : tr("walletPage.buy");
            const sideLabelLower = sideLabel.toLowerCase();
            const count = isSell ? bucket?.sellCount : bucket?.buyCount;
            const volume = isSell ? bucket?.sellVolumeUsd : bucket?.buyVolumeUsd;

            let tradeInfo = "";
            if (count && count > 0) {
              tradeInfo = `<div style="font-size:12px;margin-top:4px">${count} ${sideLabelLower}${count > 1 ? "s" : ""}</div><div style="font-size:11px;opacity:0.8;margin-top:2px">${fmt.num.compact.currency(volume ?? 0)}</div>`;
            }

            return `
              <div style="padding:8px 12px">
                <div style="opacity:0.7;font-size:11px;margin-bottom:4px">${dateStr}</div>
                <div style="display:flex;align-items:center;gap:6px;font-size:13px;font-weight:600;text-transform:uppercase;margin-bottom:4px">
                  ${raw.marker as string ?? ""}${sideLabel}
                </div>
                ${tradeInfo}
              </div>`;
          }

          const data = raw.data as [number, number] | undefined;
          if (!data) {
            return "";
          }

          const ts = data[0];
          const price = data[1];
          const dateStr =
            range < 86_400_000 * 2
              ? fmt.datetime.datetime(ts)
              : fmt.datetime.date(ts);
          const valStr = valueFormatter
            ? valueFormatter(price)
            : fmt.num.compact.currency(price);

          const bucketIdx = Math.floor((ts - startTime) / bucketSizeMs);
          const bucket = bucketMap.get(bucketIdx);

          let tradeInfo = "";
          if (bucket && (bucket.buyCount > 0 || bucket.sellCount > 0)) {
            const parts: string[] = [];
            if (bucket.buyCount > 0) {
              const label = tr("walletPage.buy").toLowerCase();
              parts.push(
                `${bucket.buyCount} ${label}${bucket.buyCount > 1 ? "s" : ""}`,
              );
            }
            if (bucket.sellCount > 0) {
              const label = tr("walletPage.sell").toLowerCase();
              parts.push(
                `${bucket.sellCount} ${label}${bucket.sellCount > 1 ? "s" : ""}`,
              );
            }
            const totalVolume = bucket.buyVolumeUsd + bucket.sellVolumeUsd;
            tradeInfo = `<div style="font-size:11px;margin-top:4px;opacity:0.8">${parts.join(", ")} · ${fmt.num.compact.currency(totalVolume)}</div>`;
          }

          return `
            <div style="padding:8px 12px">
              <div style="opacity:0.7;font-size:11px;margin-bottom:2px">${dateStr}</div>
              <div style="font-size:14px;font-weight:700">${valStr}</div>
              ${tradeInfo}
            </div>`;
        },
      },
      xAxis: {
        type: "time",
        axisLine: { show: false },
        axisTick: { show: false },
        axisLabel: {
          color: tokens.textSecondary,
          fontSize: 11,
          hideOverlap: true,
          formatter: (val: number) => {
            if (range > 86_400_000 * 30) {
              return fmt.datetime.date(val);
            }
            if (range < 86_400_000) {
              return fmt.datetime.time(val);
            }
            return fmt.datetime.date(val);
          },
        },
        splitLine: { show: false },
      },
      yAxis: {
        type: "value",
        scale: true,
        position: "right",
        axisLine: { show: false },
        axisTick: { show: false },
        axisLabel: {
          color: tokens.textSecondary,
          fontSize: 11,
          formatter: (val: number) => fmt.num.compact.currency(val),
        },
        splitLine: {
          lineStyle: { color: tokens.borderSubtle, type: "dashed" },
        },
        min: (value) => {
          let min = value.min;
          markLines.forEach((markLine) => {
            if (markLine.value < min) {
              min = markLine.value;
            }
          });
          const spread =
            value.max - value.min || Math.max(Math.abs(min) * 0.1, 1);
          return min - spread * 0.15;
        },
        max: (value) => {
          let max = value.max;
          markLines.forEach((markLine) => {
            if (markLine.value > max) {
              max = markLine.value;
            }
          });
          const spread =
            value.max - value.min || Math.max(Math.abs(max) * 0.1, 1);
          return max + spread * 0.15;
        },
      },
      series: [
        {
          type: "line",
          data: chartData,
          showSymbol: false,
          smooth: 0.1,
          lineStyle: { width: 2, color: trendColor },
          areaStyle: {
            color: {
              type: "linear",
              x: 0,
              y: 0,
              x2: 0,
              y2: 1,
              colorStops: [
                { offset: 0, color: trendColor },
                { offset: 1, color: "transparent" },
              ],
            },
            opacity: 0.12,
          },
          markPoint: {
            data: markPointData,
            symbolOffset: [0, 0],
            label: { show: true },
          },
          markLine: {
            precision: 8,
            lineStyle: {
              width: 1,
              opacity: 0.8,
            },
            data: markLines.map((markLine) => ({
              name: markLine.label,
              yAxis: markLine.value,
              lineStyle: { color: markLine.color || tokens.interactive },
              label: {
                formatter: () =>
                  `${markLine.label}: ${valueFormatter ? valueFormatter(markLine.value) : markLine.value}`,
                position:
                  markLines.length === 2
                    ? markLine.value >
                      (markLines[0] === markLine
                        ? markLines[1].value
                        : markLines[0].value)
                      ? "insideEndTop"
                      : "insideEndBottom"
                    : "insideEndBottom",
                backgroundColor: markLine.color,
                padding: [4, 4],
              },
            })),
          },
          z: 1,
        },
      ],
    };
  }, [
    chartData,
    trades,
    normalizedMarketData,
    aggregation,
    tokens,
    fmt,
    tr,
    valueFormatter,
    title,
    markLines,
    hasChartContent,
  ]);

  if (loading) {
    return (
      <Stack style={{ height, alignItems: "center", justifyContent: "center" }}>
        <InlineLoading description={tr("common.loading")} />
      </Stack>
    );
  }

  if (!hasChartContent) {
    return (
      <div
        style={{
          height,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          color: tokens.textHelper,
        }}
      >
        {tr("common.noData")}
      </div>
    );
  }

  return (
    <div className={className}>
      <ReactECharts
        option={option}
        style={{ height }}
        notMerge
        opts={{ renderer: "canvas" }}
      />
    </div>
  );
}

import { useLocalization } from "@/contexts/LocalizationContext";
import { fetchTokenPriceChartForDay, type TokenPriceChartPoint } from "@/services/wallet/walletApi";
import { useCarbonChartBaseOption, CHART_COLOR_PALETTE } from "@/util/carbon-chart-base";
import { Close } from "@carbon/icons-react";
import type { EChartsOption } from "echarts";
import ReactECharts from "echarts-for-react";
import { useEffect, useMemo, useState } from "react";
import styles from "./TokenPriceChart.module.scss";
import { Flex } from "@/components/Flex";
import { Txt } from "@/components/Txt";

export interface TradeIndicator {
  timestampMs: number;
  type: "buy" | "sell";
  price: number;
  amount: number;
  symbol: string;
}

interface AggregatedTradeBucket {
  buyCount: number;
  sellCount: number;
  buyTotalAmount: number;
  sellTotalAmount: number;
  midpointMs: number;
  matchedPrice: number;
}

interface TokenPriceChartProps {
  tokenAddress: string;
  tokenSymbol: string;
  tokenLogoUri: string | null;
  dayMs: number;
  trades: TradeIndicator[];
  onRemove: () => void;
  priceHistory?: TokenPriceChartPoint[];
}

function formatUtcTime(val: number): string {
  const d = new Date(val);
  const h = String(d.getUTCHours()).padStart(2, "0");
  const m = String(d.getUTCMinutes()).padStart(2, "0");
  return `${h}:${m}`;
}

export function TokenPriceChart({
  tokenAddress,
  tokenSymbol,
  tokenLogoUri,
  dayMs,
  trades,
  onRemove,
  priceHistory: priceHistoryProp,
}: TokenPriceChartProps) {
  const { fmt, tr } = useLocalization();
  const baseOption = useCarbonChartBaseOption();

  const [priceData, setPriceData] = useState<TokenPriceChartPoint[]>(priceHistoryProp ?? []);
  const [loading, setLoading] = useState(!priceHistoryProp);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (priceHistoryProp) {
      setPriceData(priceHistoryProp);
      setLoading(false);
      return;
    }

    let cancelled = false;
    setLoading(true);
    setError(null);

    fetchTokenPriceChartForDay(tokenAddress, dayMs)
      .then((res) => {
        if (!cancelled) {
          setPriceData(res.items);
          setLoading(false);
        }
      })
      .catch((err) => {
        if (!cancelled) {
          setError(err instanceof Error ? err.message : "Failed to load price data");
          setLoading(false);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [tokenAddress, dayMs, priceHistoryProp]);

  const chartOption = useMemo((): EChartsOption => {
    if (priceData.length === 0) return {};

    const sorted = [...priceData].sort((a, b) => a.timestampMs - b.timestampMs);
    const chartData = sorted.map((p) => [p.timestampMs, p.price]);


    const startTime = dayMs;

    const allPrices = chartData.map((d) => d[1] as number);
    const minPrice = Math.min(...allPrices);
    const maxPrice = Math.max(...allPrices);
    const priceRange = maxPrice - minPrice || 1;

    const color = CHART_COLOR_PALETTE[0];

    function findClosestPrice(timestampMs: number): number {
      let closest = sorted[0];
      let minDiff = Math.abs(sorted[0].timestampMs - timestampMs);
      for (let i = 1; i < sorted.length; i++) {
        const diff = Math.abs(sorted[i].timestampMs - timestampMs);
        if (diff < minDiff) {
          minDiff = diff;
          closest = sorted[i];
        }
      }
      return closest.price;
    }

    const bucketSizeMs = 15 * 60 * 1000;
    const bucketMap = new Map<number, AggregatedTradeBucket>();

    for (const t of trades) {
      const bucketIdx = Math.floor((t.timestampMs - startTime) / bucketSizeMs);
      const existing = bucketMap.get(bucketIdx);
      if (existing) {
        if (t.type === "buy") {
          existing.buyCount += 1;
          existing.buyTotalAmount += t.amount;
        } else {
          existing.sellCount += 1;
          existing.sellTotalAmount += t.amount;
        }
      } else {
        const bucketStart = startTime + bucketIdx * bucketSizeMs;
        bucketMap.set(bucketIdx, {
          buyCount: t.type === "buy" ? 1 : 0,
          sellCount: t.type === "sell" ? 1 : 0,
          buyTotalAmount: t.type === "buy" ? t.amount : 0,
          sellTotalAmount: t.type === "sell" ? t.amount : 0,
          midpointMs: bucketStart + bucketSizeMs / 2,
          matchedPrice: findClosestPrice(t.timestampMs),
        });
      }
    }

    const offset = priceRange * 0.06;
    const highThreshold = maxPrice - priceRange * 0.2;

    const markPointData: Array<{
      name: string;
      coord: [number, number];
      value: string;
      itemStyle: { color: string };
      symbol: string;
      symbolSize: number;
      label: { show: boolean; formatter: string; position: "inside"; fontSize: number; fontWeight: "bold"; color: string };
    }> = [];

    for (const bucket of bucketMap.values()) {
      const { buyCount, sellCount, midpointMs, matchedPrice } = bucket;
      const isTooHigh = matchedPrice > highThreshold;

      if (buyCount > 0 && sellCount === 0) {
        const y = isTooHigh ? matchedPrice - offset * 1.5 : matchedPrice + offset * 1.5;
        markPointData.push({
          name: tr("walletPage.buy"),
          coord: [midpointMs, y],
          value: "",
          itemStyle: { color: "#24a148" },
          symbol: "circle",
          symbolSize: 10,
          label: { show: true, formatter: "{c}", position: "inside", fontSize: 9, fontWeight: "bold", color: "#fff" },
        });
      } else if (sellCount > 0 && buyCount === 0) {
        const y = isTooHigh ? matchedPrice - offset * 1.5 : matchedPrice + offset * 1.5;
        markPointData.push({
          name: tr("walletPage.sell"),
          coord: [midpointMs, y],
          value: "",
          itemStyle: { color: "#da1e28" },
          symbol: "circle",
          symbolSize: 10,
          label: { show: true, formatter: "{c}", position: "inside", fontSize: 9, fontWeight: "bold", color: "#fff" },
        });
      } else if (buyCount > 0 && sellCount > 0) {
        const buyY = isTooHigh ? matchedPrice - offset : matchedPrice + offset * 2;
        const sellY = isTooHigh ? matchedPrice - offset * 2 : matchedPrice + offset;
        markPointData.push({
          name: tr("walletPage.buy"),
          coord: [midpointMs, buyY],
          value: String(buyCount),
          itemStyle: { color: "#24a148" },
          symbol: "circle",
          symbolSize: 10,
          label: { show: true, formatter: "{c}", position: "inside", fontSize: 9, fontWeight: "bold", color: "#fff" },
        });
        markPointData.push({
          name: tr("walletPage.sell"),
          coord: [midpointMs, sellY],
          value: String(sellCount),
          itemStyle: { color: "#da1e28" },
          symbol: "circle",
          symbolSize: 10,
          label: { show: true, formatter: "{c}", position: "inside", fontSize: 9, fontWeight: "bold", color: "#fff" },
        });
      }
    }

    return {
      ...baseOption,
      legend: { show: false },
      grid: { left: 8, right: 8, top: 8, bottom: 24 },
      xAxis: {
        ...baseOption.xAxis,
        type: "time",
        boundaryGap: false as never,
        splitNumber: 4,
        axisLabel: {
          ...baseOption.xAxis?.axisLabel,
          formatter: (val: number) => formatUtcTime(val),
          fontSize: 10,
        },
      },
      yAxis: {
        ...baseOption.yAxis,
        type: "value",
        position: "right" as const,
        axisLabel: {
          ...baseOption.yAxis?.axisLabel,
          formatter: (val: number) => fmt.num.compact.currency(val),
          fontSize: 10,
        },
        min: (v: { min: number; max: number }) => v.min - (v.max - v.min) * 0.15,
        max: (v: { min: number; max: number }) => v.max + (v.max - v.min) * 0.15,
      },
      tooltip: {
        ...baseOption.tooltip,
        trigger: "axis",
        formatter: (params) => {
          if (!Array.isArray(params) || params.length === 0) return "";

          const ts = (params[0].data as [number, number])[0];
          const price = (params[0].data as [number, number])[1];
          const dateStr = formatUtcTime(ts);

          const bucketIdx = Math.floor((ts - startTime) / bucketSizeMs);
          const bucket = bucketMap.get(bucketIdx);

          let tradeInfo = "";
          if (bucket && (bucket.buyCount > 0 || bucket.sellCount > 0)) {
            const parts: string[] = [];
            if (bucket.buyCount > 0) {
              parts.push(`${bucket.buyCount} ${bucket.buyCount === 1 ? tr("walletPage.buy").toLowerCase() : tr("walletPage.buy").toLowerCase() + "s"}`);
            }
            if (bucket.sellCount > 0) {
              parts.push(`${bucket.sellCount} ${bucket.sellCount === 1 ? tr("walletPage.sell").toLowerCase() : tr("walletPage.sell").toLowerCase() + "s"}`);
            }
            const totalAmount = bucket.buyTotalAmount + bucket.sellTotalAmount;
            tradeInfo = `<div style="font-size:11px;margin-top:4px;">${parts.join(", ")} · ${fmt.num.decimal(totalAmount)} ${trades[0]?.symbol ?? ""}</div>`;
          }

          return `
            <div style="padding:4px 0">
              <div style="opacity:0.7;font-size:11px">${dateStr}</div>
              <div style="font-size:13px"><strong>${fmt.num.currency(price)}</strong></div>
              ${tradeInfo}
            </div>`;
        },
      },
      series: [
        {
          name: tokenSymbol,
          type: "line",
          data: chartData,
          showSymbol: false,
          smooth: false,
          lineStyle: { width: 2, color },
          itemStyle: { color },
          areaStyle: {
            color: {
              type: "linear",
              x: 0,
              y: 0,
              x2: 0,
              y2: 1,
              colorStops: [
                { offset: 0, color: `${color}4D` },
                { offset: 1, color: `${color}0D` },
              ],
            },
          },
          markPoint: {
            data: markPointData,
            symbolOffset: [0, 0],
            label: {
              show: true,
            },
          },
        },
      ],
    };
  }, [priceData, trades, tokenSymbol, fmt, tr, baseOption]);

  if (loading) {
    return (
      <div className={styles.chartCard}>
        <div className={styles.chartHeader}>
          <div className={styles.tokenInfo}>
            {tokenLogoUri && (
              <img src={tokenLogoUri} alt={tokenSymbol} className={styles.tokenImg} />
            )}
            <span className={styles.tokenSymbol}>{tokenSymbol}</span>
          </div>
        </div>
        <div className={styles.chartContent}>
          <Flex justify="center" align="center" p={2}>
            <Txt size="sm" secondary>{tr("common.loading")}</Txt>
          </Flex>
        </div>
      </div>
    );
  }

  if (error || priceData.length === 0) {
    return (
      <div className={styles.chartCard}>
        <div className={styles.chartHeader}>
          <div className={styles.tokenInfo}>
            {tokenLogoUri && (
              <img src={tokenLogoUri} alt={tokenSymbol} className={styles.tokenImg} />
            )}
            <span className={styles.tokenSymbol}>{tokenSymbol}</span>
          </div>
          <button className={styles.removeBtn} onClick={onRemove} aria-label={tr("common.cancel")}>
            <Close size={16} />
          </button>
        </div>
        <div className={styles.chartContent}>
          <Flex justify="center" align="center" p={3}>
            <Txt size="sm" secondary>{error ?? tr("common.noData")}</Txt>
          </Flex>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.chartCard}>
      <div className={styles.chartHeader}>
        <div className={styles.tokenInfo}>
          {tokenLogoUri && (
            <img src={tokenLogoUri} alt={tokenSymbol} className={styles.tokenImg} />
          )}
          <span className={styles.tokenSymbol}>{tokenSymbol}</span>
        </div>
        <button className={styles.removeBtn} onClick={onRemove} aria-label={tr("common.cancel")}>
          <Close size={16} />
        </button>
      </div>
      <div className={styles.chartContent}>
        <ReactECharts
          option={chartOption}
          style={{ height: 180, width: "100%" }}
          notMerge
          lazyUpdate
          opts={{ renderer: "canvas" }}
        />
      </div>
    </div>
  );
}

import { PeriodSelector } from "@/components/common/PeriodSelector/PeriodSelector";
import { useLocalization } from "@/contexts/LocalizationContext";
import { useStandardChartController } from "@/hooks/useChartController";
import { useChartFiltersSync } from "@/hooks/useChartFiltersSync";
import {
  CHART_COLOR_PALETTE,
  useCarbonChartBaseOption,
} from "@/util/carbon-chart-base";
import {
  fetchTotalTradingVolume,
  type InferFetcherData,
} from "@/services/chart/chartApi";
import type { TotalTradingVolumeRequestParams } from "@/types/chart-api.types";
import { formatItemTooltip } from "@/util/tooltip-helpers";
import type { EChartsOption } from "echarts";
import ReactECharts from "echarts-for-react";
import { useMemo, useRef } from "react";
import { ChartWrapper, ChartGridItem } from "../shared";
import type { ChartProps } from "../shared/ChartProp";

type TotalTradingVolumeResponse = InferFetcherData<
  typeof fetchTotalTradingVolume
>;

export function TotalTradingVolumeChart({
  title,
  minHeight = 400,
  initialFilters = {
    timePeriod: "30D",
    wallets: [],
  },
  autoRefresh = true,
  refreshInterval = 30000,
  fetchEnabled = true,
}: ChartProps) {
  const { tr, fmt } = useLocalization();
  const chartTitle = title || tr("charts.totalTradingVolumeChart.title");

  const chartRef = useRef<ReactECharts>(null);
  const baseOption = useCarbonChartBaseOption();

  const { filters, walletsString, setTimePeriod } = useChartFiltersSync({
    initialFilters,
    debounceDelay: 300,
  });

  const query = useMemo<TotalTradingVolumeRequestParams>(
    () => ({
      period: filters.timePeriod,
      wallets: walletsString,
    }),
    [filters.timePeriod, walletsString],
  );

  const { data, loadingState, refetch } = useStandardChartController<
    TotalTradingVolumeResponse,
    TotalTradingVolumeRequestParams
  >({
    fetcher: fetchTotalTradingVolume,
    query,
    autoRefresh,
    refreshInterval,
    enabled: fetchEnabled,
  });

  const chartOption = useMemo((): EChartsOption | null => {
    if (
      !data ||
      !data.wallets ||
      !Array.isArray(data.wallets) ||
      data.wallets.length === 0 ||
      "error" in data.wallets
    ) {
      return null;
    }

    const wallets = [...data.wallets].sort(
      (a, b) => (b.tradingVolumeUsd ?? 0) - (a.tradingVolumeUsd ?? 0),
    );
    const categories = wallets.map(
      (w, i) => `#${i + 1} ${w.wallet.slice(0, 6)}...${w.wallet.slice(-4)}`,
    );
    const totalVolumes = wallets.map((w) => w.tradingVolumeUsd ?? 0);

    return {
      ...baseOption,
      legend: { show: false },
      xAxis: {
        ...baseOption.xAxis,
        type: "value",
        name: `Volume (${data.metadata?.currency || "USD"})`,
        axisLabel: {
          ...baseOption.xAxis.axisLabel,
          formatter: (value: number) => fmt.num.compact.currency(value),
        },
      },
      yAxis: {
        ...baseOption.yAxis,
        type: "category",
        data: categories,
        axisLabel: {
          ...baseOption.yAxis.axisLabel,
          interval: 0,
        },
        inverse: true,
      },
      series: [
        {
          name: "Total Volume",
          type: "bar",
          data: totalVolumes,
          itemStyle: {
            color: CHART_COLOR_PALETTE[0],
          },
          label: {
            show: true,
            position: "right",
            formatter: (params: any) => fmt.num.compact.currency(params.value),
            color: baseOption.textStyle.color,
          },
          emphasis: {
            itemStyle: {
              shadowBlur: 10,
              shadowOffsetX: 0,
              shadowColor: "rgba(0, 0, 0, 0.5)",
            },
          },
        },
      ],
      tooltip: {
        ...baseOption.tooltip,
        trigger: "axis",
        axisPointer: {
          type: "shadow",
        },
        formatter: (params: any) => {
          if (!Array.isArray(params) || params.length === 0) return "";
          const wallet = wallets[params[0].dataIndex];
          return formatItemTooltip(wallet.wallet, [
            {
              label: "Total Volume",
              value: fmt.num.compact.currency(wallet.tradingVolumeUsd ?? 0),
            },
          ]);
        },
      },
    };
  }, [data, baseOption, fmt]);

  return (
    <ChartWrapper
      title={chartTitle}
      loadingState={loadingState}
      isEmpty={
        !data ||
        !data.wallets ||
        !Array.isArray(data.wallets) ||
        data.wallets.length === 0 ||
        (data.wallets as any).error
      }
      onRetry={() => refetch(false)}
      toolbarLayout="stacked"
      actions={
        <PeriodSelector
          value={filters.timePeriod}
          onChange={(k) => setTimePeriod(k)}
        />
      }
    >
      {chartOption && (
        <ChartGridItem minHeight={minHeight}>
          <ReactECharts
            ref={chartRef}
            option={chartOption}
            style={{
              height: "100%",
              width: "100%",
              minHeight: `${minHeight}px`,
            }}
            notMerge
            lazyUpdate
          />
        </ChartGridItem>
      )}
    </ChartWrapper>
  );
}

import React, { useMemo, useRef, useCallback, useState, useEffect } from 'react';
import ReactECharts from 'echarts-for-react';
import type { EChartsOption } from 'echarts';
import { useLocalization } from '@/contexts/LocalizationContext';
import { useChartFiltersSync } from '@/hooks/useChartFiltersSync';
import { PeriodSelector } from '@/components/common/PeriodSelector/PeriodSelector';
import { useCarbonChartBaseOption } from '@/util/carbon-chart-base';
import { useCarbonTokens } from '@/hooks/useCarbonToken';
import { cds } from '@/util/carbon-theme';
import { useChartContext } from '@/contexts/ChartContext';
import { fetchTradingVolumeDistribution, type InferFetcherData } from '@/services/chart/chartApi';
import { isChartSuccess } from '@/util/chart-helpers';
import { createTooltipHeader, createTooltipRow } from '@/util/tooltip-helpers';
import type { TradingVolumeDistributionRequestParams } from '@/types/chart-api.types';
import { useStandardChartController } from '@/hooks/useChartController';
import { ChartWrapper, ChartGrid, ChartGridItem } from '@/components/charts/shared';
import { useChartExport } from '@/hooks/useChartExport';
import type { ExportFormat } from '@/types/chart-filters.types';
import type { ChartDataSeries } from '@/types/chart-data.types';
import type { ChartProps } from '../shared/ChartProp';
import { runChartExport } from '@/services/chart/chartExportService';

type TradingVolumeDistributionData = InferFetcherData<typeof fetchTradingVolumeDistribution>;
const DEFAULT_BUY_COLOR = '#24a148';
const DEFAULT_SELL_COLOR = '#da1e28';

export const TradingVolumeDistribution: React.FC<ChartProps> = ({
  minHeight = 400,
  initialFilters,
  autoRefresh = true,
  refreshInterval = 30000,
  fetchEnabled = true,
  className,
  actions,
}) => {
  const { tr, fmt } = useLocalization();
  const chartTitle = tr('charts.tradingVolumeDistributionChart.title');
  const buyLabel = tr('charts.tradingVolumeDistributionChart.buy');
  const sellLabel = tr('charts.tradingVolumeDistributionChart.sell');

  const chartRef = useRef<ReactECharts>(null);
  const baseOption = useCarbonChartBaseOption();
  const tradeColors = useCarbonTokens({
    buy: cds.supportSuccess,
    sell: cds.supportError,
  });
  const { selectedTimezone: timezone } = useChartContext();

  const [selectedAssets, setSelectedAssets] = useState<Set<string>>(new Set());

  const { filters, walletsString, setTimePeriod } = useChartFiltersSync({
    initialFilters,
    debounceDelay: 300,
  });

  const query = useMemo<TradingVolumeDistributionRequestParams>(
    () => ({
      period: filters.timePeriod,
      wallets: walletsString,
    }),
    [filters.timePeriod, walletsString]
  );

  const { data, loadingState, refetch } =
    useStandardChartController<TradingVolumeDistributionData, TradingVolumeDistributionRequestParams>({
      fetcher: fetchTradingVolumeDistribution,
      query,
      autoRefresh,
      refreshInterval,
      enabled: fetchEnabled,
    });

  const { exportPNG, exportSVG, exportPDF, exportCSV } = useChartExport({
    chartTitle,
    timezone,
    baseFilename: 'trading-volume-distribution',
  });

  const handleExport = useCallback(
    async (format: ExportFormat) => {
      if (!isChartSuccess(data, 'wallets')) return;
      if (!data.wallets || !Array.isArray(data.wallets) || data.wallets.length === 0) return;

      const instance = chartRef.current?.getEchartsInstance() ?? null;
      const csv: ChartDataSeries[] = [];

      if (data.wallets && Array.isArray(data.wallets)) {
        data.wallets.forEach((wallet: any) => {
          const buy = wallet.buyVolume ?? 0;
          const sell = wallet.sellVolume ?? 0;
          csv.push({
            id: `trading-volume-distribution-${wallet.wallet}`,
            name: `Trading Volume Distribution - ${wallet.wallet}`,
            type: 'pie',
            visible: true,
            data: [
              { name: buyLabel, value: buy },
              { name: sellLabel, value: sell },
            ],
          });
        });
      }

      await runChartExport(
        {
          format,
          filters,
          chartInstance: instance as any,
          csvData: csv,
        },
        { exportPNG, exportSVG, exportPDF, exportCSV }
      );
    },
    [data, filters, exportPNG, exportSVG, exportPDF, exportCSV]
  );

  const createChartOption = useCallback((
    distributionData: { name: string; value: number; percentage: number; color?: string }[],
    total: number,
    walletLabel?: string,
    isMultiWallet?: boolean
  ): EChartsOption => {
    const filteredData = isMultiWallet && selectedAssets.size > 0
      ? distributionData.filter(a => selectedAssets.has(a.name))
      : distributionData;

    const filteredTotal = filteredData.reduce((sum, a) => sum + a.value, 0);
    const dataWithRecalculatedPercentages = filteredData.map(a => ({
      ...a,
      percentage: filteredTotal > 0 ? (a.value / filteredTotal) * 100 : 0,
    }));

    return {
      ...baseOption,
      xAxis: undefined,
      yAxis: undefined,
      title: walletLabel ? {
        text: walletLabel,
        left: 8,
        top: 8,
        textStyle: {
          color: baseOption.textStyle.color,
          fontSize: 16,
          fontWeight: 'bold',
        },
      } : undefined,
      tooltip: {
        ...baseOption.tooltip,
        trigger: 'item',
        formatter: (p: any) => createTooltipHeader(p.name)
          + createTooltipRow(
            tr('charts.tradingVolumeDistributionChart.volume'),
            fmt.num.compact.currency(Number(p.value ?? 0))
          )
          + createTooltipRow(
            tr('charts.tradingVolumeDistributionChart.percentage'),
            `${p.data.percentage.toFixed(2)}%`
          ),
      },
      legend: {
        show: true,
        data: distributionData.map(d => d.name),
        textStyle: { color: baseOption.textStyle.color },
      },
      series: [
        {
          type: 'pie',
          radius: ['22%', '48%'],
          center: ['50%', '50%'],
          data: dataWithRecalculatedPercentages.map((a) => ({
            name: a.name,
            value: a.value,
            percentage: a.percentage,
            itemStyle: {
              color: (a as any).color,
              borderColor: baseOption.backgroundColor as string,
              borderWidth: 2,
              borderRadius: 6,
            },
          })),
          label: {
            formatter: (p: any) => `${p.name}\n${p.data.percentage.toFixed(1)}%`,
            fontSize: 11,
          },
        },
      ],
      graphic: [
        {
          type: 'text',
          left: 'center',
          top: '46%',
          style: {
            text: tr('charts.tradingVolumeDistributionChart.totalVolume'),
            fill: baseOption.textStyle.color,
            fontSize: 14,
          },
        },
        {
          type: 'text',
          left: 'center',
          top: '50%',
          style: {
            text: fmt.num.compact.currency(isMultiWallet && selectedAssets.size > 0 ? filteredTotal : total),
            fill: baseOption.textStyle.color,
            fontSize: 18,
            fontWeight: 'bold',
          },
        },
      ],
    };
  }, [baseOption, tr, selectedAssets, fmt]);

  const aggregatedLegendData = useMemo(() => {
    if (!data || !data.wallets || !Array.isArray(data.wallets) || data.wallets.length <= 1) return null;
    const buyColor = tradeColors.buy || DEFAULT_BUY_COLOR;
    const sellColor = tradeColors.sell || DEFAULT_SELL_COLOR;

    return [
      {
        name: buyLabel,
        color: buyColor,
      },
      {
        name: sellLabel,
        color: sellColor,
      },
    ];
  }, [data, buyLabel, sellLabel, tradeColors]);

  useEffect(() => {
    if (aggregatedLegendData) {
      setSelectedAssets(new Set(aggregatedLegendData.map(a => a.name)));
    }
  }, [aggregatedLegendData]);

  const toggleAssetSelection = useCallback((assetName: string) => {
    setSelectedAssets(prev => {
      const newSet = new Set(prev);
      if (newSet.has(assetName)) {
        if (newSet.size > 1) {
          newSet.delete(assetName);
        }
      } else {
        newSet.add(assetName);
      }
      return newSet;
    });
  }, []);

  const chartOptions = useMemo(() => {
    if (!data || !data.wallets || !Array.isArray(data.wallets) || data.wallets.length === 0 || (data.wallets as any).error) return [];

    const isMultiWallet = data.wallets.length > 1;

    return data.wallets.map((wallet) => {
      const buy = wallet.buyVolume ?? 0;
      const sell = wallet.sellVolume ?? 0;
      const total = wallet.totalVolume ?? (buy + sell);
      const buyColor = tradeColors.buy || DEFAULT_BUY_COLOR;
      const sellColor = tradeColors.sell || DEFAULT_SELL_COLOR;
      const pieData = [
        { name: buyLabel, value: buy, percentage: total > 0 ? (buy / total) * 100 : 0, color: buyColor },
        { name: sellLabel, value: sell, percentage: total > 0 ? (sell / total) * 100 : 0, color: sellColor },
      ];
      return {
        walletAddress: wallet.walletAddress,
        option: createChartOption(
          pieData,
          total,
          `${wallet.walletAddress.slice(0, 8)}...`,
          isMultiWallet
        ),
      };
    });
  }, [data, createChartOption, buyLabel, sellLabel, tradeColors]);

  const isEmpty = !isChartSuccess(data, 'wallets') || data.wallets.length === 0 || (filters.wallets && filters.wallets.length === 0);

  return (
    <ChartWrapper
      title={chartTitle}
      loadingState={loadingState}
      isEmpty={isEmpty}
      emptyState={filters.wallets && filters.wallets.length === 0
        ? {
          title: tr('charts.tradingVolumeDistributionChart.noWalletsTitle'),
          message: tr('charts.tradingVolumeDistributionChart.noWalletsMessage'),
        }
        : undefined}
      onRetry={() => refetch(false)}
      onExport={handleExport}
      className={className}
      actions={actions}
    >
      <div data-html2canvas-ignore="true" style={{ padding: '0.5rem' }}>
        <PeriodSelector value={filters.timePeriod} onChange={(k) => setTimePeriod(k)} compact />
      </div>

      {chartOptions.length > 0 && (
        <div style={{ display: 'flex', flexDirection: 'column', width: '100%' }}>
          {aggregatedLegendData && chartOptions.length > 1 && (
            <div
              data-html2canvas-ignore="true"
              style={{
                display: 'flex',
                flexWrap: 'wrap',
                gap: '1rem',
                padding: '1rem',
                justifyContent: 'center',
                borderBottom: '1px solid var(--cds-border-subtle)',
                marginBottom: '1rem',
              }}
            >
              {aggregatedLegendData.map((asset) => {
                const isSelected = selectedAssets.has(asset.name);
                return (
                  <div
                    key={asset.name}
                    onClick={() => toggleAssetSelection(asset.name)}
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: '0.5rem',
                      cursor: 'pointer',
                      opacity: isSelected ? 1 : 0.3,
                      transition: 'opacity 0.2s ease',
                      userSelect: 'none',
                    }}
                    title={isSelected ? `Click to hide ${asset.name}` : `Click to show ${asset.name}`}
                  >
                    <span
                      style={{
                        width: '12px',
                        height: '12px',
                        borderRadius: '50%',
                        backgroundColor: asset.color,
                        opacity: isSelected ? 1 : 0.5,
                      }}
                    />
                    <span style={{ fontSize: '14px', color: baseOption.textStyle.color }}>
                      {asset.name}
                    </span>
                  </div>
                );
              })}
            </div>
          )}

          <ChartGrid itemCount={chartOptions.length} multiItemColumns={3}>
            {chartOptions.map((chartData, index) => (
              <ChartGridItem
                key={chartData.walletAddress}
                itemKey={chartData.walletAddress}
                minHeight={minHeight}
                aspectRatio="1"
              >
                <ReactECharts
                  ref={index === 0 ? chartRef : undefined}
                  option={chartData.option}
                  style={{ height: '100%', width: '100%', minHeight: `${minHeight}px` }}
                  notMerge
                  lazyUpdate
                />
              </ChartGridItem>
            ))}
          </ChartGrid>
        </div>
      )}
    </ChartWrapper>
  );
};

import { PeriodSelector } from "@/components/common/PeriodSelector/PeriodSelector";
import { useLocalization } from "@/contexts/LocalizationContext";
import { useStandardChartController } from "@/hooks/useChartController";
import { useChartFiltersSync } from "@/hooks/useChartFiltersSync";
import {
  CHART_COLOR_PALETTE,
