    if (
      !data ||
      !data.wallets ||
      !Array.isArray(data.wallets) ||
      data.wallets.length === 0
    ) {
      return null;
    }

    const categories = data.wallets.map((w) => w.wallet);
    const values = data.wallets.map(
      (w) => w.tradingVolumePerTransaction,
    );

    return {
      ...baseOption,
      xAxis: {
        ...baseOption.xAxis,
        type: "category",
        data: categories,
        axisLabel: {
          ...baseOption.xAxis.axisLabel,
          interval: 0,
          rotate: categories.length > 5 ? 45 : 0,
        },
        splitLine: {
          show: false,
        },
      },
      yAxis: {
        ...baseOption.yAxis,
        type: "value",
        name: tr("charts.tradingVolumePerTransactionChart.volume"),
        axisLabel: {
          ...baseOption.yAxis.axisLabel,
          formatter: (value: number) => fmt.num.compact.currency(value),
        },
      },
      series: [
        {
          name: "Trading Volume per Transaction",
          type: "bar",
          data: values,
          itemStyle: {
            color: CHART_COLOR_PALETTE[0],
          },
          label: {
            show: true,
            position: "top",
            formatter: (params: any) => fmt.num.compact.currency(params.value),
            color: baseOption.textStyle.color,
          },
        },
      ],
      tooltip: {
        ...baseOption.tooltip,
        trigger: "item",
        axisPointer: {
          type: "shadow",
        },
      },
    };
  }, [data, baseOption, tr, fmt]);

  return (
    <ChartWrapper
      title={chartTitle}
      loadingState={loadingState}
      isEmpty={
        !data ||
        !data.wallets ||
        !Array.isArray(data.wallets) ||
        data.wallets.length === 0 ||
        (data.wallets as any).error
      }
      onRetry={() => refetch(false)}
      toolbarLayout="stacked"
      actions={
        <PeriodSelector
          value={filters.timePeriod}
          onChange={(k) => setTimePeriod(k)}
          compact
        />
      }
    >
      {chartOption && (
        <ChartGridItem minHeight={minHeight}>
          <ReactECharts
            ref={chartRef}
            option={chartOption}
            style={{
              height: "100%",
              width: "100%",
              minHeight: `${minHeight}px`,
            }}
            notMerge
            lazyUpdate
          />
        </ChartGridItem>
      )}
    </ChartWrapper>
  );
}

import { useMemo, useRef, useState } from 'react';
import ReactECharts from 'echarts-for-react';
import { useLocalization } from '@/contexts/LocalizationContext';
import { ChartWrapper, ChartGridItem } from '@/components/charts/shared';
import { useChartFiltersSync } from '@/hooks/useChartFiltersSync';
import {
  CHART_COLOR_PALETTE,
  useCarbonChartBaseOption,
} from '@/util/carbon-chart-base';
import { useChartContext } from '@/contexts/ChartContext';
import { fetchTransactionDistribution, type InferFetcherData } from '@/services/chart/chartApi';
import { formatDate, isChartSuccess } from '@/util/chart-helpers';
import { formatAxisTooltip } from '@/util/tooltip-helpers';
import type { TransactionDistributionRequestParams } from '@/types/chart-api.types';

type TransactionDistributionData = InferFetcherData<typeof fetchTransactionDistribution>;
import type { TimePeriod, TransactionType } from '@/types/chart-filters.types';
import { useStandardChartController } from '@/hooks/useChartController';
import { Flex } from '@/components/Flex';
import { FilterSwitch } from '@/components/FilterSwitch';

interface TransactionDistributionProps {
  title?: string;
  minHeight?: number;
  initialTimePeriod?: TimePeriod;
  initialTransactionType?: TransactionType;
  chartMode?: 'stacked' | 'grouped';
  walletIds?: string[];
  autoRefresh?: boolean;
  refreshInterval?: number;
  onDataLoaded?: (data: TransactionDistributionData) => void;
  className?: string;
}

export function TransactionDistribution({
  title,
  minHeight = 400,
  initialTimePeriod = '30D',
  initialTransactionType = 'all',
  chartMode = 'stacked',
  walletIds = [],
  autoRefresh = true,
  refreshInterval = 30000,
  onDataLoaded,
}: TransactionDistributionProps) {
  const { tr } = useLocalization();
  const chartTitle = title || tr('charts.transactionDistributionChart.title');

  const [selectedChartMode, setSelectedChartMode] = useState<'stacked' | 'grouped'>(chartMode);

  const transactionChartRef = useRef<ReactECharts>(null);
  const tokenChartRef = useRef<ReactECharts>(null);

  const { selectedTimezone: timezone } = useChartContext();
  const baseOption = useCarbonChartBaseOption();

  const { filters, walletsString } = useChartFiltersSync({
    initialFilters: {
      timePeriod: initialTimePeriod,
      transactionType: initialTransactionType,
      wallets: walletIds.length > 0 ? walletIds : undefined,
    },
    debounceDelay: 300,
  });

  const query = useMemo<TransactionDistributionRequestParams>(
    () => ({
      timePeriod: filters.timePeriod,
      transactionType: filters.transactionType,
      walletIds: walletsString,
      timezone,
    }),
    [filters.timePeriod, filters.transactionType, walletsString, timezone]
  );

  const { data, loadingState, refetch } =
    useStandardChartController<TransactionDistributionData, TransactionDistributionRequestParams>({
      fetcher: fetchTransactionDistribution,
      query,
      autoRefresh,
      refreshInterval,
      onDataLoaded,
    });

  const transactionCountsOptions = useMemo(() => {
    if (!isChartSuccess(data, 'transactionCounts')) {
      return {};
    }

    const series = data.transactionCounts.map((wallet, index) => ({
      name: wallet.walletName,
      type: 'bar' as const,
      stack: selectedChartMode === 'stacked' ? 'total' : undefined,
      data: wallet.data.map(point => [point.timestamp, point.value]),
      label: {
        show: wallet.data.length <= 30,
        position: selectedChartMode === 'stacked' ? 'inside' : 'top',
        formatter: (params: any) => {
          const value = params.value[1];
          return value > 0 ? value.toString() : '';
        },
        fontSize: 10,
      },
      color: CHART_COLOR_PALETTE[index % CHART_COLOR_PALETTE.length],
      emphasis: {
        focus: 'series',
      },
    }));

    return {
      ...baseOption,
      tooltip: {
        ...baseOption.tooltip,
        trigger: 'axis',
        axisPointer: {
          type: 'shadow',
        },
        formatter: (params: any) => {
          if (!Array.isArray(params) || params.length === 0) return '';

          const timestamp = params[0].value[0];
          const dateStr = formatDate(new Date(timestamp), timezone);

          let tooltipContent = `<strong>${dateStr}</strong><br/>`;
          let total = 0;

          params.forEach((param: any) => {
            const count = param.value[1];
            total += count;
            const color = param.color;
            tooltipContent += `
              <div style="display: flex; align-items: center; margin-top: 4px;">
                <span style="display: inline-block; width: 10px; height: 10px; background-color: ${color}; margin-right: 8px; border-radius: 50%;"></span>
                <span style="flex: 1;">${param.seriesName}:</span>
                <strong style="margin-left: 8px;">${count}</strong>
              </div>
            `;
          });

          if (selectedChartMode === 'stacked') {
            tooltipContent += `<div style="margin-top: 8px; padding-top: 4px; border-top: 1px solid #ccc;"><strong>Total: ${total}</strong></div>`;
          }

          return tooltipContent;
        },
      },
      legend: {
        show: true,
        data: data.transactionCounts.map(w => w.walletName),
        textStyle: { color: baseOption.textStyle.color },
      },
      xAxis: {
        ...baseOption.xAxis,
        type: 'time',
        axisLabel: {
          ...baseOption.xAxis.axisLabel,
          formatter: (value: number) => formatDate(new Date(value), timezone, 'MMM dd'),
        },
      },
      yAxis: {
        ...baseOption.yAxis,
        type: 'value',
        name: 'Transaction count',
        axisLabel: {
          ...baseOption.yAxis.axisLabel,
          formatter: (value: number) => value.toFixed(0),
        },
      },
      series,
      dataZoom: [
        {
          type: 'inside',
          start: 0,
          end: 100,
        },
        {
          type: 'slider',
          show: data.transactionCounts[0]?.data.length > 50,
          start: 0,
          end: 100,
          height: 20,
          bottom: 10,
        },
      ],
    };
  }, [data, selectedChartMode, timezone, baseOption]);

  const uniqueTokenCountsOptions = useMemo(() => {
    if (!isChartSuccess(data, 'transactionCounts')) {
      return {};
    }

    return {
      ...baseOption,
      tooltip: {
        trigger: 'axis',
        axisPointer: {
          type: 'cross',
          crossStyle: {
            color: '#999',
          },
        },
        formatter: (params: any) => formatAxisTooltip(
          params,
          (p) => formatDate(new Date(p.value[0]), timezone),
          (p) => p.value[1].toString()
        ),
      },
      xAxis: {
        ...baseOption.xAxis,
        type: 'time',
        axisLabel: {
          ...baseOption.xAxis.axisLabel,
          formatter: (value: number) => formatDate(new Date(value), timezone, 'MMM dd'),
        },
      },
      yAxis: {
        ...baseOption.yAxis,
        type: 'value',
        name: 'Unique token traded',
        axisLabel: {
          ...baseOption.yAxis.axisLabel,
          formatter: (value: number) => value.toFixed(0),
        },
      },
      series: [
        {
          name: tr('charts.transactionDistributionChart.tokens'),
          type: 'line',
          data: data.uniqueTokenCounts.map(point => [point.timestamp, point.value]),
          smooth: 0.3,
          showSymbol: data.uniqueTokenCounts.length <= 50,
          symbolSize: 6,
          itemStyle: {
            color: CHART_COLOR_PALETTE[1],
          },
          areaStyle: {
            color: {
              type: 'linear',
              x: 0,
              y: 0,
              x2: 0,
              y2: 1,
              colorStops: [
                { offset: 0, color: `${CHART_COLOR_PALETTE[1]}4D` },
                { offset: 1, color: `${CHART_COLOR_PALETTE[1]}0D` },
              ],
            },
          },
          label: {
            show: data.uniqueTokenCounts.length <= 30,
            position: 'top',
            formatter: (params: any) => params.value[1].toString(),
            fontSize: 10,
          },
        },
      ],
      dataZoom: [
        {
          type: 'inside',
          start: 0,
          end: 100,
        },
        {
          type: 'slider',
          show: data.uniqueTokenCounts.length > 50,
          start: 0,
          end: 100,
          height: 20,
          bottom: 10,
        },
      ],
    };
  }, [data, timezone, baseOption, tr]);

  const handleChartModeChange = (mode: 'stacked' | 'grouped') => {
    setSelectedChartMode(mode);
  };

  const handleRetry = () => {
    refetch(false);
  };

  const chartModeOptions = [
    { value: 'stacked' as const, label: tr('charts.transactionDistributionChart.stacked') },
    { value: 'grouped' as const, label: tr('charts.transactionDistributionChart.grouped') },
  ];

  return (
    <ChartWrapper
      title={chartTitle}
      loadingState={loadingState}
      onRetry={handleRetry}
      isEmpty={!isChartSuccess(data, 'transactionCounts') || (data.transactionCounts.length === 0 && data.uniqueTokenCounts.length === 0)}
      toolbarLayout="stacked"
      actions={
        <Flex gap={8} align="center">
          <div style={{ width: 160 }}>
            <FilterSwitch
              options={chartModeOptions}
              value={selectedChartMode}
              onChange={(v) => handleChartModeChange(v as 'stacked' | 'grouped')}
            />
          </div>
        </Flex>
      }
    >
      {data && (
        <ChartGridItem minHeight={minHeight}>
          <ReactECharts
            ref={transactionChartRef}
            option={transactionCountsOptions}
            style={{ height: '100%', width: '100%', minHeight: `${minHeight}px` }}
            opts={{ renderer: 'canvas' }}
            notMerge={true}
            lazyUpdate={true}
          />
        </ChartGridItem>
      )}

      {data && (
        <ChartGridItem minHeight={minHeight}>
          <ReactECharts
            ref={tokenChartRef}
            option={uniqueTokenCountsOptions}
            style={{ height: '100%', width: '100%', minHeight: `${minHeight}px` }}
            opts={{ renderer: 'canvas' }}
            notMerge={true}
            lazyUpdate={true}
          />
        </ChartGridItem>
      )}
    </ChartWrapper>
  );
}

import { useMemo, useRef, useState } from 'react';
import ReactECharts from 'echarts-for-react';
import type { EChartsOption } from 'echarts';
import { useLocalization } from '@/contexts/LocalizationContext';
import { formatItemTooltip } from '@/util/tooltip-helpers';
import { useChartFiltersSync } from '@/hooks/useChartFiltersSync';
import {
  CHART_COLOR_PALETTE,
  useCarbonChartBaseOption,
} from '@/util/carbon-chart-base';
import type { WinrateRequestParams } from '@/types/chart-api.types';
import { ChartWrapper, ChartContainer, ChartSection, ChartGrid, ChartGridItem } from '../shared';
import type { ChartProps } from '../shared/ChartProp';
import { SegmentedControl, chartControlStyles } from '@/components/charts/shared/ChartControls';
import { useGet, UseGetResp } from '@/hooks/useGet';
import client from '@/api/main';

interface WinrateBin {
  range: string;
  count: number;
  min: number;
  max: number;
}

type WinrateData = {
  wallets: {
    walletAddress: string;
    walletName?: string | undefined;
    winrate: number;
    totalTrades: number;
    winningTrades: number;
    losingTrades: number;
    winningDistribution: WinrateBin[];
    losingDistribution: WinrateBin[];
    avgWinUsd: number;
    avgLossUsd: number;
  }[];
}

export function WinrateChart({
  title,
  minHeight = 400,
  initialFilters = {
    timePeriod: "30D",
    wallets: [],
  },
}: ChartProps) {
  type WinrateTimeRange = "24H" | "7D" | "30D" | "90D";
  const WINRATE_TIME_RANGES: WinrateTimeRange[] = ["24H", "7D", "30D", "90D"];

  const { tr, fmt } = useLocalization();
  const chartTitle = title || tr("charts.winrateChart.title");
  const [timeRange, setTimeRange] = useState<WinrateTimeRange>("30D");

  const overallChartRef = useRef<ReactECharts>(null);
  const baseOption = useCarbonChartBaseOption();

  const { walletsString } = useChartFiltersSync({
    initialFilters,
    debounceDelay: 300,
  });

  useMemo<WinrateRequestParams>(
    () => ({
      period: timeRange,
      wallets: walletsString,
    }),
    [timeRange, walletsString],
  );

  const winRateData: UseGetResp<WinrateData> = useGet(client.api.wallets.analysis.winrate, 200, {
    query: {
      wallets: walletsString ?? "",
      period: timeRange,
    }
  })

  const overallWinrateOption = useMemo((): EChartsOption | null => {
    if (!winRateData.data || winRateData.data.wallets.length == 0) {
      return null;
    }

    const data = winRateData.data;

    const categories = data.wallets.map(w => fmt.text.address(w.walletAddress));
    const winrateValues = data.wallets.map(w => w.winrate);

    return {
      ...baseOption,
      xAxis: {
        ...baseOption.xAxis,
        type: "category",
        data: categories,
        axisLabel: {
          ...baseOption.xAxis.axisLabel,
          interval: 0,
          rotate: categories.length > 5 ? 30 : 0,
        },
      },
      yAxis: {
        ...baseOption.yAxis,
        type: "value",
        name: "Winrate (%)",
        min: 0,
        max: 100,
        axisLabel: {
          ...baseOption.yAxis.axisLabel,
          formatter: "{value}%",
        },
      },
      series: [
        {
          name: "Winrate",
          type: "bar",
          data: winrateValues,
          itemStyle: {
            color: CHART_COLOR_PALETTE[0],
          },
          label: {
            show: true,
            position: 'top',
            formatter: '{c}%',
            color: baseOption.textStyle.color,
          },
        },
      ],
      legend: undefined,
      tooltip: {
        ...baseOption.tooltip,
        trigger: "axis",
        formatter: (params: any) => {
          const param = params[0];
          const wallet = data.wallets[param.dataIndex];
          return formatItemTooltip(fmt.text.address(wallet.walletAddress), [
            { label: "Winrate", value: `${param.value}%` },
            { label: "Winning Trades", value: wallet.winningTrades.toString() },
            { label: "Losing Trades", value: wallet.losingTrades.toString() },
            { label: "Total Trades", value: wallet.totalTrades.toString() },
          ]);
        },
      },
    };
  }, [winRateData.data, baseOption]);

  const distributionCharts = useMemo(() => {
    if (!winRateData.data || winRateData.data.wallets.length == 0) {
      return [];
    }
    const data = winRateData.data;

    return data.wallets.map((wallet) => {
      const categories = [
        ...wallet.losingDistribution.map(d => d.range),
        ...wallet.winningDistribution.map(d => d.range),
      ];
      const winningCounts = [
        ...wallet.losingDistribution.map(() => 0),
        ...wallet.winningDistribution.map(d => d.count),
      ];
      const losingCounts = [
        ...wallet.losingDistribution.map(d => -d.count),
        ...wallet.winningDistribution.map(() => 0),
      ];

      const option: EChartsOption = {
        ...baseOption,
        title: wallet.walletAddress ? {
          text: fmt.text.address(wallet.walletAddress),
          left: 8,
          top: 8,
          textStyle: {
            color: baseOption.textStyle.color,
            fontSize: 16,
            fontWeight: 'bold',
          },
        } : undefined,
        grid: {
          left: "8%",
          right: "8%",
          bottom: "12%",
          top: "24%",
          containLabel: true,
        },
        xAxis: {
          ...baseOption.xAxis,
          type: "category",
          data: categories,
          axisLabel: {
            ...baseOption.xAxis.axisLabel,
            interval: 0,
            rotate: 30,
          },
        },
        yAxis: {
          ...baseOption.yAxis,
          type: "value",
          name: "Trade Count",
          axisLabel: {
            ...baseOption.yAxis.axisLabel,
            formatter: (value: number) => Math.abs(value).toString(),
          },
        },
        series: [
          {
            name: "Winning",
            type: "bar",
            stack: "total",
            data: winningCounts,
            itemStyle: {
              color: CHART_COLOR_PALETTE[1],
            },
          },
          {
            name: "Losing",
            type: "bar",
            stack: "total",
            data: losingCounts,
            itemStyle: {
              color: CHART_COLOR_PALETTE[2],
            },
          },
        ],
        legend: {
          show: true,
          data: ['Winning', 'Losing'],
          textStyle: { color: baseOption.textStyle.color },
        },
        tooltip: {
          ...baseOption.tooltip,
          trigger: "axis",
          axisPointer: {
            type: "shadow",
          },
          formatter: (params: any) => {
            const winning = params.find((p: any) => p.seriesName === "Winning");
            const losing = params.find((p: any) => p.seriesName === "Losing");
            return `
              <div style="font-weight: 600; margin-bottom: 8px;">${params[0].name}</div>
              ${winning ? `<div style="display: flex; justify-content: space-between; gap: 16px;">
                <span style="color: ${CHART_COLOR_PALETTE[1]}">● Winning:</span><strong>${winning.value}</strong>
              </div>` : ''}
              ${losing ? `<div style="display: flex; justify-content: space-between; gap: 16px;">
                <span style="color: ${CHART_COLOR_PALETTE[2]}">● Losing:</span><strong>${Math.abs(losing.value)}</strong>
              </div>` : ''}
            `;
          },
        },
      };

      return {
        walletAddress: wallet.walletAddress,
        option,
      };
    });
  }, [winRateData.data, baseOption]);

  const timeRangeOptions = WINRATE_TIME_RANGES.map(r => ({ value: r, label: r }));

  return (
    <ChartWrapper
      title={chartTitle}
      loadingState={{
        status: winRateData.isLoading ? "loading" : "idle",
        retryCount: 0,
      }}
      isEmpty={winRateData.data ? winRateData.data.wallets.length > 0 : false}
      onRetry={() => winRateData.mutate()}
      toolbarLayout="stacked"
      enableMiniPlayer={false}
      enableExport={false}
      enableFullscreen={false}
      actions={
        <div className={chartControlStyles.toolbar}>
          <SegmentedControl
            ariaLabel={tr("charts.timePeriod")}
            options={timeRangeOptions}
            value={timeRange}
            onChange={(value) => {
              if (
                value === "24H" ||
                value === "7D" ||
                value === "30D" ||
                value === "90D"
              ) {
                setTimeRange(value);
              }
            }}
          />
        </div>
      }
    >
      <ChartContainer gap="0">
        <ChartSection minHeight="300px">
          {overallWinrateOption && (
            <ChartGridItem minHeight={300}>
              <ReactECharts
                ref={overallChartRef}
                option={overallWinrateOption}
                style={{
                  height: "100%",
                  width: "100%",
                  minHeight: `${minHeight}px`,
                }}
                notMerge
                lazyUpdate
              />
            </ChartGridItem>
          )}
        </ChartSection>

        <ChartGrid
          itemCount={distributionCharts?.length}
          autoFit
          minColumnWidth="400px"
        >
          {distributionCharts.map((chart) => (
            <ChartGridItem
              key={chart.walletAddress}
              itemKey={chart.walletAddress}
              minHeight={300}
            >
              <ReactECharts
                option={chart.option}
                style={{ height: "100%", width: "100%" }}
                notMerge
                lazyUpdate
              />
            </ChartGridItem>
          ))}
        </ChartGrid>
      </ChartContainer>
    </ChartWrapper>
  );
}

/**
 * FullscreenView Component
 *
 * Provides fullscreen viewing mode for charts with native API support and modal fallback.
 *
 * Features:
 * - Native Fullscreen API with modal fallback
 * - ESC key handler for exit
 * - Focus trap for keyboard navigation
 * - Dark overlay for enhanced visibility
 * - Loading state during fullscreen transition
 *
 * @module components/charts/shared/FullscreenView
 */

import { Theme } from "@carbon/react";
import React, { useCallback, useEffect, useRef } from "react";
import { createPortal } from "react-dom";
import { useLocalization } from "@/contexts/LocalizationContext";
import { useUserTheme } from "../../../contexts/ThemeContext";
import styles from "./FullscreenView.module.scss";

export interface FullscreenViewProps {
  /** Whether fullscreen mode is active */
  isActive: boolean;

  /** Callback when fullscreen is exited */
  onExit: () => void;

  /** Content to display in fullscreen */
  children: React.ReactNode;

  /** Chart title for accessibility */
  title?: string;
}

/**
 * FullscreenView Component
 *
 * Displays chart content in fullscreen mode with keyboard navigation support.
 * Uses native Fullscreen API when available, falls back to modal overlay.
 */
export const FullscreenView: React.FC<FullscreenViewProps> = ({
  isActive,
  onExit,
  children,
  title = "Chart",
}) => {
  const { tr } = useLocalization();
  const { theme } = useUserTheme();
  const containerRef = useRef<HTMLDivElement>(null);
  const previousFocusRef = useRef<HTMLElement | null>(null);

  /**
   * Handle ESC key press to exit fullscreen
   */
  const handleKeyDown = useCallback(
    (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        event.preventDefault();
        onExit();
      }
    },
    [onExit],
  );

  /**
   * Handle fullscreen change events
   */
  const handleFullscreenChange = useCallback(() => {
    if (!document.fullscreenElement) {
      onExit();
    }
  }, [onExit]);

  /**
   * Request native fullscreen mode
   */
  const requestFullscreen = useCallback(async () => {
    if (!containerRef.current) return;

    try {
      if (containerRef.current.requestFullscreen) {
        await containerRef.current.requestFullscreen();
      }
    } catch (error) {
      console.warn(
        "Fullscreen API not supported, using modal fallback:",
        error,
      );
    }
  }, []);

  /**
   * Exit native fullscreen mode
   */
  const exitFullscreen = useCallback(async () => {
    try {
      if (document.fullscreenElement && document.exitFullscreen) {
        await document.exitFullscreen();
      }
    } catch (error) {
      console.warn("Error exiting fullscreen:", error);
    }
  }, []);

  /**
   * Setup focus trap for keyboard navigation
   */
  useEffect(() => {
    if (!isActive || !containerRef.current) return;

    // Store previously focused element
    previousFocusRef.current = document.activeElement as HTMLElement;

    // Focus the container
    containerRef.current.focus();

    // Setup focus trap
    const focusableElements = containerRef.current.querySelectorAll(
      'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])',
    );

    const firstElement = focusableElements[0] as HTMLElement;
    const lastElement = focusableElements[
      focusableElements.length - 1
    ] as HTMLElement;

    const handleTabKey = (event: KeyboardEvent) => {
      if (event.key !== "Tab") return;

      if (event.shiftKey) {
        // Shift + Tab
        if (document.activeElement === firstElement) {
          event.preventDefault();
          lastElement?.focus();
        }
      } else {
        // Tab
        if (document.activeElement === lastElement) {
          event.preventDefault();
          firstElement?.focus();
        }
      }
    };

    containerRef.current.addEventListener("keydown", handleTabKey);

    return () => {
      containerRef.current?.removeEventListener("keydown", handleTabKey);

      // Restore focus to previous element
      if (previousFocusRef.current) {
        previousFocusRef.current.focus();
      }
    };
  }, [isActive]);

  /**
   * Setup fullscreen API and keyboard handlers
   */
  useEffect(() => {
    if (!isActive) return;

    // Try to use native fullscreen API
    requestFullscreen();

    // Add event listeners
    document.addEventListener("keydown", handleKeyDown);
    document.addEventListener("fullscreenchange", handleFullscreenChange);

    return () => {
      document.removeEventListener("keydown", handleKeyDown);
      document.removeEventListener("fullscreenchange", handleFullscreenChange);
      exitFullscreen();
    };
  }, [
    isActive,
    handleKeyDown,
    handleFullscreenChange,
    requestFullscreen,
    exitFullscreen,
  ]);

  if (!isActive) {
    return null;
  }

  return createPortal(
    <Theme theme={theme === "dark" ? "g100" : "white"}>
      <div
        ref={containerRef}
        className={styles.fullscreenView}
        role="dialog"
        aria-modal="true"
        aria-label={`${title} - ${tr("charts.fullscreenView")}`}
        tabIndex={-1}
      >
        <div className={styles.header}>
          <h2 className={styles.title}>{title}</h2>
          <button
            className={styles.exitButton}
            onClick={onExit}
            aria-label={tr("charts.exitFullscreen")}
            title={tr("charts.exitFullscreenEsc")}
          >
            <svg
              width="24"
              height="24"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <line x1="18" y1="6" x2="6" y2="18" />
              <line x1="6" y1="6" x2="18" y2="18" />
            </svg>
          </button>
        </div>

        <div className={styles.content}>{children}</div>
      </div>
    </Theme>,
    document.body,
  );
};

export default FullscreenView;

/**
 * MiniPlayer Component
 *
 * Provides a draggable and resizable mini-player mode for charts.
 *
 * Features:
 * - Drag and resize with react-rnd
 * - ESC key to close
 * - Minimize/maximize controls
 * - Persistent position and size
 * - Z-index management for multiple mini-players
 *
 * @module components/charts/shared/MiniPlayer
 */

import { useUserTheme } from "@/contexts/ThemeContext";
import { Theme } from "@carbon/react";
import React, { useCallback, useRef, useState } from "react";
import { createPortal } from "react-dom";
import { useLocalization } from "@/contexts/LocalizationContext";
import { Rnd } from "react-rnd";
import type { DraggableEventHandler } from "react-draggable";
import styles from "./MiniPlayer.module.scss";

// Constants
const MINI_PLAYER_DEFAULTS = {
  WIDTH: 500,
  HEIGHT: 400,
  MIN_WIDTH: 320,
  MIN_HEIGHT: 240,
  HEADER_HEIGHT: 80,
  MAX_WIDTH_RATIO: 0.9,
  MAX_HEIGHT_RATIO: 0.9,
  Z_INDEX: 999,
} as const;

export interface MiniPlayerProps {
  /** Whether mini-player mode is active */
  isActive: boolean;

  /** Callback when mini-player is closed */
  onClose: () => void;

  /** Content to display in mini-player */
  children: React.ReactNode;

  /** Chart title */
  title?: string;

  /** Initial position (default: bottom-right) */
  defaultPosition?: { x: number; y: number };

  /** Initial size (default: 500x400) */
  defaultSize?: { width: number; height: number };
}

/**
 * MiniPlayer Component
 *
 * Displays chart content in a draggable, resizable mini-player window.
 */
export const MiniPlayer: React.FC<MiniPlayerProps> = ({
  isActive,
  onClose,
  children,
  title = "Chart",
  defaultPosition,
  defaultSize = {
    width: MINI_PLAYER_DEFAULTS.WIDTH,
    height: MINI_PLAYER_DEFAULTS.HEIGHT,
  },
}) => {
  const { tr } = useLocalization();
  const { theme } = useUserTheme();
  const [isMinimized, setIsMinimized] = useState(false);
  const [size, setSize] = useState(defaultSize);
  const previousSizeRef = useRef(defaultSize);

  // Calculate position relative to current scroll position
  const getInitialPosition = useCallback(() => {
    if (defaultPosition) return defaultPosition;

    // Get current scroll position
    const scrollX = window.pageXOffset || document.documentElement.scrollLeft;
    const scrollY = window.pageYOffset || document.documentElement.scrollTop;

    // Calculate position in document coordinates (viewport position + scroll)
    return {
      x: scrollX + window.innerWidth - size.width,
      y: scrollY + window.innerHeight - size.width,
    };
  }, [defaultPosition]);

  const [position, setPosition] = useState(getInitialPosition);

  // Update position when activated to account for current scroll position
  React.useEffect(() => {
    if (isActive) {
      setPosition(getInitialPosition());
    }
  }, [isActive, getInitialPosition]);

  /**
   * Handle ESC key press to close mini-player
   */
  const handleKeyDown = useCallback(
    (event: React.KeyboardEvent) => {
      if (event.key === "Escape") {
        event.preventDefault();
        onClose();
      }
    },
    [onClose],
  );

  /**
   * Toggle minimize/maximize state
   */
  const toggleMinimize = useCallback(() => {
    if (isMinimized) {
      // Restore previous size
      setSize(previousSizeRef.current);
    } else {
      // Store current size before minimizing
      previousSizeRef.current = size;
      setSize({
        width: size.width,
        height: MINI_PLAYER_DEFAULTS.HEADER_HEIGHT,
      }); // Minimize to header only
    }
    setIsMinimized(!isMinimized);
  }, [isMinimized, size]);

  /**
   * Handle drag stop to save position
   */
  const handleDragStop: DraggableEventHandler = useCallback(
    (_e, data) => {
      setPosition({
        x: data.x,
        y: Math.max(data.y, MINI_PLAYER_DEFAULTS.HEADER_HEIGHT),
      });
    },
    [],
  );

  /**
   * Handle resize stop to save size
   */
  const handleResizeStop = useCallback(
    (
      _e: MouseEvent | TouchEvent,
      _direction: string,
      ref: HTMLElement,
      _delta: { width: number; height: number },
      position: { x: number; y: number },
    ) => {
      setSize({
        width: ref.offsetWidth,
        height: ref.offsetHeight,
      });
      setPosition({
        x: position.x,
        y: Math.max(position.y, MINI_PLAYER_DEFAULTS.HEADER_HEIGHT),
      });
    },
    [],
  );

  if (!isActive) {
    return null;
  }

  return createPortal(
    <Rnd
      position={{
        x: position.x,
        y: position.y,
      }}
      size={{
        width: size.width,
        height: size.height,
      }}
      minWidth={MINI_PLAYER_DEFAULTS.MIN_WIDTH}
      minHeight={
        isMinimized
          ? MINI_PLAYER_DEFAULTS.HEADER_HEIGHT
          : MINI_PLAYER_DEFAULTS.MIN_HEIGHT
      }
      maxWidth={window.innerWidth * MINI_PLAYER_DEFAULTS.MAX_WIDTH_RATIO}
      maxHeight={window.innerHeight * MINI_PLAYER_DEFAULTS.MAX_HEIGHT_RATIO}
      bounds="parent"
      dragHandleClassName={styles.header}
      onDragStop={handleDragStop}
      onResizeStop={handleResizeStop}
      enableResizing={!isMinimized}
      style={{
        zIndex: MINI_PLAYER_DEFAULTS.Z_INDEX,
      }}
      className={styles.miniPlayer}
    >
      <Theme theme={theme === "dark" ? "g100" : "white"}>
        <div
          className={styles.container}
          onKeyDown={handleKeyDown}
          role="dialog"
          aria-modal="false"
          aria-label={`${title} - ${tr("charts.miniPlayer")}`}
          tabIndex={-1}
        >
          <div className={styles.header}>
            <div className={styles.headerLeft}>
              <div
                className={styles.dragHandle}
                aria-label={tr("charts.dragToMove")}
              >
                <svg
                  width="16"
                  height="16"
                  viewBox="0 0 16 16"
                  fill="currentColor"
                >
                  <circle cx="4" cy="4" r="1.5" />
                  <circle cx="4" cy="8" r="1.5" />
                  <circle cx="4" cy="12" r="1.5" />
                  <circle cx="8" cy="4" r="1.5" />
                  <circle cx="8" cy="8" r="1.5" />
                  <circle cx="8" cy="12" r="1.5" />
                </svg>
              </div>
              <h3 className={styles.title}>{title}</h3>
            </div>

            <div className={styles.headerRight}>
              <button
                className={styles.minimizeButton}
                onClick={toggleMinimize}
                aria-label={
                  isMinimized ? tr("charts.maximize") : tr("charts.minimize")
                }
                title={
                  isMinimized ? tr("charts.maximize") : tr("charts.minimize")
                }
              >
                {isMinimized ? (
                  <svg
                    width="16"
                    height="16"
                    viewBox="0 0 16 16"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="2"
                  >
                    <polyline points="4 9 8 5 12 9" />
                  </svg>
                ) : (
                  <svg
                    width="16"
                    height="16"
                    viewBox="0 0 16 16"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="2"
                  >
                    <line x1="2" y1="8" x2="14" y2="8" />
                  </svg>
                )}
              </button>

              <button
                className={styles.closeButton}
                onClick={onClose}
                aria-label={tr("charts.closeMiniPlayer")}
                title={tr("charts.closeMiniPlayerEsc")}
              >
                <svg
                  width="16"
                  height="16"
                  viewBox="0 0 16 16"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth="2"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                >
                  <line x1="12" y1="4" x2="4" y2="12" />
                  <line x1="4" y1="4" x2="12" y2="12" />
                </svg>
              </button>
            </div>
          </div>

          {!isMinimized && <div className={styles.content}>{children}</div>}
        </div>
      </Theme>
    </Rnd>,
    document.body,
  );
};

