const getHeaders = (tr: any) => [
  { key: "token", header: tr("marketPage.token") },
  { key: "price", header: tr("marketPage.price") },
  { key: "change24h", header: tr("marketPage.change24h") },
  { key: "volume24h", header: tr("marketPage.volume24h") },
  { key: "marketCap", header: tr("marketPage.marketCap") },
  { key: "supply", header: tr("token.marketStats.circSupply") },
];

export const TokenPerformanceTable: React.FC<TokenPerformanceTableProps> = ({
  onTokenSelect,
  selectedTokenAddress,
}) => {
  const { tr, fmt } = useLocalization();
  const [tokens, setTokens] = useState<TokenPerformance[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const headers = getHeaders(tr);

  // Handle row click
  const handleRowClick = (tokenId: string) => {
    const token = tokens.find((t) => t.id === tokenId);
    if (token && onTokenSelect) {
      onTokenSelect(token);
    }
  };

  useEffect(() => {
    async function fetchTokenData() {
      try {
        setLoading(true);
        setError(null);

        const apiDomain =
          import.meta.env.VITE_CLIENT_API_DOMAIN || window.location.origin;

        // Batch tokens into smaller chunks to avoid API issues
        const BATCH_SIZE = 10;
        const batches: string[][] = [];
        for (let i = 0; i < SOLANA_TOKEN_ADDRESSES.length; i += BATCH_SIZE) {
          batches.push(SOLANA_TOKEN_ADDRESSES.slice(i, i + BATCH_SIZE));
        }

        const allMarketData: TokenMarketDataItem[] = [];
        const allMetaData: TokenMetaDataItem[] = [];

        // Fetch each batch separately with error handling per batch
        for (const batch of batches) {
          const addressesParam = batch.join(",");

          try {
            // Fetch market data and meta data in parallel for this batch
            const [marketResp, metaResp] = await Promise.all([
              fetch(`${apiDomain}/api/tokens/markets/${addressesParam}`),
              fetch(`${apiDomain}/api/tokens/meta/${addressesParam}`),
            ]);

            // Process market data if successful
            if (marketResp.ok) {
              const marketData = (await marketResp.json()) as MarketData;
              if (Array.isArray(marketData)) {
                allMarketData.push(...marketData);
              }
            } else {
              console.warn(
                `Failed to fetch market data for batch: ${batch.join(",").substring(0, 50)}...`,
              );
            }

            // Process meta data if successful
            if (metaResp.ok) {
              const metaData = (await metaResp.json()) as MetaData;
              if (Array.isArray(metaData)) {
                allMetaData.push(...metaData);
              }
            } else {
              console.warn(
                `Failed to fetch meta data for batch: ${batch.join(",").substring(0, 50)}...`,
              );
            }
          } catch (batchError) {
            // Log but continue with other batches
            console.warn(
              `Error fetching batch: ${batch.join(",").substring(0, 50)}...`,
              batchError,
            );
          }
        }

        // If no market data was fetched at all, show error
        if (allMarketData.length === 0) {
          setError(tr("ERROR.FAILED_TO_FETCH_REQUESTED_DATA"));
          setLoading(false);
          return;
        }

        // Create a lookup map for meta data by address
        const metaLookup = new Map(allMetaData.map((m) => [m.address, m]));

        // Combine market and meta data, filtering out invalid entries
        const combinedTokens: TokenPerformance[] = allMarketData
          .filter(
            (market) => market && market.address && market.priceUsd != null,
          )
          .map((market, index) => {
            const meta = metaLookup.get(market.address);
            return {
              id: String(index + 1),
              address: market.address,
              token: meta?.name || "Unknown",
              symbol: meta?.symbol?.toUpperCase() || "???",
              imageUrl: meta?.imageUrl || null,
              price: Number(market.priceUsd) || 0,
              change24h: Number(market.priceChangePercentage24h || 0),
              volume24h: Number(market.volume24h) || 0,
              marketCap: Number(market.marketCap) || 0,
              supply: Number(market.circulatingSupply) || 0,
              totalSupply: Number(market.totalSupply) || 0,
              ath: Number(market.ath) || 0,
              athChangePercentage: Number(market.athChangePercentage) || 0,
              atl: Number(market.atl) || 0,
              atlChangePercentage: Number(market.atlChangePercentage) || 0,
            };
          })
          // Sort by market cap descending
          .sort((a, b) => b.marketCap - a.marketCap);

        setTokens(combinedTokens);

        // Show partial success message if some tokens were skipped
        if (combinedTokens.length < SOLANA_TOKEN_ADDRESSES.length) {
          console.info(
            `Loaded ${combinedTokens.length} of ${SOLANA_TOKEN_ADDRESSES.length} tokens`,
          );
        }
      } catch (err) {
        console.error("Failed to fetch token data:", err);
        setError(tr("ERROR.FAILED_TO_FETCH_REQUESTED_DATA"));
      } finally {
        setLoading(false);
      }
    }

    fetchTokenData();
  }, []);

  // Removed local formatNumber

  const formatSupply = (num: number, symbol: string) => {
    if (num >= 1e12) return `${(num / 1e12).toFixed(2)}T ${symbol}`;
    if (num >= 1e9) return `${(num / 1e9).toFixed(2)}B ${symbol}`;
    if (num >= 1e6) return `${(num / 1e6).toFixed(2)}M ${symbol}`;
    return `${fmt.num.decimal(num)} ${symbol}`;
  };

  const rows = tokens.map((token) => ({
    id: token.id,
    token: (
      <div className={styles.tokenCell}>
        {token.imageUrl && (
          <img
            src={token.imageUrl}
            alt={token.token}
            className={styles.tokenImage}
            width={24}
            height={24}
          />
        )}
        <div className={styles.tokenInfo}>
          <span className={styles.tokenName}>{token.token}</span>
          <span className={styles.tokenSymbol}>{token.symbol}</span>
        </div>
      </div>
    ),
    price: fmt.num.currency(token.price),
    change24h: (
      <span
        className={token.change24h >= 0 ? styles.positive : styles.negative}
      >
        {token.change24h >= 0 ? <ArrowUp size={16} /> : <ArrowDown size={16} />}
        {Math.abs(token.change24h).toFixed(2)}%
      </span>
    ),
    volume24h: fmt.num.compact.currency(token.volume24h),
    marketCap: fmt.num.compact.currency(token.marketCap),
    supply: formatSupply(token.supply, token.symbol),
  }));
  /**
   * Handle export functionality
   */
  const handleExport = async (format: ExportFormat) => {
    if (format === "csv") {
      // Export as CSV
      const csvHeaders = headers.map((h) => h.header).join(",");
      const csvRows = tokens.map((token) =>
        [
          token.token,
          token.symbol,
          token.price.toFixed(6),
          token.change24h.toFixed(2),
          token.volume24h.toString(),
          token.marketCap.toString(),
          token.supply.toString(),
        ].join(","),
      );
      const csvContent = [csvHeaders, ...csvRows].join("\n");

      const blob = new Blob([csvContent], { type: "text/csv" });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = `token-performance-${Date.now()}.csv`;
      link.click();
      URL.revokeObjectURL(url);
    }
  };
  if (loading) {
    return (
      <TableWrapper
        title={tr("marketPage.tokenPerformanceTitle")}
        onExport={handleExport}
        isEmpty={true}
      >
        <div className={styles.loadingState}>{tr("common.loading")}</div>
      </TableWrapper>
    );
  }

  if (error) {
    return (
      <TableWrapper
        title={tr("marketPage.tokenPerformanceTitle")}
        onExport={handleExport}
        isEmpty={true}
      >
        <div className={styles.errorState}>{error}</div>
      </TableWrapper>
    );
  }

  return (
    <TableWrapper
      title={tr("marketPage.tokenPerformanceTitle")}
      onExport={handleExport}
      isEmpty={tokens.length === 0}
    >
      <div className={styles.tokenPerformanceTable}>
        <DataTable rows={rows} headers={headers}>
          {({ rows, headers, getTableProps, getHeaderProps, getRowProps }) => (
            <Table {...getTableProps()}>
              <TableHead>
                <TableRow>
                  {headers.map((header) => {
                    const { key, ...headerProps } = getHeaderProps({ header });
                    return (
                      <TableHeader key={key} {...headerProps}>
                        {header.header}
                      </TableHeader>
                    );
                  })}
                </TableRow>
              </TableHead>
              <TableBody>
                {rows.map((row) => {
                  const { key, ...rowProps } = getRowProps({ row });
                  const token = tokens.find((t) => t.id === row.id);
                  const isSelected = token?.address === selectedTokenAddress;
                  return (
                    <TableRow
                      key={key}
                      {...rowProps}
                      className={`${styles.clickableRow} ${isSelected ? styles.selectedRow : ""}`}
                      onClick={() => handleRowClick(row.id)}
                    >
                      {row.cells.map((cell) => (
                        <TableCell key={cell.id}>{cell.value}</TableCell>
                      ))}
                    </TableRow>
                  );
                })}
              </TableBody>
            </Table>
          )}
        </DataTable>
      </div>
    </TableWrapper>
  );
};

/**
 * TokenPriceHistoryChart Component
 *
 * Displays price history chart for a single token using real API data.
 * Features time period selection similar to CoinGecko.
 */

import React, { useEffect, useState, useMemo, useRef } from 'react';
import ReactECharts from 'echarts-for-react';
import type { EChartsOption } from 'echarts';
import { Tile, SkeletonPlaceholder, Button } from '@carbon/react';
import { Maximize, Save, Download } from '@carbon/icons-react';
import styles from './TokenPriceHistoryChart.module.scss';

interface ChartDataPoint {
  address: string | null;
  unixTimestampMs: number;
  price: number;
  marketCap: number;
  totalVolume: number;
}

type TimePeriod = '30m' | '1h' | '24h' | '7d' | '30d';

interface TokenPriceHistoryChartProps {
  /** Token address to fetch data for */
  tokenAddress?: string | null;
  /** Token symbol for display */
  tokenSymbol?: string;
  /** Chart height in pixels */
  height?: number;
}

const TIME_PERIODS: { value: TimePeriod; label: string }[] = [
  { value: '30m', label: '30 min' },
  { value: '1h', label: '1h' },
  { value: '24h', label: '24h' },
  { value: '7d', label: '7 days' },
  { value: '30d', label: '30 days' },
];

export const TokenPriceHistoryChart: React.FC<TokenPriceHistoryChartProps> = ({
  tokenAddress,
  tokenSymbol = 'Token',
  height = 400,
}) => {
  const [chartData, setChartData] = useState<ChartDataPoint[]>([]);
  const [selectedPeriod, setSelectedPeriod] = useState<TimePeriod>('24h');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const chartRef = useRef<ReactECharts>(null);

  // Fetch chart data when token or period changes
  useEffect(() => {
    if (!tokenAddress) {
      setChartData([]);
      return;
    }

    const fetchChartData = async () => {
      setLoading(true);
      setError(null);

      try {
        const apiDomain = import.meta.env.VITE_CLIENT_API_DOMAIN || window.location.origin;
        const response = await fetch(
          `${apiDomain}/api/tokens/markets/chart/${tokenAddress}?period=${selectedPeriod}`
        );

        if (!response.ok) {
          throw new Error('Failed to fetch chart data');
        }

        const data = await response.json();
        setChartData(data);
      } catch (err) {
        console.error('Failed to fetch chart data:', err);
        setError('Failed to load price history');
      } finally {
        setLoading(false);
      }
    };

    fetchChartData();
  }, [tokenAddress, selectedPeriod]);

  // Handle period change
  const handlePeriodChange = (period: TimePeriod) => {
    setSelectedPeriod(period);
  };

  // Format currency for display
  const formatCurrency = (value: number) => {
    if (value < 0.01) return `$${value.toFixed(6)}`;
    if (value < 1) return `$${value.toFixed(4)}`;
    if (value >= 1e9) return `$${(value / 1e9).toFixed(2)}B`;
    if (value >= 1e6) return `$${(value / 1e6).toFixed(2)}M`;
    if (value >= 1e3) return `$${(value / 1e3).toFixed(2)}K`;
    return `$${value.toFixed(2)}`;
  };

  // Generate ECharts options
  const chartOptions: EChartsOption = useMemo(() => {
    if (chartData.length === 0) {
      return {};
    }

    const sortedData = [...chartData].sort((a, b) => a.unixTimestampMs - b.unixTimestampMs);
    const prices = sortedData.map(d => d.price);
    const minPrice = Math.min(...prices);
    const maxPrice = Math.max(...prices);
    const priceRange = maxPrice - minPrice;

    return {
      grid: {
        left: 60,
        right: 20,
        top: 20,
        bottom: 60,
        containLabel: false,
      },
      tooltip: {
        trigger: 'axis',
        backgroundColor: 'rgba(0, 0, 0, 0.8)',
        borderColor: 'transparent',
        textStyle: {
          color: '#fff',
        },
        formatter: (params: any) => {
          if (!Array.isArray(params) || params.length === 0) return '';
          const point = params[0];
          const date = new Date(point.data[0]);
          const dateStr = selectedPeriod === '30m' || selectedPeriod === '1h'
            ? date.toLocaleTimeString()
            : date.toLocaleDateString() + ' ' + date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
          return `
            <div style="padding: 8px;">
              <div style="margin-bottom: 4px; font-weight: bold;">${tokenSymbol}</div>
              <div style="color: #888; margin-bottom: 4px;">${dateStr}</div>
              <div style="font-size: 16px; font-weight: bold;">${formatCurrency(point.data[1])}</div>
            </div>
          `;
        },
      },
      xAxis: {
        type: 'time',
        axisLine: {
          lineStyle: {
            color: '#444',
          },
        },
        axisLabel: {
          color: '#888',
          formatter: (value: number) => {
            const date = new Date(value);
            if (selectedPeriod === '30m' || selectedPeriod === '1h') {
              return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
            }
            if (selectedPeriod === '24h') {
              return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
            }
            return date.toLocaleDateString([], { month: 'short', day: 'numeric' });
          },
        },
        splitLine: {
          show: false,
        },
      },
      yAxis: {
        type: 'value',
        min: minPrice - priceRange * 0.1,
        max: maxPrice + priceRange * 0.1,
        axisLine: {
          show: false,
        },
        axisLabel: {
          color: '#888',
          formatter: (value: number) => formatCurrency(value),
        },
        splitLine: {
          lineStyle: {
            color: '#333',
            type: 'dashed',
          },
        },
      },
      series: [
        {
          name: tokenSymbol,
          type: 'line',
          data: sortedData.map(d => [d.unixTimestampMs, d.price]),
          smooth: true,
          symbol: 'none',
          lineStyle: {
            width: 2,
            color: '#4589ff',
          },
          areaStyle: {
            color: {
              type: 'linear',
              x: 0,
              y: 0,
              x2: 0,
              y2: 1,
              colorStops: [
                { offset: 0, color: 'rgba(69, 137, 255, 0.3)' },
                { offset: 1, color: 'rgba(69, 137, 255, 0.05)' },
              ],
            },
          },
        },
      ],
      dataZoom: [
        {
          type: 'inside',
          xAxisIndex: 0,
          start: 0,
          end: 100,
        },
      ],
    };
  }, [chartData, tokenSymbol, selectedPeriod]);

  // Handle export as PNG
  const handleExport = () => {
    const echartsInstance = chartRef.current?.getEchartsInstance();
    if (echartsInstance) {
      const url = echartsInstance.getDataURL({
        type: 'png',
        pixelRatio: 2,
        backgroundColor: '#1a1a1a',
      });
      const link = document.createElement('a');
      link.href = url;
      link.download = `${tokenSymbol}-price-history-${selectedPeriod}.png`;
      link.click();
    }
  };

  // Empty state
  if (!tokenAddress) {
    return (
      <Tile className={styles.chartContainer}>
        <div className={styles.header}>
          <h3 className={styles.title}>Price History</h3>
        </div>
        <div className={styles.emptyState} style={{ height }}>
          <p>Select a token to view price history</p>
        </div>
      </Tile>
    );
  }

  // Loading state
  if (loading && chartData.length === 0) {
    return (
      <Tile className={styles.chartContainer}>
        <div className={styles.header}>
          <h3 className={styles.title}>Price History</h3>
        </div>
        <SkeletonPlaceholder style={{ height, width: '100%' }} />
      </Tile>
    );
  }

  return (
    <Tile className={styles.chartContainer}>
      <div className={styles.header}>
        <h3 className={styles.title}>Price History</h3>
        <div className={styles.actions}>
          <Button
            kind="ghost"
            size="sm"
            hasIconOnly
            iconDescription="Fullscreen"
            renderIcon={Maximize}
          />
          <Button
            kind="ghost"
            size="sm"
            hasIconOnly
            iconDescription="Save"
            renderIcon={Save}
          />
          <Button
            kind="ghost"
            size="sm"
            hasIconOnly
            iconDescription="Export"
            renderIcon={Download}
            onClick={handleExport}
          />
        </div>
      </div>

      <div className={styles.timePeriodSelector}>
        {TIME_PERIODS.map(period => (
          <button
            key={period.value}
            type="button"
            className={`${styles.periodButton} ${selectedPeriod === period.value ? styles.active : ''}`}
            onClick={() => handlePeriodChange(period.value)}
          >
            {period.label}
          </button>
        ))}
      </div>

      {error ? (
        <div className={styles.errorState} style={{ height }}>
          <p>{error}</p>
        </div>
      ) : chartData.length === 0 ? (
        <div className={styles.emptyState} style={{ height }}>
          <p>No price data available for this period</p>
        </div>
      ) : (
        <ReactECharts
          ref={chartRef}
          option={chartOptions}
          style={{ height, width: '100%' }}
          opts={{ renderer: 'canvas' }}
          notMerge={true}
        />
      )}
    </Tile>
  );
};

import { PaymentElement, useElements, useStripe } from "@stripe/react-stripe-js";
import { useState } from "react";
import { Building2, CreditCard, Wallet } from "lucide-react";
import client from "@/api/main";
import { useLocalization } from "@/contexts/LocalizationContext";
import { SolanaPaymentFlow } from "./SolanaPaymentFlow";

type CheckoutFormProps = {
  tierName: string;
  tierPrice: string;
  tierKey: "Lite" | "Plus" | "Pro";
  activeMethod: PaymentMethod;
  onMethodChange: (method: PaymentMethod) => void;
  onSuccess: () => void;
  onCancel: () => void;
};

type PaymentMethod = "card" | "bank" | "solana";

/**
 * Dual-payment checkout form supporting:
 *  1. Stripe (Card + Bank Transfer)
 *  2. Solana Devnet Wallet (Phantom/Solflare)
 *
 * Stripe Flow:
 *  1. User fills card → clicks "Subscribe"
 *  2. stripe.confirmSetup() — saves the card as a PaymentMethod on the customer
 *  3. We receive the confirmed paymentMethodId (pm_xxx)
 *  4. POST /api/payment/activate-subscription → backend creates the subscription
 *
 * Solana Flow:
 *  1. User selects Solana and connects wallet
 *  2. Constructs SystemProgram.transfer transaction
 *  3. User signs and sends transaction
 *  4. Frontend captures txId and sends to POST /api/payments/verify-solana
 *  5. Backend verifies transaction and creates subscription
 */
export function CheckoutForm({
  tierName,
  tierPrice,
  tierKey,
  activeMethod,
  onMethodChange,
  onSuccess,
  onCancel,
}: CheckoutFormProps) {
  const { tr } = useLocalization();
  const stripe = useStripe();
  const elements = useElements();
  const [isProcessing, setIsProcessing] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  async function handleStripeSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    if (!stripe || !elements) return;

    setIsProcessing(true);
    setErrorMsg(null);

    try {
      const { error: submitError } = await elements.submit();
      if (submitError) {
        setErrorMsg(submitError.message ?? tr("payment.errors.cardSetupFailed"));
        setIsProcessing(false);
        return;
      }

      // Step 1: Create the SetupIntent on the backend with the selected paymentMethodTypes
      // This ensures Stripe only includes the method the user selected
      const setupResp = await client.api.payment["setup-intent"].$post({
        json: { 
          tier: tierKey,
          paymentMethod: activeMethod === "bank" ? "us_bank_account" : "card",
        },
      });

      if (!setupResp.ok) {
        const body = await setupResp.json() as any;
        setErrorMsg(body.message ?? tr("payment.errors.createIntent"));
        setIsProcessing(false);
        return;
      }

      const setupData = await setupResp.json() as any;
      const clientSecret = setupData.clientSecret;

      if (!clientSecret) {
        setErrorMsg(tr("payment.errors.setupFailed"));
        setIsProcessing(false);
        return;
      }

      // Step 2: Confirm the SetupIntent with Stripe
      const { error, setupIntent } = await stripe.confirmSetup({
        elements,
        clientSecret,
        redirect: "if_required",
        confirmParams: {
          return_url: `${window.location.origin}/pricing?setup=complete`,
        },
      });

      if (error) {
        setErrorMsg(error.message ?? tr("payment.errors.cardSetupFailed"));
        setIsProcessing(false);
        return;
      }

      if (!setupIntent || setupIntent.status !== "succeeded") {
        setErrorMsg(tr("payment.errors.cardSetupIncomplete"));
        setIsProcessing(false);
        return;
      }

      // Step 3: Extract the paymentMethodId from the confirmed SetupIntent
      const paymentMethodId =
        typeof setupIntent.payment_method === "string"
          ? setupIntent.payment_method
          : (setupIntent.payment_method as any)?.id;

      if (!paymentMethodId) {
        setErrorMsg(tr("payment.errors.missingPaymentMethod"));
        setIsProcessing(false);
        return;
      }

      // Step 4: Ask the backend to create the subscription with this payment method
      const activateResp = await client.api.payment["activate-subscription"].$post({
        json: { paymentMethodId, tier: tierKey },
      });

      const body = await activateResp.json() as any;

      if (!activateResp.ok) {
        setErrorMsg(body.message ?? tr("payment.errors.activateSubscription"));
        setIsProcessing(false);
        return;
      }

      console.log("[CheckoutForm] Subscription activated:", body.subscriptionId, "Status:", body.status);
      onSuccess();
    } catch (networkErr) {
      console.error("[CheckoutForm] Network error:", networkErr);
      setErrorMsg(tr("payment.errors.network"));
      setIsProcessing(false);
    }
  }

  return (
    <div className="flex flex-col gap-6">
      {/* Order Summary */}
      <div className="flex items-center justify-between !rounded-3xl border border-white/10 bg-white/[0.04] !p-5 shadow-inner">
