          {/* Candlestick icon */}
          <button
            className={`${styles.chartTypeBtn} ${mode === "candle" ? styles.chartTypeBtnActive : ""}`}
            onClick={() => { setMode("candle"); setIsDropdownOpen(false); }}
            title={tr("token.overviewChart.candle")}
            aria-pressed={mode === "candle"}
          >
            <svg width="18" height="18" viewBox="0 0 18 18" fill="none" aria-hidden="true">
              {/* Candle 1 - bullish */}
              <line x1="5" y1="2" x2="5" y2="5" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/>
              <rect x="3.5" y="5" width="3" height="5" rx="0.5" fill="currentColor" opacity="0.9"/>
              <line x1="5" y1="10" x2="5" y2="13" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/>
              {/* Candle 2 - bearish */}
              <line x1="10" y1="3" x2="10" y2="6" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/>
              <rect x="8.5" y="6" width="3" height="6" rx="0.5" fill="currentColor" opacity="0.5"/>
              <line x1="10" y1="12" x2="10" y2="15" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/>
              {/* Candle 3 - bullish */}
              <line x1="15" y1="4" x2="15" y2="7" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/>
              <rect x="13.5" y="7" width="3" height="4" rx="0.5" fill="currentColor" opacity="0.9"/>
              <line x1="15" y1="11" x2="15" y2="14" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/>
            </svg>
          </button>
        </div>
      </div>
      </div>
      {/* End Toolbar */}

      {/* Chart */}
      <div className={mode === "candle" ? styles.candleWrapper : styles.chartWrapper}>
        {mode === "candle" ? (
          topPools.isLoading ? (
            <div className={styles.loading}>{tr("common.loading")}</div>
          ) : !topPoolAddress ? (
            <div className={styles.empty}>
              {tr("token.overviewChart.noCandlePool")}
            </div>
          ) : (
            <GeckoTerminalChart poolAddress={topPoolAddress} height="560" />
          )
        ) : loading && seriesData.length === 0 ? (
          <div className={styles.loading}>{tr("common.loading")}</div>
        ) : seriesData.length === 0 ? (
          <div className={styles.empty}>
            {tr("token.overviewChart.noData")}
            {!address ? "" : ` - ${tr("token.overviewChart.noCoingeckoId")}`}
          </div>
        ) : (
          <ReactECharts
            ref={chartRef}
            option={option}
            notMerge
            onEvents={chartEvents}
            style={{ height: "100%", width: "100%" }}
            opts={{ renderer: "canvas" }}
            showLoading={loading}
            loadingOption={{ color, maskColor: "rgba(0,0,0,0.4)" }}
          />
        )}

        {selectedNewsEvent && (
          <div className={styles.newsPopup}>
            <div className={styles.newsPopupHeader}>
              <div>
                <div className={styles.newsPopupEyebrow}>News marker</div>
                <div className={styles.newsPopupTitle}>
                  {formatEventDate(selectedNewsEvent.timestamp)}
                </div>
              </div>
              <button
                type="button"
                className={styles.newsPopupClose}
                onClick={() => setSelectedNewsEvent(null)}
                aria-label="Close news marker"
              >
                x
              </button>
            </div>

            <div className={styles.newsPopupMeta}>
              {selectedNewsEvent.articleCount} article
              {selectedNewsEvent.articleCount === 1 ? "" : "s"} on this date
            </div>

            <div className={styles.newsSummary}>
              {newsSummaryLoading && !selectedNewsEvent.summary ? (
                <div className={styles.newsSummaryLoading}>
                  Loading summary...
                </div>
              ) : newsSummaryError ? (
                <div className={styles.newsSummaryLoading}>
                  {newsSummaryError}
                  {newsSummaryUpgradePath && (
                    <>
                      {" "}
                      <a href={newsSummaryUpgradePath}>Upgrade plan</a>
                    </>
                  )}
                </div>
              ) : selectedNewsEvent.summary ? (
                <>
                  <div className={styles.newsSummaryTitle}>
                    {selectedNewsEvent.summary.headline}
                  </div>
                  <ul className={styles.newsSummaryBullets}>
                    {selectedNewsEvent.summary.bullets.map((bullet) => (
                      <li key={bullet}>{bullet}</li>
                    ))}
                  </ul>
                  {selectedNewsEvent.summary.provider && (
                    <div className={styles.newsSummaryProvider}>
                      Summary: {selectedNewsEvent.summary.provider}
                    </div>
                  )}
                  {newsSummaryUsage && !newsSummaryUsage.disabled && (
                    <div className={styles.newsSummaryProvider}>
                      {newsSummaryUsage.remaining}/{newsSummaryUsage.limit} summaries left today
                    </div>
                  )}
                </>
              ) : (
                <div className={styles.newsSummaryLoading}>
                  Summary unavailable.
                </div>
              )}
            </div>

            <div className={styles.newsArticleList}>
              {selectedNewsEvent.articles.map((article) => (
                <a
                  key={article.url}
                  className={styles.newsArticle}
                  href={article.url}
                  target="_blank"
                  rel="noreferrer"
                >
                  <div className={styles.newsArticleThumbnail}>
                    {article.imageUrl || article.favicon ? (
                      <img
                        src={article.imageUrl || article.favicon || undefined}
                        alt=""
                        loading="lazy"
                        onError={(event) => {
                          event.currentTarget.style.display = "none";
                        }}
                      />
                    ) : (
                      <span aria-hidden="true">
                        {article.source.trim().slice(0, 1).toUpperCase() ||
                          "N"}
                      </span>
                    )}
                  </div>
                  <div className={styles.newsArticleContent}>
                    <div className={styles.newsArticleTitle}>
                      {article.title}
                    </div>
                    <div className={styles.newsArticleMeta}>
                      {article.source}
                      {article.publishedAt
                        ? ` | ${formatArticleDate(article.publishedAt)}`
                        : ""}
                    </div>
                    {article.description && (
                      <div className={styles.newsArticleDescription}>
                        {article.description}
                      </div>
                    )}
                  </div>
                </a>
              ))}
            </div>
          </div>
        )}
      </div>

        {!loading && seriesData.length > 0 && (
        <div className={styles.newsMarkerStatus}>
          {newsLoading
            ? "Loading news markers..."
            : newsError
              ? newsError
              : newsEvents.length === 0
                ? "No news markers for this timeframe."
                : `${newsEvents.length} news marker${newsEvents.length === 1 ? "" : "s"} detected in this timeframe.`}
        </div>
      )}
    </div>
  );
}

import React from "react";
import ReactECharts from "echarts-for-react";
import { useUserTheme } from "@/contexts/ThemeContext";

// ─── Types ────────────────────────────────────────────────────────────────────

export interface UnlockEvent {
  unlock_date: number;
  tokens_to_unlock: number;
  allocation_details: Record<string, number>;
}

interface TokenUnlockScheduleProps {
  symbol: string;
  schedule: UnlockEvent[];
}

// ─── Color palette ────────────────────────────────────────────────────────────

const COLORS = [
  "#7C3AED", "#2563EB", "#2DD4BF", "#22C55E",
  "#F59E0B", "#EC4899", "#8B5CF6", "#38BDF8",
  "#A855F7", "#14B8A6", "#F472B6", "#C084FC",
];

// ─── Build categories + cumulative data ──────────────────────────────────────

function buildChartData(schedule: UnlockEvent[]) {
  const categorySet = new Set<string>();
  schedule.forEach((ev) => Object.keys(ev.allocation_details).forEach((k) => categorySet.add(k)));
  const categories = Array.from(categorySet);

  const sorted = [...schedule].sort((a, b) => a.unlock_date - b.unlock_date);
  const cumulative: Record<string, number> = {};
  categories.forEach((c) => (cumulative[c] = 0));

  const dates: string[] = [];
  const seriesData: Record<string, number[]> = {};
  categories.forEach((c) => (seriesData[c] = []));

  sorted.forEach((ev) => {
    const d = new Date(ev.unlock_date);
    const label = `${d.getFullYear()}/${String(d.getMonth() + 1).padStart(2, "0")}`;
    dates.push(label);
    categories.forEach((cat) => {
      cumulative[cat] += ev.allocation_details[cat] ?? 0;
      seriesData[cat].push(Math.round(cumulative[cat]));
    });
  });

  const uniqueDates: string[] = [];
  const deduped: Record<string, number[]> = {};
  categories.forEach((c) => (deduped[c] = []));
  dates.forEach((d, i) => {
    if (i === 0 || d !== dates[i - 1]) {
      uniqueDates.push(d);
      categories.forEach((c) => deduped[c].push(seriesData[c][i]));
    } else {
      const last = uniqueDates.length - 1;
      categories.forEach((c) => { deduped[c][last] = Math.max(deduped[c][last], seriesData[c][i]); });
    }
  });

  return { categories, uniqueDates, deduped };
}

// ─── Locate "now" on the category axis (fractional index, interpolated by month) ──

function getNowXAxisIndex(uniqueDates: string[]): number | null {
  if (uniqueDates.length === 0) return null;

  const toMonthIndex = (label: string) => {
    const [year, month] = label.split("/").map(Number);
    return year * 12 + (month - 1);
  };

  const now = new Date();
  const nowMonths = now.getFullYear() * 12 + now.getMonth();
  const monthIndices = uniqueDates.map(toMonthIndex);

  if (nowMonths <= monthIndices[0]) return 0;
  if (nowMonths >= monthIndices[monthIndices.length - 1]) {
    return monthIndices.length - 1;
  }

  for (let i = 0; i < monthIndices.length - 1; i += 1) {
    if (nowMonths >= monthIndices[i] && nowMonths <= monthIndices[i + 1]) {
      const span = monthIndices[i + 1] - monthIndices[i];
      if (span === 0) return i;
      return i + (nowMonths - monthIndices[i]) / span;
    }
  }

  return monthIndices.length - 1;
}

// ─── Build ECharts option (no legend — we use custom HTML legend) ─────────────

function buildChartOption(
  categories: string[],
  uniqueDates: string[],
  deduped: Record<string, number[]>,
  isDark: boolean,
): any {
  const textColor = isDark ? "#CBD5E1" : "#475569";
  const gridColor = isDark
    ? "rgba(148,163,184,0.12)"
    : "rgba(148,163,184,0.18)";
  const tooltipBg = isDark ? "rgba(11,16,32,0.96)" : "#ffffff";
  const tooltipBorder = isDark ? "rgba(148,163,184,0.16)" : "rgba(148,163,184,0.24)";

  return {
    color: COLORS,
    legend: { show: false }, // hidden — we render custom HTML legend
    tooltip: {
      trigger: "axis",
      backgroundColor: tooltipBg,
      borderColor: tooltipBorder,
      borderWidth: 1,
      padding: [12, 16],
      textStyle: { color: isDark ? "#e0e0e0" : "#161616", fontSize: 12 },
      formatter: (params: any) => {
        if (!Array.isArray(params) || params.length === 0) return "";
        const date = params[0].axisValue;
        const total = (params as any[]).reduce((s: number, p: any) => s + (p.value || 0), 0);
        const rows = (params as any[])
          .filter((p) => p.value > 0)
          .sort((a, b) => b.value - a.value)
          .map((p) =>
            `<div style="display:flex;justify-content:space-between;gap:24px;margin:2px 0">` +
            `<span><span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${p.color};margin-right:6px"></span>${p.seriesName}</span>` +
            `<span style="font-weight:600">${(p.value / 1e6).toFixed(2)}M</span></div>`,
          ).join("");
        return (
          `<div style="font-weight:700;margin-bottom:8px">${date}</div>` +
          rows +
          `<div style="border-top:1px solid ${tooltipBorder};margin-top:8px;padding-top:6px;display:flex;justify-content:space-between">` +
          `<span>Total</span><span style="font-weight:700">${(total / 1e6).toFixed(2)}M</span></div>`
        );
      },
    },
    grid: { top: 24, left: 56, right: 24, bottom: 32 },
    xAxis: {
      type: "category",
      data: uniqueDates,
      axisLine: { lineStyle: { color: gridColor } },
      axisLabel: {
        color: textColor,
        fontSize: 11,
        interval: Math.floor(uniqueDates.length / 6),
        formatter: (val: string) => val.split("/")[0],
      },
      axisTick: { show: false },
    },
    yAxis: {
      type: "value",
      axisLabel: {
        color: textColor,
        fontSize: 11,
        formatter: (v: number) =>
          v >= 1e9 ? `${(v / 1e9).toFixed(1)}B`
          : v >= 1e6 ? `${(v / 1e6).toFixed(0)}M`
          : v >= 1e3 ? `${(v / 1e3).toFixed(0)}K`
          : String(v),
      },
      splitLine: { lineStyle: { color: gridColor } },
    },
    series: categories.map((cat, i) => {
      const isLast = i === categories.length - 1;
      const nowIndex = isLast ? getNowXAxisIndex(uniqueDates) : null;
      return {
        name: cat, type: "line", stack: "unlock", smooth: true, symbol: "none",
        lineStyle: { width: 0 }, areaStyle: { opacity: 0.85 },
        itemStyle: { color: COLORS[i % COLORS.length] },
        data: deduped[cat],
        ...(nowIndex != null && {
          markLine: {
            silent: true,
            symbol: "none",
            lineStyle: {
              color: isDark ? "#FBBF24" : "#D97706",
              type: "dashed",
              width: 1.5,
            },
            label: {
              show: true,
              formatter: "Now",
              position: "insideEndTop",
              color: isDark ? "#FBBF24" : "#D97706",
              fontSize: 10,
              fontWeight: 700,
            },
            data: [{ xAxis: nowIndex }],
          },
        }),
      };
    }),
  };
}

// ─── Upcoming unlocks list ────────────────────────────────────────────────────

function UpcomingList({ schedule, isDark }: { schedule: UnlockEvent[]; isDark: boolean }) {
  const now = Date.now();
  const upcoming = schedule
    .filter((ev) => ev.unlock_date >= now)
    .sort((a, b) => a.unlock_date - b.unlock_date)
    .slice(0, 5);

  if (upcoming.length === 0) {
    return <p style={{ color: "var(--yoca-text-muted)", fontSize: "0.875rem", marginTop: "0.5rem" }}>No upcoming unlock events found.</p>;
  }

  const borderColor = "var(--yoca-border)";
  const chipBackground = isDark ? "rgba(255,255,255,0.05)" : "rgba(255,255,255,0.04)";

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "0.5rem", marginTop: "0.75rem" }}>
      {upcoming.map((ev, i) => {
        const date = new Date(ev.unlock_date);
        const daysLeft = Math.ceil((ev.unlock_date - now) / (1000 * 60 * 60 * 24));
        const cats = Object.entries(ev.allocation_details).sort((a, b) => b[1] - a[1]);
        return (
          <div key={i} style={{ border: `1px solid ${borderColor}`, borderRadius: "14px", padding: "0.875rem 1rem", background: "rgba(255,255,255,0.03)", display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: "1rem" }}>
            <div style={{ flex: 1 }}>
              <div style={{ fontWeight: 700, fontSize: "0.9rem", color: "var(--yoca-text-main)", marginBottom: "0.25rem" }}>
                {date.toLocaleDateString("en-US", { year: "numeric", month: "short", day: "numeric" })}
                <span style={{ marginLeft: "0.5rem", fontSize: "0.75rem", fontWeight: 600, color: daysLeft <= 30 ? "var(--yoca-warning)" : "var(--yoca-text-muted)" }}>
                  {daysLeft <= 0 ? "Today" : `in ${daysLeft}d`}
                </span>
              </div>
              <div style={{ display: "flex", flexWrap: "wrap", gap: "0.375rem" }}>
                {cats.map(([cat, amount], ci) => (
                  <span key={ci} style={{ fontSize: "0.75rem", color: "var(--yoca-text-soft)", background: chipBackground, borderRadius: "999px", padding: "2px 8px" }}>
                    <span style={{ display: "inline-block", width: 6, height: 6, borderRadius: "50%", background: COLORS[ci % COLORS.length], marginRight: 5, verticalAlign: "middle" }} />
                    {cat}: {amount >= 1e6 ? `${(amount / 1e6).toFixed(2)}M` : amount >= 1e3 ? `${(amount / 1e3).toFixed(1)}K` : amount.toFixed(0)}
                  </span>
                ))}
              </div>
            </div>
            <div style={{ textAlign: "right", whiteSpace: "nowrap" }}>
              <div style={{ fontWeight: 800, fontSize: "1rem", color: "var(--yoca-text-main)" }}>
                {ev.tokens_to_unlock >= 1e9 ? `${(ev.tokens_to_unlock / 1e9).toFixed(2)}B` : ev.tokens_to_unlock >= 1e6 ? `${(ev.tokens_to_unlock / 1e6).toFixed(2)}M` : ev.tokens_to_unlock >= 1e3 ? `${(ev.tokens_to_unlock / 1e3).toFixed(1)}K` : ev.tokens_to_unlock.toFixed(0)}
              </div>
              <div style={{ fontSize: "0.75rem", color: "var(--yoca-text-muted)" }}>tokens unlock</div>
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ─── Main Component ───────────────────────────────────────────────────────────

export const TokenUnlockSchedule = ({ symbol, schedule }: TokenUnlockScheduleProps) => {
  const { theme } = useUserTheme();
  const isDark = theme === "dark";
  const displaySymbol = symbol?.toUpperCase() ?? "";
  const borderColor = "var(--yoca-border)";

  const { categories, uniqueDates, deduped } = buildChartData(schedule);
  const chartOption = buildChartOption(categories, uniqueDates, deduped, isDark);

  return (
    <div style={{ padding: "0.5rem 0" }}>
      <div style={{ border: `1px solid ${borderColor}`, borderRadius: "14px", padding: "1.5rem", marginBottom: "1.5rem", background: "rgba(255,255,255,0.03)" }}>
        <h3 style={{ fontSize: "1.125rem", fontWeight: 700, marginBottom: "0.25rem", color: "var(--yoca-text-main)" }}>
