import { InlineLoading } from "@carbon/react";
import { Close } from "@carbon/react/icons";
import ReactDOM from "react-dom";
import { useCallback, useEffect, useRef, useState } from "react";
import WalletAnalystPanel from "@/components/WalletAnalystPanel.tsx";
import { ID_MODAL_ROOT } from "@/config/constants";
import { useLocalization } from "@/contexts/LocalizationContext";
import {
  analyzeWalletWithAI,
  type WalletAnalysisApiResponse,
} from "@/services/api/walletAnalysis.tsx";
import styles from "./AiAnalysisModal.module.scss";

interface AiAnalysisModalProps {
  isOpen: boolean;
  onClose: () => void;
  walletAddress: string;
  language: "vi" | "en";
}

export function AiAnalysisModal({
  isOpen,
  onClose,
  walletAddress,
  language,
}: AiAnalysisModalProps) {
  const { tr } = useLocalization();
  const [data, setData] = useState<WalletAnalysisApiResponse | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const requestIdRef = useRef(0);

  const loadData = useCallback(
    async (forceRefresh = false) => {
      if (!walletAddress) return;

      const requestId = ++requestIdRef.current;
      setLoading(true);
      setError(null);

      if (!forceRefresh) {
        setData(null);
      }

      try {
        const result = await analyzeWalletWithAI({
          walletAddress,
          language,
          transactionLimit: 200,
          userLevel: "BEGINNER",
          maxSummaryLength: "SHORT",
        });

        if (requestId === requestIdRef.current) {
          setData(result);
          setLoading(false);
        }
      } catch (err) {
        if (requestId === requestIdRef.current) {
          const message =
            err instanceof Error ? err.message : tr("aiAnalysis.failed");
          setError(message);
          setLoading(false);
        }
      }
    },
    [walletAddress, language],
  );

  useEffect(() => {
    if (isOpen) {
      void loadData();
    } else {
      setData(null);
      setError(null);
      setLoading(false);
    }
  }, [isOpen, loadData]);

  if (!isOpen) return null;

  const modalRoot = document.getElementById(ID_MODAL_ROOT);
  if (!modalRoot) return null;

  return ReactDOM.createPortal(
    <div className={styles.backdrop} onClick={onClose}>
      <div className={styles.card} onClick={(e) => e.stopPropagation()} role="dialog" aria-modal="true" aria-label={tr("aiAnalysis.title")}>
        <div className={styles.header}>
          <span className={styles.title}>{tr("aiAnalysis.title")}</span>
          <button type="button" className={styles.closeBtn} onClick={onClose} aria-label={tr("aiAnalysis.close")}>
            <Close size={20} />
          </button>
        </div>

        {loading && (
          <div className={styles.loadingState}>
            <InlineLoading description={tr("aiAnalysis.analyzing")} />
          </div>
        )}

        {!loading && error && (
          <div className={styles.errorState}>
            <p className={styles.errorMessage}>{error}</p>
            <button type="button" className={styles.retryBtn} onClick={() => void loadData(true)}>
              {tr("aiAnalysis.retry")}
            </button>
          </div>
        )}

        {!loading && !error && data && (
          <WalletAnalystPanel
            profile={data.profile}
            aiSummary={data.aiSummary}
            generatedAt={data.generatedAt}
            refreshing={loading}
            onRefresh={() => void loadData(true)}
          />
        )}
      </div>
    </div>,
    modalRoot,
  );
}

import { createContext, useCallback, useContext, useEffect, useRef, useState } from "react";
import client from "@/api/main";
import { useAuth } from "@/contexts/AuthContext";
import { useLocalization } from "@/contexts/LocalizationContext";
import { useChatSessions, type ChatSessionContextType, type SessionItem } from "./useChatSessions";
import type { ChatAiUsage, ChatMessageItem, ChatResponse } from "./types";

export const MAX_INPUT_LENGTH = 500;
const API_BASE = import.meta.env.VITE_CLIENT_API_DOMAIN || "";

interface ChatContextValue {
  addresses: string[];
  contextType: ChatSessionContextType;
  messages: ChatMessageItem[];
  inputText: string;
  isLoading: boolean;
  error: string | null;
  usage: ChatAiUsage | null;
  showPromptMenu: boolean;
  showSessionMenu: boolean;
  truncatedMessages: ChatMessageItem[] | null;
  sessions: SessionItem[];
  activeSessionId: string | null;
  activeSession: SessionItem | null;
  setInputText: React.Dispatch<React.SetStateAction<string>>;
  setShowPromptMenu: React.Dispatch<React.SetStateAction<boolean>>;
  setShowSessionMenu: React.Dispatch<React.SetStateAction<boolean>>;
  setActiveSessionId: (id: string | null) => void;
  sendQuery: (query: string, opts?: { skipCache?: boolean; promptId?: string }) => Promise<void>;
  handleRedo: (msgIndex: number, content: string) => Promise<void>;
  handleRevert: (msgIndex: number, content: string) => Promise<void>;
  handleUndoRevert: () => Promise<void>;
  handleNewChat: () => Promise<void>;
  handleSessionSelect: (sessionId: string) => Promise<void>;
  handleDeleteSession: (e: React.MouseEvent, sessionId: string) => Promise<void>;
  refreshSessions: () => Promise<void>;
  createSessionFromQuickMessages: (msgs: ChatMessageItem[], chatAddresses: string[]) => Promise<SessionItem | null>;
}


async function hydrateMessageData(message: ChatMessageItem): Promise<ChatMessageItem> {
  const needsData = message.role === "assistant"
    && !message.data
    && Array.isArray(message.dataRefs)
    && message.dataRefs.length > 0
    && ((message.charts?.length ?? 0) > 0 || (message.tables?.length ?? 0) > 0);

  if (!needsData) return message;

  try {
    const res = await fetch(`${API_BASE}/api/chat/tool-data/resolve`, {
      method: "POST",
      credentials: "include",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ refs: message.dataRefs }),
    });
    if (!res.ok) return message;
    const payload = (await res.json()) as { data?: Record<string, unknown> };
    return { ...message, data: payload.data ?? {} };
  } catch {
    return message;
  }
}

async function hydrateSessionMessages(messages: ChatMessageItem[]): Promise<ChatMessageItem[]> {
  return Promise.all(messages.map((message) => hydrateMessageData(message)));
}
export const ChatContext = createContext<ChatContextValue | null>(null);

interface ChatContextProviderProps {
  addresses: string[];
  contextType: ChatSessionContextType;
  lang?: string;
  children: React.ReactNode;
}

export function ChatContextProvider({ addresses, contextType, lang, children }: ChatContextProviderProps) {
  const { tr } = useLocalization();
  const { user, openAuthModal } = useAuth();
  const [messages, setMessages] = useState<ChatMessageItem[]>([]);
  const [inputText, setInputText] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [usage, setUsage] = useState<ChatAiUsage | null>(null);
  const [showPromptMenu, setShowPromptMenu] = useState(false);
  const [showSessionMenu, setShowSessionMenu] = useState(false);
  const [truncatedMessages, setTruncatedMessages] = useState<ChatMessageItem[] | null>(null);

  const {
    sessions,
    activeSessionId,
    activeSession,
    setActiveSessionId,
    saveMessagesToSession,
    createSessionWithMessages,
    deleteSessionById,
    refreshSessions,
  } = useChatSessions(user?.userId ?? null);

  useEffect(() => {
    let cancelled = false;
    if (activeSession) {
      setMessages(activeSession.messages);
      setError(null);
      setTruncatedMessages(null);
      hydrateSessionMessages(activeSession.messages).then((hydrated) => {
        if (!cancelled) setMessages(hydrated);
      });
      return () => {
        cancelled = true;
      };
    }
    setMessages([]);
    setError(null);
    setTruncatedMessages(null);
    return () => {
      cancelled = true;
    };
  }, [activeSession]);

  useEffect(() => {
    if (!user?.userId) return;
    let cancelled = false;
    (async () => {
      try {
        const res = await client.api.chat.usage.$get();
        const data = await res.json();
        if (!cancelled) setUsage(data as ChatAiUsage);
      } catch { /* ignore */ }
    })();
    return () => { cancelled = true; };
  }, [user?.userId]);

  const messagesRef = useRef(messages);
  messagesRef.current = messages;

  const makeMessageContext = useCallback(
    (walletAddresses = addresses): NonNullable<ChatMessageItem["context"]> => ({
      contextType: walletAddresses.length > 1 ? "wallet-comparison" : contextType,
      walletAddresses,
    }),
    [addresses, contextType],
  );

  const withMessageContext = useCallback(
    (msg: ChatMessageItem, walletAddresses?: string[]): ChatMessageItem => ({
      ...msg,
      context: msg.context ?? makeMessageContext(walletAddresses),
    }),
    [makeMessageContext],
  );

  const readChatError = useCallback(
    async (res: Response) => {
      if (res.status === 401) openAuthModal("login");

      try {
        const body = await res.json() as {
          error?: string;
          message?: string;
          errorCode?: string;
          upgradePath?: string;
        };
        const message =
          body.message?.trim() ||
          body.error?.trim() ||
          tr("chat.serverError", { status: String(res.status) });

        return body.upgradePath &&
          body.errorCode === "AI_DAILY_LIMIT_EXCEEDED"
          ? `${message} Upgrade: ${body.upgradePath}`
          : message;
      } catch {
        return tr("chat.serverError", { status: String(res.status) });
      }
    },
    [openAuthModal, tr],
  );

  const sendQuery = useCallback(
    async (query: string, opts?: { skipCache?: boolean; promptId?: string }) => {
      if (!query.trim() || isLoading || addresses.length === 0) return;

      setShowPromptMenu(false);
      setTruncatedMessages(null);

      const messageContext = makeMessageContext();
      const userMsg: ChatMessageItem = { role: "user", content: query.trim(), context: messageContext };
      const prevMessages = messagesRef.current;
      setMessages((prev) => [...prev, userMsg]);
      setInputText("");
      setIsLoading(true);
      setError(null);

      try {
        const history = prevMessages.slice(-10).map((m) => ({
          role: m.role,
          content: m.content.length > 2000 ? m.content.slice(0, 2000) : m.content,
        }));
        const res = await client.api.chat.$post({
          json: {
            addresses,
            query: query.trim(),
            language: lang,
            history,
            sessionId: activeSessionId ?? undefined,
            contextType,
            skipCache: opts?.skipCache,
            promptId: opts?.promptId,
          },
        });

        if (!res.ok) throw new Error(await readChatError(res));

        const data = (await res.json()) as ChatResponse & { sessionId?: string };
        if (data.usage) setUsage(data.usage);
        const assistantMsg: ChatMessageItem = {
          role: "assistant",
          content: data.text,
          context: messageContext,
          dataRefs: data.dataRefs,
          data: data.data,
          charts: data.charts,
          tables: data.tables,
          actions: data.actions,
          tldr: data.tldr,
          sections: data.sections,
          sources: data.sources,
          evidence: data.evidence,
          warnings: data.warnings,
          confidence: data.confidence,
        };

        setMessages((prev) => [...prev, assistantMsg]);

        if (data.sessionId && data.sessionId !== activeSessionId) {
          setActiveSessionId(data.sessionId);
        }

        refreshSessions();
      } catch (err) {
        const msg = err instanceof Error ? err.message : "Failed to send message";
        setError(msg);
        setMessages((prev) => [
          ...prev,
          withMessageContext({ role: "assistant", content: tr("chat.errorMessage", { error: msg }) }),
        ]);
      } finally {
        setIsLoading(false);
      }
    },

    [addresses, contextType, lang, isLoading, activeSessionId, setActiveSessionId, refreshSessions, tr, makeMessageContext, withMessageContext, readChatError],
  );

  const handleRedo = useCallback(async (msgIndex: number, content: string) => {
    if (isLoading) return;

    const prevMessages = messagesRef.current;
    const truncated = prevMessages.slice(0, msgIndex + 1);
    const title = prevMessages.find((m) => m.role === "user")?.content.slice(0, 50);

    setMessages(truncated);
    setTruncatedMessages(null);
    setShowPromptMenu(false);
    setIsLoading(true);
    setError(null);

    try {
      const history = prevMessages.slice(0, msgIndex).slice(-10).map((m) => ({
        role: m.role,
        content: m.content.length > 2000 ? m.content.slice(0, 2000) : m.content,
      }));

      const res = await client.api.chat.$post({
        json: {
          addresses,
          query: content.trim(),
          language: lang,
          history,
          sessionId: activeSessionId ?? undefined,
          contextType,
          skipCache: true,
          skipSessionSave: true,
        },
      });

      if (!res.ok) throw new Error(await readChatError(res));

      const data = (await res.json()) as ChatResponse & { sessionId?: string };
      const redoContext = truncated[msgIndex]?.context ?? makeMessageContext();
      if (data.usage) setUsage(data.usage);
      const assistantMsg: ChatMessageItem = {
        role: "assistant",
        content: data.text,
        context: redoContext,
        dataRefs: data.dataRefs,
        data: data.data,
        charts: data.charts,
        tables: data.tables,
        actions: data.actions,
        tldr: data.tldr,
        sections: data.sections,
        sources: data.sources,
        evidence: data.evidence,
        warnings: data.warnings,
        confidence: data.confidence,
      };

      const finalMessages = [...truncated, assistantMsg];
      setMessages(finalMessages);

      if (activeSessionId) {
        await saveMessagesToSession(activeSessionId, finalMessages, title);
      }

      if (data.sessionId && data.sessionId !== activeSessionId) {
        setActiveSessionId(data.sessionId);
      }

      refreshSessions();
    } catch (err) {
      const msg = err instanceof Error ? err.message : "Failed to send message";
      setError(msg);
      setMessages((prev) => [
        ...prev,
        withMessageContext({ role: "assistant", content: tr("chat.errorMessage", { error: msg }) }),
      ]);
    } finally {
      setIsLoading(false);
    }
  }, [addresses, activeSessionId, setActiveSessionId, contextType, isLoading, lang, saveMessagesToSession, refreshSessions, tr, makeMessageContext, withMessageContext, readChatError]);

  const handleRevert = useCallback(async (msgIndex: number, content: string) => {
    if (!activeSessionId) return;

    const prevMessages = messagesRef.current;
    const truncated = prevMessages.slice(0, msgIndex);
    const title = prevMessages.find((m) => m.role === "user")?.content.slice(0, 50);
    await saveMessagesToSession(activeSessionId, truncated, title);

    const rest = prevMessages.slice(msgIndex);
    setTruncatedMessages(rest.length > 0 ? rest : null);
    setMessages(truncated);
    setInputText(content);
    setShowPromptMenu(false);
  }, [activeSessionId, saveMessagesToSession]);

  const handleUndoRevert = useCallback(async () => {
    if (!truncatedMessages) return;
    const prevMessages = messagesRef.current;
    const restored = [...prevMessages, ...truncatedMessages];
    setMessages(restored);
    setTruncatedMessages(null);
    if (activeSessionId) {
      await saveMessagesToSession(activeSessionId, restored);
    }
  }, [truncatedMessages, activeSessionId, saveMessagesToSession]);

  const handleNewChat = useCallback(async () => {
    setMessages([]);
    setTruncatedMessages(null);
    setError(null);
    setShowPromptMenu(false);
    setActiveSessionId(null);
  }, [setActiveSessionId]);

  const handleSessionSelect = useCallback(async (sessionId: string) => {
    setActiveSessionId(sessionId);
    setShowSessionMenu(false);
  }, [setActiveSessionId]);

  const handleDeleteSession = useCallback(async (e: React.MouseEvent, sessionId: string) => {
    e.stopPropagation();
    await deleteSessionById(sessionId);
  }, [deleteSessionById]);

  const createSessionFromQuickMessages = useCallback(async (msgs: ChatMessageItem[], chatAddresses: string[]) => {
    const messageContext: NonNullable<ChatMessageItem["context"]> = {
      contextType: chatAddresses.length > 1 ? "wallet-comparison" : "wallet",
      walletAddresses: chatAddresses,
    };
    const stampedMessages = msgs.map((msg) => ({
      ...msg,
      context: messageContext,
    }));
    const title = stampedMessages.find((msg) => msg.role === "user")?.content.slice(0, 50);
    const session = await createSessionWithMessages(
      chatAddresses,
      messageContext.contextType,
      stampedMessages,
      title,
    );

    if (session) {
      setMessages(stampedMessages);
      setTruncatedMessages(null);
      setShowPromptMenu(false);
      setShowSessionMenu(false);
    }

    return session;
  }, [createSessionWithMessages]);

  return (
    <ChatContext.Provider
      value={{
        addresses,
        contextType,
        messages,
        inputText,
        isLoading,
        error,
        usage,
        showPromptMenu,
        showSessionMenu,
        truncatedMessages,
        sessions,
        activeSessionId,
        activeSession,
        setInputText,
        setShowPromptMenu,
        setShowSessionMenu,
        setActiveSessionId,
        sendQuery,
        handleRedo,
        handleRevert,
        handleUndoRevert,
        handleNewChat,
        handleSessionSelect,
        handleDeleteSession,
        refreshSessions,
        createSessionFromQuickMessages,
      }}
    >
      {children}
    </ChatContext.Provider>
  );
}

export function useChatContext(): ChatContextValue {
  const ctx = useContext(ChatContext);
  if (!ctx) {
    throw new Error("useChatContext must be used within a ChatContextProvider");
  }
  return ctx;
}

import classNames from "classnames";
import { useCallback, useMemo, useState, type ReactNode } from "react";
import ReactDOM from "react-dom";
import { useNavigate } from "react-router";
import { Copy, Check, RefreshCw, Pencil } from "lucide-react";
import { ID_MODAL_ROOT } from "@/config/constants";
import { useLocalization } from "@/contexts/LocalizationContext";
import type { TranslationKeyPath } from "@/config/localization";
import type {
  ActionSpec,
  ChatMessageItem,
  ChatSource,
  WalletChatSection,
  WalletSectionKind,
} from "./types";
import { GeckoTerminalChart } from "@/components/charts/GeckoTerminalChart";
import { ChartRenderer, TableRenderer } from "./WalletChatChartRenderer";
import { SourcePanel } from "./WalletChatSourcePanel";
import styles from "./WalletChat.module.scss";

interface Props {
  message: ChatMessageItem;
  index: number;
  onAction?: (href: string) => void;
  onRedo?: (index: number, content: string) => void;
  onRevert?: (index: number, content: string) => void;
}

const MARKER_RE = /<(chart|table|action)\s+id="([^"]+)"\s*\/>/g;
const CITE_RE = /<cite\s+ids="([^"]+)"\s*>((?:(?!<\/cite>)[\s\S])*?)<\/cite>/g;

function normalizeMarkers(text: string): string {
  return text.replace(/<(chart|table)>id="([^"]+)"<\/\1>/g, '<$1 id="$2" />');
}

type PartType =
  | { type: "text"; content: string }
  | { type: "chart"; id: string }
  | { type: "table"; id: string }
  | { type: "action"; id: string }
  | { type: "cite"; ids: string[]; content: string };

function parseMarkers(text: string): PartType[] {
  const normalized = normalizeMarkers(text);
  const parts: PartType[] = [];

  // Collect all marker positions (cite + self-closing)
  type Marker = { index: number; endIndex: number; type: PartType["type"] } & (
    | { type: "cite"; ids: string[]; content: string }
    | { type: "chart" | "table" | "action"; id: string }
  );

  const markers: Marker[] = [];

  let m: RegExpExecArray | null;
  while ((m = CITE_RE.exec(normalized)) !== null) {
    const ids = m[1].split(",").map((s) => s.trim()).filter(Boolean);
    markers.push({
      index: m.index,
      endIndex: m.index + m[0].length,
      type: "cite",
      ids,
      content: m[2],
    });
  }

  while ((m = MARKER_RE.exec(normalized)) !== null) {
    markers.push({
      index: m.index,
      endIndex: m.index + m[0].length,
      type: m[1] as "chart" | "table" | "action",
      id: m[2],
    });
  }

  markers.sort((a, b) => a.index - b.index);

  let lastIndex = 0;
  for (const marker of markers) {
    if (marker.index > lastIndex) {
      parts.push({ type: "text", content: normalized.slice(lastIndex, marker.index) });
    }
    if (marker.type === "cite") {
      parts.push({ type: "cite", ids: marker.ids, content: marker.content });
    } else if (marker.type === "action") {
      parts.push({ type: "action", id: marker.id });
    } else {
      parts.push({ type: marker.type as "chart" | "table", id: marker.id });
    }
    lastIndex = marker.endIndex;
  }
  if (lastIndex < normalized.length) {
    parts.push({ type: "text", content: normalized.slice(lastIndex) });
  }

  return parts;
}

// ─── Rich Text Helpers ──────────────────────────────────────────────────

const METRIC_OR_SIGNAL_PATTERN =
  /([+-]\d+(?:\.\d+)?%|[$€£¥₿]\s?\d[\d,]*(?:\.\d+)?)/gi;

function stripMarkdownArtifacts(value: string) {
  return value.replace(/\*\*/g, "");
}

function splitBoldSegments(value: string) {
  const segments: Array<{ text: string; bold: boolean }> = [];
  const boldPattern = /\*\*([^*]+?)\*\*/g;
  let lastIndex = 0;

  for (const match of value.matchAll(boldPattern)) {
    const index = match.index ?? 0;
    if (index > lastIndex) {
      segments.push({ text: stripMarkdownArtifacts(value.slice(lastIndex, index)), bold: false });
    }
    segments.push({ text: match[1], bold: true });
    lastIndex = index + match[0].length;
  }

  if (lastIndex < value.length) {
    segments.push({ text: stripMarkdownArtifacts(value.slice(lastIndex)), bold: false });
  }

  return segments.length > 0
    ? segments.filter((s) => s.text.length > 0)
    : [{ text: stripMarkdownArtifacts(value), bold: false }];
}

function getMetricClass(value: string) {
  if (/^\+\d/.test(value) && value.includes("%")) return "metricPositive";
  if (/^-\d/.test(value) && value.includes("%")) return "metricNegative";
  if (/^[$€£¥₿]/.test(value.trim())) return "metricMoney";
  return "metricNeutral";
}

function isNumericPartOfIdentifier(fullText: string, matchIndex: number, matchedText: string): boolean {
  if (!/^\d[\d,.]*$/.test(matchedText)) return false;
  const charBefore = fullText[matchIndex - 1];
  const charAfter = fullText[matchIndex + matchedText.length];
  if (charBefore && /[a-zA-Z]/.test(charBefore)) return true;
  if (charAfter && /[a-zA-Z]/.test(charAfter)) return true;
  return false;
}

function renderMetricTokens(value: string, keyPrefix: string): ReactNode[] {
  const nodes: ReactNode[] = [];
  let lastIndex = 0;

  for (const match of value.matchAll(METRIC_OR_SIGNAL_PATTERN)) {
    const index = match.index ?? 0;
    const text = match[0];
    if (index > lastIndex) {
      nodes.push(value.slice(lastIndex, index));
    }
    if (isNumericPartOfIdentifier(value, index, text)) {
      nodes.push(text);
    } else if (isInsideCitationBrackets(value, index, text)) {
      nodes.push(text);
    } else {
      const metricClass = getMetricClass(text);
      nodes.push(
        <span key={`${keyPrefix}-${index}`} className={classNames(styles.metricToken, styles[metricClass])}>
          {text}
        </span>,
      );
    }
    lastIndex = index + text.length;
  }

  if (lastIndex < value.length) {
    nodes.push(value.slice(lastIndex));
  }

  return nodes;
}

function isInsideCitationBrackets(fullText: string, matchIndex: number, matchedText: string): boolean {
  return fullText[matchIndex - 1] === "[" && fullText[matchIndex + matchedText.length] === "]";
}

function renderInlineRichText(value: string, keyPrefix = "rich") {
  return splitBoldSegments(value).map((segment, idx) => {
    const content = renderMetricTokens(segment.text, `${keyPrefix}-${idx}`);
    if (!segment.bold) return <span key={`${keyPrefix}-${idx}`}>{content}</span>;
    return (
      <strong key={`${keyPrefix}-${idx}`} className={styles.richStrong}>
        {content}
      </strong>
    );
  });
}

function parseStructuredQuery(text: string): Record<string, string> | null {
  const t = text.trim();
  if (!t.startsWith("{") || !t.endsWith("}") || !t.includes(": ")) return null;
  const inner = t.slice(1, -1);
  const pairs: Record<string, string> = {};
  let depth = 0;
  let current = "";
  for (const ch of inner) {
    if (ch === "{" || ch === "[") depth++;
    else if (ch === "}" || ch === "]") depth--;
    if (ch === "," && depth === 0) {
      const sep = current.indexOf(": ");
      if (sep > 0) { pairs[current.slice(0, sep).trim()] = current.slice(sep + 2).trim(); }
      current = "";
    } else { current += ch; }
  }
  if (current.trim()) {
    const sep = current.indexOf(": ");
    if (sep > 0) { pairs[current.slice(0, sep).trim()] = current.slice(sep + 2).trim(); }
  }
  return Object.keys(pairs).length > 0 ? pairs : null;
}

function isBulletLikeLine(value: string) {
  return /^\s*(?:[-*\u2022]\s+|\d+[.)]\s+)/.test(value);
}

function cleanBulletLine(value: string) {
  return value.replace(/^\s*(?:[-*\u2022]\s+|\d+[.)]\s+)/, "").trim();
}

function WalletRichText({ text, inline = false }: { text?: string | number | null; inline?: boolean }) {
  const value = String(text ?? "").trim();
  if (!value) return null;

  if (inline) return <>{renderInlineRichText(value)}</>;

  const blocks = value.split(/\n{2,}/).map((b) => b.trim()).filter(Boolean);

  return (
    <>
      {blocks.map((block, blockIdx) => {
        const lines = block.split(/\n/).map((l) => l.trim()).filter(Boolean);

        if (lines.length > 0 && lines.every(isBulletLikeLine)) {
          return (
            <ul key={blockIdx} className={styles.richList}>
              {lines.map((line, lineIdx) => (
                <li key={lineIdx}>
                  {renderInlineRichText(cleanBulletLine(line), `rich-${blockIdx}-${lineIdx}`)}
                </li>
              ))}
            </ul>
          );
        }

        return (
          <div key={blockIdx} className={styles.richParagraphGroup}>
            {lines.map((line, lineIdx) =>
              isBulletLikeLine(line) ? (
                <div key={lineIdx} className={styles.richBulletLine}>
                  <span aria-hidden="true" />
                  <span>{renderInlineRichText(cleanBulletLine(line), `rich-${blockIdx}-${lineIdx}`)}</span>
                </div>
              ) : (
                <p key={lineIdx} className={styles.richParagraph}>
                  {renderInlineRichText(line, `rich-${blockIdx}-${lineIdx}`)}
                </p>
              ),
            )}
          </div>
        );
      })}
    </>
  );
}

// ─── Section Table ──────────────────────────────────────────────────────

function SectionTable({ table }: { table: Array<Record<string, string | number | null>> }) {
  const columns = useMemo(() => {
    const keys = new Set<string>();
    table.forEach((row) => Object.keys(row).forEach((k) => keys.add(k)));
    return [...keys].slice(0, 6);
  }, [table]);

  if (columns.length === 0) return null;

  return (
    <div className={styles.tableWrap}>
      <table className={styles.sectionTable}>
        <thead>
          <tr>
            {columns.map((col) => <th key={col}>{col}</th>)}
          </tr>
        </thead>
        <tbody>
          {table.map((row, idx) => (
            <tr key={idx}>
              {columns.map((col) => (
                <td key={col}>
                  <WalletRichText text={row[col] ?? "-"} inline />
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

