import client from "@/api/main";
import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useState,
} from "react";

type AuthUser = {
  userId: string;
  displayName: string | null;
  avatarUrl?: string | null;
};

type AuthContextType = {
  user: AuthUser | null;
  isUserLoading: boolean;
  setUser: (user: AuthUser | null) => void;
  refreshUser: () => Promise<void>;
  signOut: () => Promise<void>;
  openAuthModal: (mode?: "login" | "register") => void;
  closeAuthModal: () => void;
  isSignInOpen: boolean;
  isSignUpOpen: boolean;
};

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<AuthUser | null>(null);
  const [isUserLoading, setIsUserLoading] = useState(true);

  const refreshUser = useCallback(async () => {
    try {
      setIsUserLoading(true);

      const resp = await client.api.users.auth.me.$get();

      if (resp.ok) {
        const res = await resp.json();

        if (res) {
          setUser({
            userId: res.id,
            displayName: res.displayName,
            avatarUrl: res.avatarUrl,
          });
        } else {
          // API may return null for unauthenticated sessions.
          setUser(null);
        }
      } else {
        // API may return null for unauthenticated sessions.
        setUser(null);
      }
    } catch (err) {
      console.error("Failed to fetch current user:", err);
    } finally {
      setIsUserLoading(false);
    }
  }, []);

  useEffect(() => {
    setUser(null);
    refreshUser();
  }, [refreshUser]);

  const signOut = useCallback(async () => {
    await client.api.users.auth.logout.$delete();
    setUser(null);
  }, []);

  const [isSignInOpen, setIsSignInOpen] = useState(false);
  const [isSignUpOpen, setIsSignUpOpen] = useState(false);

  const openAuthModal = useCallback((mode: "login" | "register" = "login") => {
    if (mode === "login") setIsSignInOpen(true);
    else setIsSignUpOpen(true);
  }, []);

  const closeAuthModal = useCallback(() => {
    setIsSignInOpen(false);
    setIsSignUpOpen(false);
  }, []);

  return (
    <AuthContext.Provider
      value={{ 
        user, 
        isUserLoading,
        setUser, 
        refreshUser, 
        signOut, 
        openAuthModal,
        closeAuthModal,
        isSignInOpen,
        isSignUpOpen 
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth(): AuthContextType {
  const context = useContext(AuthContext);
  if (context == undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
}

/**
 * Chart Context
 * 
 * Provides shared state for charts across the application, including:
 * - Global timezone setting
 * - Chart registration for coordinated refreshes
 * - Shared configuration
 * 
 * @module ChartContext
 */

import React, { createContext, useContext, useState, useCallback, useRef } from 'react';

/**
 * Type for chart refresh function
 */
type ChartRefreshFn = () => Promise<void>;

/**
 * Chart context value interface
 */
interface ChartContextValue {
  /** Currently selected timezone (IANA timezone string) */
  selectedTimezone: string;
  
  /** Update the global timezone setting */
  setTimezone: (tz: string) => void;
  
  /** Register a chart for coordinated refresh */
  registerChart: (chartId: string, refreshFn: ChartRefreshFn) => void;
  
  /** Unregister a chart */
  unregisterChart: (chartId: string) => void;
  
  /** Refresh all registered charts */
  refreshAllCharts: () => Promise<void>;
  
  /** Check if a chart is registered */
  isChartRegistered: (chartId: string) => boolean;
}

/**
 * Create the context with undefined default
 */
const ChartContext = createContext<ChartContextValue | undefined>(undefined);

/**
 * Hook to access the chart context
 * @throws Error if used outside of ChartProvider
 */
export function useChartContext(): ChartContextValue {
  const context = useContext(ChartContext);
  
  if (!context) {
    throw new Error('useChartContext must be used within a ChartProvider');
  }
  
  return context;
}

/**
 * Props for ChartProvider component
 */
interface ChartProviderProps {
  /** Child components */
  children: React.ReactNode;
  
  /** Initial timezone (defaults to user's local timezone) */
  initialTimezone?: string;
}

/**
 * ChartProvider Component
 * 
 * Wraps the application or a section of the app to provide shared chart state.
 * 
 * @example
 * ```tsx
 * <ChartProvider initialTimezone="America/New_York">
 *   <Dashboard />
 * </ChartProvider>
 * ```
 */
export function ChartProvider({ children, initialTimezone }: ChartProviderProps) {
  // Get user's local timezone if not specified
  const userTimezone = Intl.DateTimeFormat().resolvedOptions().timeZone;
  const [selectedTimezone, setSelectedTimezone] = useState<string>(
    initialTimezone || userTimezone
  );
  
  // Registry of chart refresh functions
  const chartRegistry = useRef<Map<string, ChartRefreshFn>>(new Map());
  
  /**
   * Update the global timezone
   */
  const setTimezone = useCallback((tz: string) => {
    setSelectedTimezone(tz);
  }, []);
  
  /**
   * Register a chart with its refresh function
   */
  const registerChart = useCallback((chartId: string, refreshFn: ChartRefreshFn) => {
    chartRegistry.current.set(chartId, refreshFn);
  }, []);
  
  /**
   * Unregister a chart
   */
  const unregisterChart = useCallback((chartId: string) => {
    chartRegistry.current.delete(chartId);
  }, []);
  
  /**
   * Refresh all registered charts
   */
  const refreshAllCharts = useCallback(async () => {
    const refreshPromises: Promise<void>[] = [];
    
    chartRegistry.current.forEach((refreshFn) => {
      refreshPromises.push(refreshFn());
    });
    
    try {
      await Promise.all(refreshPromises);
    } catch (error) {
      console.error('Error refreshing charts:', error);
    }
  }, []);
  
  /**
   * Check if a chart is registered
   */
  const isChartRegistered = useCallback((chartId: string) => {
    return chartRegistry.current.has(chartId);
  }, []);
  
  const value: ChartContextValue = {
    selectedTimezone,
    setTimezone,
    registerChart,
    unregisterChart,
    refreshAllCharts,
    isChartRegistered,
  };
  
  return <ChartContext.Provider value={value}>{children}</ChartContext.Provider>;
}

/**
 * Re-export context for direct access if needed
 */
export { ChartContext };

import {
    locale,
    type BaseTranslation,
    type FmtStrParams,
    type HasNodeParam,
    type PathValue,
    type TranslationKeyPath,
    type TranslationSchema,
    type WithBase,
} from "@/config/localization";
import React, { useEffect, useMemo, useState, type ReactNode } from "react";

type LangCode = keyof typeof locale;

type TranslationReturn<K extends TranslationKeyPath> =
  HasNodeParam<PathValue<BaseTranslation, K>> extends true
    ? React.ReactNode
    : string;

// This helps the error when you mistype the key (eg. tr("non_existent_key")) will be at the key name itself.
// Though if you continue to type in the second argument, it'd both show the error at the wrong key
// and hint the type of second argument as all the format variables of the translation
export type TranslateFunction = {
  <K extends TranslationKeyPath>(
    key: FmtStrParams<PathValue<BaseTranslation, K>> extends undefined
      ? K
      : never,
  ): WithBase<PathValue<BaseTranslation, K>, TranslationReturn<K>>;

  <K extends TranslationKeyPath>(
    key: K,
    params: FmtStrParams<PathValue<BaseTranslation, K>>,
  ): WithBase<PathValue<BaseTranslation, K>, TranslationReturn<K>>;
};

type NumberFormatter = typeof locale.en.format.num;
type DatetimeFormatter = typeof locale.en.format.datetime;
type TextFormatter = typeof locale.en.format.text;

type Formatter = {
  num: NumberFormatter;
  datetime: DatetimeFormatter;
  text: TextFormatter;
};

type LocalizationContextType = {
  lang: LangCode;
  setLang: React.Dispatch<React.SetStateAction<LangCode>>;
  tr: TranslateFunction;
  fmt: Formatter;
};

type PluralSelection =
  | { ok: false }
  | { ok: true; selection: { singular: string; plural: string } };

function tryGetPluralSelection(key: string): PluralSelection {
  const parts = key.split("|");
  if (parts.length != 2 || parts[0].length <= 0 || parts[1].length <= 0) {
    return { ok: false };
  } else {
    return {
      ok: true,
      selection: { singular: parts[0], plural: parts[1] },
    };
  }
}

const LocalizationContext = React.createContext<
  LocalizationContextType | undefined
>(undefined);

function getTranslationValue(
  translation: TranslationSchema,
  path: TranslationKeyPath,
): string {
  return path
    .split(".")
    .reduce((acc: unknown, part) => (acc as Record<string, unknown>)[part], translation as unknown) as string;
}

function reactFromParts(parts: ReactNode[]) {
  return React.createElement(React.Fragment, null, ...parts);
}

function interpolate(
  template: string,
  params: Record<string, unknown>,
): string | React.ReactNode {
  const count = Number(params.count);
  const hasCount = "count" in params && !Number.isNaN(count);

  const parts: React.ReactNode[] = [];

  let lastIndex = 0;
  const regex = /{{(.*?)}}/g;
  let match: RegExpExecArray | null;

  while ((match = regex.exec(template)) != null) {
    const rawKey = match[1].trim();

    if (match.index > lastIndex) {
      parts.push(template.slice(lastIndex, match.index));
    }

    const plural: PluralSelection = hasCount
      ? tryGetPluralSelection(rawKey)
      : { ok: false };

    if (plural.ok) {
      parts.push(
        count != 1 ? plural.selection.plural : plural.selection.singular,
      );
    } else {
      const value = params[rawKey];

      if (React.isValidElement(value)) {
        parts.push(value);
      } else if (value != null) {
        parts.push(String(value));
      } else {
        parts.push("");
      }
    }

    lastIndex = regex.lastIndex;
  }

  // Add final part
  if (lastIndex < template.length) {
    parts.push(template.slice(lastIndex));
  }

  const hasNode = parts.some((p) => typeof p != "string");

  return hasNode ? reactFromParts(parts) : parts.join("");
}

const LANG_STORAGE_KEY = "yoca_language";
const VIETNAMESE_LOCALES = ["vi", "vi-VN"];

function getConfiguredLang(): LangCode {
  // Try to get from localStorage first
  const configuredLang = localStorage.getItem(
    LANG_STORAGE_KEY,
  ) as LangCode | null;
  if (configuredLang && configuredLang in locale) {
    return configuredLang;
  }

  // Detect browser language
  const browserLang = navigator.language || navigator.languages?.[0];

  // Check if browser language is Vietnamese
  if (
    browserLang &&
    VIETNAMESE_LOCALES.some((loc) => browserLang.startsWith(loc))
  ) {
    return "vi";
  }

  // Note: this is rarely needed as we didn't aim to support other languages
  // Check if browser language matches any supported language
  // if (browserLang) {
  //   const langCode = browserLang.split("-")[0] as LangCode;
  //   if (langCode in locale) {
  //     return langCode;
  //   }
  // }
  return "en";
}

export function LocalizationProvider({
  children,
}: {
  children: React.ReactNode;
}) {
  const [lang, setLang] = useState<LangCode>(getConfiguredLang());

  useEffect(() => {
    localStorage.setItem(LANG_STORAGE_KEY, lang);
  }, [lang]);

  function tr<K extends TranslationKeyPath>(
    key: FmtStrParams<PathValue<BaseTranslation, K>> extends undefined
      ? K
      : never,
  ): TranslationReturn<K>;

  function tr<K extends TranslationKeyPath>(
    key: K,
    params: FmtStrParams<PathValue<BaseTranslation, K>>,
  ): TranslationReturn<K>;

  function tr(
    key: TranslationKeyPath,
    params?: Record<string, unknown>,
  ): string | React.ReactNode {
    const template = getTranslationValue(locale[lang].translation, key);

    if (params) {
      return interpolate(template, params);
    }

    return template;
  }

  const fmt = useMemo<Formatter>(() => {
    return {
      num: locale[lang].format.num,
      datetime: locale[lang].format.datetime,
      text: locale[lang].format.text,
    };
  }, [lang]);

  return (
    <LocalizationContext.Provider value={{ lang, setLang, tr, fmt }}>
      {children}
    </LocalizationContext.Provider>
  );
}

export function useLocalization() {
  const ctx = React.useContext(LocalizationContext);

  if (!ctx) {
    throw new Error("useLocalization must be used inside LocalizationProvider");
  }

  return ctx;
}

