}

interface SolanaContextType {
  isModalOpen: boolean;
  openModal: () => void;
  closeModal: () => void;
}

const SolanaContext = createContext<SolanaContextType | undefined>(undefined);

export const useSolanaContext = () => {
  const context = useContext(SolanaContext);
  if (!context) {
    throw new Error("useSolanaContext must be used within SolanaProvider");
  }
  return context;
};

function SolanaProviderContent({ children }: { children: ReactNode }) {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const { visible: walletModalVisible, setVisible: setWalletModalVisibility } =
    useWalletModal();

  useEffect(() => {
    if (!walletModalVisible) {
      setIsModalOpen(false);
    }
  }, [walletModalVisible]);

  const openModal = () => setIsModalOpen(true);
  const closeModal = () => {
    setIsModalOpen(false);
    setWalletModalVisibility(false);
  };

  const contextValue = useMemo(
    () => ({
      isModalOpen,
      openModal,
      closeModal,
    }),
    [isModalOpen],
  );

  return (
    <SolanaContext.Provider value={contextValue}>
      {children}
      <ModalStateManager renderLauncher={() => <></>}>
        {() => (
          <ComposedModal
            open={isModalOpen}
            onClose={closeModal}
            className={styles.walletModalContainer}
            preventCloseOnClickOutside={false}
          >
            <ModalBody
              id="wallet-modal-container"
              style={{ height: "100vh" }}
            />
          </ComposedModal>
        )}
      </ModalStateManager>
    </SolanaContext.Provider>
  );
}

export const SolanaProvider: FC<SolanaProviderProps> = ({ children }) => {
  /**
   * Derive the network from VITE_SOLANA_NETWORK with strict validation.
   * Falls back to Devnet if the env is misconfigured so the UI can still
   * mount and display the error through its own toast/alert system.
   */
  const network = useMemo((): WalletAdapterNetwork => {
    try {
      return getWalletAdapterNetwork();
    } catch (err) {
      console.error(
        "[SolanaProvider] Network configuration error — falling back to Devnet:\n",
        (err as Error).message
      );
      return WalletAdapterNetwork.Devnet;
    }
  }, []);
  const endpoint = useMemo(() => {
    try {
      return getSolanaRpcEndpoint();
    } catch (err) {
      console.error(
        "[SolanaProvider] RPC configuration error — falling back to clusterApiUrl:\n",
        (err as Error).message
      );
      return clusterApiUrl(network);
    }
  }, [network]);

  const wallets = useMemo(
    () => [new PhantomWalletAdapter(), new SolflareWalletAdapter({ network })],
    [network],
  );

  localStorage.removeItem("walletName");

  return (
    <ConnectionProvider endpoint={endpoint}>
      <WalletProvider wallets={wallets} autoConnect={false}>
        <WalletModalProvider
          container="#wallet-modal-container"
          className="hello"
        >
          <SolanaProviderContent>{children}</SolanaProviderContent>
        </WalletModalProvider>
      </WalletProvider>
    </ConnectionProvider>
  );
};

import { THEME_LOCAL_STORAGE_KEY } from "@/config/constants";
import { GlobalTheme, Theme } from "@carbon/react";
import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useRef,
  useState,
  type ComponentProps,
  type ReactNode,
  type RefObject,
} from "react";

type SupportedTheme = ComponentProps<typeof Theme>["theme"];
const userThemes = {
  light: "white",
  dark: "g100",
} as const satisfies Record<string, SupportedTheme>;
export type ThemeMode = keyof typeof userThemes;

function isValidTheme(value: string): value is ThemeMode {
  return Object.keys(userThemes).includes(value);
}

interface ThemeContextType {
  theme: ThemeMode;
  toggleTheme: () => void;
  themeRef: RefObject<HTMLDivElement | null>;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

interface ThemeProviderProps {
  children: ReactNode;
}

function getInitialTheme(): ThemeMode {
  const previousTheme = localStorage.getItem(THEME_LOCAL_STORAGE_KEY);
  if (previousTheme && isValidTheme(previousTheme)) {
    return previousTheme;
  }
  return "light";
}

export const ThemeProvider: React.FC<ThemeProviderProps> = ({ children }) => {
  const [theme, setTheme] = useState<ThemeMode>(getInitialTheme);

  const themeRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    localStorage.setItem(THEME_LOCAL_STORAGE_KEY, theme);
  }, [theme]);

  const toggleTheme = useCallback(() => {
    setTheme((prevTheme) => (prevTheme == "light" ? "dark" : "light"));
  }, []);

  return (
    <ThemeContext.Provider
      value={{
        theme,
        toggleTheme,
        themeRef,
      }}
    >
      <GlobalTheme theme={userThemes[theme]}>
        <Theme theme={userThemes[theme]} style={{ minHeight: "100vh" }}>
          <div
            ref={themeRef}
            className="yoca-app-theme"
            data-carbon-theme
            data-yoca-theme={theme}
          >
            {children}
          </div>
        </Theme>
      </GlobalTheme>
    </ThemeContext.Provider>
  );
};

export function useUserTheme() {
  const context = useContext(ThemeContext);
  if (context == undefined) {
    throw new Error("useUserTheme must be used within a ThemeProvider");
  }
  return context;
}

import { useAuth } from "@/contexts/AuthContext";
import {
    addTokenToWatchlist,
    addWalletToWatchlist,
    getTokenWatchlist,
    getWalletWatchlist,
    removeTokenFromWatchlist,
    removeWalletFromWatchlist,
} from "@/services/profile/profileApi";
import {
    createContext,
    useCallback,
    useContext,
    useEffect,
    useMemo,
    useState,
    type ReactNode,
} from "react";

interface WatchlistContextType {
    tokenWatchlist: string[];
    walletWatchlist: string[];
    isLoading: boolean;
    tokenPending: Record<string, boolean>;
    walletPending: Record<string, boolean>;
    refetch: () => Promise<void>;
    addToken: (tokenAddress: string) => Promise<void>;
    removeToken: (tokenAddress: string) => Promise<void>;
    toggleToken: (tokenAddress: string) => Promise<void>;
    addWallet: (walletAddress: string) => Promise<void>;
    removeWallet: (walletAddress: string) => Promise<void>;
    toggleWallet: (walletAddress: string) => Promise<void>;
}

const WatchlistContext = createContext<WatchlistContextType | undefined>(
    undefined,
);

function pushUnique(items: string[], value: string): string[] {
    if (items.includes(value)) return items;
    return [...items, value];
}

function removeValue(items: string[], value: string): string[] {
    return items.filter((item) => item !== value);
}

export function WatchlistProvider({ children }: { children: ReactNode }) {
    const { user } = useAuth();
    const [tokenWatchlist, setTokenWatchlist] = useState<string[]>([]);
    const [walletWatchlist, setWalletWatchlist] = useState<string[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [tokenPending, setTokenPending] = useState<Record<string, boolean>>({});
    const [walletPending, setWalletPending] = useState<Record<string, boolean>>({});

    const refetch = useCallback(async () => {
        if (!user) {
            setTokenWatchlist([]);
            setWalletWatchlist([]);
            return;
        }

        setIsLoading(true);
        try {
            const [tokens, wallets] = await Promise.all([
                getTokenWatchlist(),
                getWalletWatchlist(),
            ]);
            setTokenWatchlist(tokens);
            setWalletWatchlist(wallets);
        } catch {
            setTokenWatchlist([]);
            setWalletWatchlist([]);
        } finally {
            setIsLoading(false);
        }
    }, [user]);

    useEffect(() => {
        void refetch();
    }, [refetch]);

    const addToken = useCallback(async (tokenAddress: string) => {
        setTokenPending((prev) => ({ ...prev, [tokenAddress]: true }));
        setTokenWatchlist((prev) => pushUnique(prev, tokenAddress));

        try {
            await addTokenToWatchlist(tokenAddress);
        } catch (error) {
            setTokenWatchlist((prev) => removeValue(prev, tokenAddress));
            throw error;
        } finally {
            setTokenPending((prev) => ({ ...prev, [tokenAddress]: false }));
        }
    }, []);

    const removeToken = useCallback(async (tokenAddress: string) => {
        setTokenPending((prev) => ({ ...prev, [tokenAddress]: true }));
        setTokenWatchlist((prev) => removeValue(prev, tokenAddress));

        try {
            await removeTokenFromWatchlist(tokenAddress);
        } catch (error) {
            setTokenWatchlist((prev) => pushUnique(prev, tokenAddress));
            throw error;
        } finally {
            setTokenPending((prev) => ({ ...prev, [tokenAddress]: false }));
        }
    }, []);

    const toggleToken = useCallback(
        async (tokenAddress: string) => {
            const exists = tokenWatchlist.includes(tokenAddress);
            if (exists) {
                await removeToken(tokenAddress);
                return;
            }
            await addToken(tokenAddress);
        },
        [addToken, removeToken, tokenWatchlist],
    );

    const addWallet = useCallback(async (walletAddress: string) => {
        setWalletPending((prev) => ({ ...prev, [walletAddress]: true }));
        setWalletWatchlist((prev) => pushUnique(prev, walletAddress));

        try {
            await addWalletToWatchlist(walletAddress);
        } catch (error) {
            setWalletWatchlist((prev) => removeValue(prev, walletAddress));
            throw error;
        } finally {
            setWalletPending((prev) => ({ ...prev, [walletAddress]: false }));
        }
    }, []);

    const removeWallet = useCallback(async (walletAddress: string) => {
        setWalletPending((prev) => ({ ...prev, [walletAddress]: true }));
        setWalletWatchlist((prev) => removeValue(prev, walletAddress));

        try {
            await removeWalletFromWatchlist(walletAddress);
        } catch (error) {
            setWalletWatchlist((prev) => pushUnique(prev, walletAddress));
            throw error;
        } finally {
            setWalletPending((prev) => ({ ...prev, [walletAddress]: false }));
        }
    }, []);

    const toggleWallet = useCallback(
        async (walletAddress: string) => {
            const exists = walletWatchlist.includes(walletAddress);
            if (exists) {
                await removeWallet(walletAddress);
                return;
            }
            await addWallet(walletAddress);
        },
        [addWallet, removeWallet, walletWatchlist],
    );

    const value = useMemo<WatchlistContextType>(
        () => ({
            tokenWatchlist,
            walletWatchlist,
            isLoading,
            tokenPending,
            walletPending,
            refetch,
            addToken,
            removeToken,
            toggleToken,
            addWallet,
            removeWallet,
            toggleWallet,
        }),
        [
            tokenWatchlist,
            walletWatchlist,
            isLoading,
            tokenPending,
            walletPending,
            refetch,
            addToken,
            removeToken,
            toggleToken,
            addWallet,
            removeWallet,
            toggleWallet,
        ],
    );

    return (
        <WatchlistContext.Provider value={value}>{children}</WatchlistContext.Provider>
    );
}

export function useWatchlist() {
    const context = useContext(WatchlistContext);

    if (context == undefined) {
        throw new Error("useWatchlist must be used within a WatchlistProvider");
    }

    return context;
}

import {
  fetchWalletOverview,
  fetchWalletSwaps,
  fetchWalletTransfers,
  type WalletOverviewMultiPeriodResponse,
  type WalletOverviewPeriodKey,
  type WalletSwapsResponse,
  type WalletTransfersResponse,
  type WalletSwap,
  type WalletTransfer,
} from "@/services/wallet/walletApi";
import type { TimePeriod } from "@/types/chart-filters.types";
import type { ActivityRow, ProfileActivityData } from "@/types/profile";
import { useLocalization } from "@/contexts/LocalizationContext";
import { useEffect, useState } from "react";

interface UseProfileActivityTabDataInput {
  walletAddresses: string[];
  period: TimePeriod;
}

interface UseProfileActivityTabDataResult {
  data: ProfileActivityData;
  loading: boolean;
  error: string | null;
}

const EMPTY_ACTIVITY_DATA: ProfileActivityData = {
  leftNavItems: [
    "swaps-table",
    "transfers-table",
    "wallet-overview-cards",
    "trade-frequency-heatmap",
  ],
  selectedNav: "swaps-table",
  swapTransferRows: [],
  swapsRaw: [],
  transfersRaw: [],
  walletCards: [],
  heatmap: { cells: [], maxCount: 0 },
};

function normalizePeriod(period: TimePeriod): WalletOverviewPeriodKey {
  if (
    period === "24H" ||
    period === "7D" ||
    period === "30D" ||
    period === "90D"
  ) {
    return period;
  }

  return "30D";
}

function formatSwapPair(swap: WalletSwap): string {
  const tokensInvolved =
    typeof swap.tokensInvolved === "string"
      ? swap.tokensInvolved
      : String(swap.tokensInvolved ?? "");
  return tokensInvolved.replace(/,/g, " → ");
}

function toAmountUsd(value: unknown): number {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : 0;
}

function toActivityRows(
  walletAddress: string,
  swaps: WalletSwap[],
  transfers: WalletTransfer[],
  formatAddressFn: (address: string) => string,
): ActivityRow[] {
  const swapRows = swaps.map((swap, index) => ({
    id: `${walletAddress}-swap-${index}-${swap.transactionHash}`,
    walletId: walletAddress,
    walletLabel: formatAddressFn(walletAddress),
    type: "swap" as const,
    pairOrToken: formatSwapPair(swap),
    amountUsd: toAmountUsd(swap.totalValueUsd),
    timestamp: swap.blockTimestampIso,

    soldToken: swap.sold?.symbol || swap.sold?.name || "Unknown",
    boughtToken: swap.bought?.symbol || swap.bought?.name || "Unknown",
    baseQuotePrice: toAmountUsd(swap.baseQuotePrice),
    txHash: swap.transactionHash,
  }));

  const transferRows = transfers.map((transfer, index) => ({
    id: `${walletAddress}-transfer-${index}-${transfer.transactionSignature}`,
    walletId: walletAddress,
    walletLabel: formatAddressFn(walletAddress),
    type: "transfer" as const,
    pairOrToken: transfer.tokenSymbol || transfer.tokenName || "Unknown",
    amountUsd: toAmountUsd(transfer.amountUsd ?? 0),
    timestamp: transfer.timestamp,
    fromAddress: transfer.from,
    toAddress: transfer.to,
    amount: transfer.amount,
    tokenSymbol: transfer.tokenSymbol || transfer.tokenName || "Unknown",
    signature: transfer.transactionSignature,
  }));

  return [...swapRows, ...transferRows].sort((left, right) =>
    right.timestamp.localeCompare(left.timestamp),
  );
}

export function useProfileActivityTabData({
  walletAddresses,
  period,
}: UseProfileActivityTabDataInput): UseProfileActivityTabDataResult {
  const { fmt } = useLocalization();
  const [data, setData] = useState<ProfileActivityData>(EMPTY_ACTIVITY_DATA);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let isActive = true;

    const load = async () => {
      if (walletAddresses.length === 0) {
        setData(EMPTY_ACTIVITY_DATA);
        setLoading(false);
        setError(null);
        return;
      }

      setLoading(true);
      setError(null);

      try {
        const periodKey = normalizePeriod(period);
        const results = await Promise.allSettled(
          walletAddresses.map(async (walletAddress) => {
            const [overview, swapsResult, transfersResult] = await Promise.all([
              fetchWalletOverview(walletAddress),
              fetchWalletSwaps(walletAddress),
              fetchWalletTransfers(walletAddress),
            ]);

            return { walletAddress, overview, swapsResult, transfersResult };
          }),
        );

        if (!isActive) {
          return;
        }

        const swapTransferRows: ActivityRow[] = [];
        const swapsRaw: WalletSwap[] = [];
        const transfersRaw: WalletTransfer[] = [];
        const walletCards = results
          .filter(
            (
              result,
            ): result is PromiseFulfilledResult<{
              walletAddress: string;
              overview: WalletOverviewMultiPeriodResponse;
              swapsResult: WalletSwapsResponse;
              transfersResult: WalletTransfersResponse;
            }> => result.status === "fulfilled",
          )
          .map((result) => {
            const { walletAddress, overview, swapsResult, transfersResult } =
              result.value;
            swapsRaw.push(...(swapsResult.swaps ?? []));
            transfersRaw.push(...(transfersResult.transfers ?? []));
            swapTransferRows.push(
              ...toActivityRows(
                walletAddress,
                swapsResult.swaps ?? [],
                transfersResult.transfers ?? [],
                (addr) => fmt.text.address(addr),
              ),
            );

            const stats =
              overview.periods[periodKey] ??
              overview.periods[overview.selectedPeriod];
            const totalAssetValueUsd =
              overview.totalAssetValueUsd ??
              overview.holdings.totalAssetValueUsd ??
              0;

            return {
              walletId: walletAddress,
              walletLabel: fmt.text.address(walletAddress),
              walletAddress,
              totalAssetValueUsd,
              unrealizedPnlInPeriodUsd: stats?.pnl?.unrealizedUsd ?? 0,
              tradingVolumeUsd: stats?.tradingVolumeUsd ?? 0,
              buyTradingVolumeUsd: stats?.buy.volumeUsd ?? 0,
              sellTradingVolumeUsd: stats?.sell.volumeUsd ?? 0,
              buyTransactionCount: stats?.buy.transactionCount ?? 0,
              sellTransactionCount: stats?.sell.transactionCount ?? 0,
              tokenAmountTraded: stats?.tokensTradedCount ?? 0,
              tokenAmountHolding:
                overview.tokensHoldingCount ??
                overview.holdings.tokensHoldingCount ??
                0,
              totalPnlUsd: stats?.pnl?.totalUsd ?? 0,
              realizedPnlUsd: stats?.pnl?.realizedUsd ?? 0,
              unrealizedPnlUsd: stats?.pnl?.unrealizedUsd ?? 0,
            };
          });

        swapTransferRows.sort((left, right) =>
          right.timestamp.localeCompare(left.timestamp),
        );

        setData({
          leftNavItems: [
            "swaps-table",
            "transfers-table",
            "wallet-overview-cards",
            "trade-frequency-heatmap",
          ],
          selectedNav: "swaps-table",
          swapTransferRows,
          swapsRaw,
          transfersRaw,
          walletCards,
          heatmap: { cells: [], maxCount: 0 },
        });
      } catch (loadError) {
        if (!isActive) {
          return;
        }

        setData(EMPTY_ACTIVITY_DATA);
        setError(
          loadError instanceof Error
            ? loadError.message
            : "Failed to load activity data",
        );
      } finally {
        if (isActive) {
          setLoading(false);
        }
      }
    };

    void load();

    return () => {
      isActive = false;
    };
  }, [period, walletAddresses]);

  return { data, loading, error };
}

import {
    fetchLinkedWallets,
    type LinkedWalletRowPayload,
} from "@/services/profile/profileDataProvider";
import { useEffect, useState } from "react";


export interface UseProfileSharedDataInput {
    setLoading: (loading: boolean) => void;
}

export interface ProfileSharedDataResult {
    walletAddresses: string[];
    linkedWallets: LinkedWalletRowPayload[];
    error: boolean;
}

export function useProfileSharedData({ setLoading }: UseProfileSharedDataInput): ProfileSharedDataResult {

    const [walletAddresses, setWalletAddresses] = useState<string[]>([]);
    const [linkedWallets, setLinkedWallets] = useState<LinkedWalletRowPayload[]>([]);
    const [error, setError] = useState(false);

    useEffect(() => {
        const load = async () => {
            setLoading(true);

            try {
                const wallets = await fetchLinkedWallets();
                setLinkedWallets(wallets);
                setWalletAddresses(wallets.map((wallet) => wallet.walletAddress));
            } catch {
                setError(true);
            } finally {
                setLoading(false);
            }
        };

        void load();
    }, []);

    return { walletAddresses, linkedWallets, error };
