import type {
    ClientRequestOptions,
    ClientResponse
} from "hono/client";
import useSWR from "swr";

type GetInput<T> =
  T extends { $get: (args: infer A, options?: ClientRequestOptions) => unknown }
    ? NonNullable<A>
    : {};
    
type HasRequiredKeys<T> = T extends object
  ? {
      [K in keyof T]-?: {} extends Pick<T, K> ? never : K;
    }[keyof T] extends never
    ? false
    : true
  : false;

type SuccessJson<R> = R extends { json: () => Promise<infer D> } ? D : never;

type ErrorResponse<R, S extends number> = R extends { status: infer U }
  ? U extends S
    ? never
    : R
  : never;

type SuccessResponse<R, S extends number> = R extends { status: S } ? R : never;

type UseGetConfig<Success, Transformed> = {
  options?: ClientRequestOptions;
  select?: (data: Success) => Transformed;
  enabled?: boolean;
};

export function useGet<
  T extends {
    $get: (...params: never[]) => Promise<ClientResponse<unknown, number, string>>;
    $url: (...params: never[]) => URL;
  },
  SuccessStatus extends number,
  Response = Awaited<ReturnType<T["$get"]>>,
  SuccessResponseType = SuccessResponse<Response, SuccessStatus>,
  Success = SuccessJson<SuccessResponseType>,
  Transformed = Success,
  Error = ErrorResponse<Response, SuccessStatus>,
>(
  request: T,
  successStatus: SuccessStatus,
  ...params: HasRequiredKeys<GetInput<T>> extends true
    ? [args: GetInput<T>, config?: UseGetConfig<Success, Transformed>]
    : [args?: GetInput<T>, config?: UseGetConfig<Success, Transformed>]
) : UseGetResp<NoInfer<Transformed>, Error>{
  const [args, config] = params;
  const { options, select, enabled = true } = config ?? {};
  type RequestArgs = GetInput<T> | undefined;
  const requestArgs = args as RequestArgs;
  const get = request.$get as (
    args: RequestArgs,
    options?: ClientRequestOptions,
  ) => Promise<ClientResponse<unknown, number, string>>;
  const url = request.$url as (args: RequestArgs) => URL;

  return useSWR<Transformed, Error>(
    enabled ? url(requestArgs).href : null,
    async () => {
      const res = await get(requestArgs, options);
      if (res.status != successStatus) {
        throw res;
      }

      const json = await res.json();

      return select ? select(json as Success) : (json as Transformed);
    },
    {
      revalidateOnFocus: false,
      // keepPreviousData: true,
      revalidateOnReconnect: false,
      // revalidateIfStale: false,
    },
  );
}

export type UseGetResp<Data, Error = unknown> = {
  isLoading: boolean;
  isValidating: boolean;
  data: Data | undefined;
  error: Error | undefined;
  mutate: () => void;
};

/**
 * useNewsFeed Hook
 * Manages news fetching with user-initiated loading, caching, and loading states
 */

import { useCallback, useState } from 'react';
import { getTokenNews } from '@/services/news';
import type { NewsArticle, TokenNewsQuery } from '@/types/news';

interface UseNewsFeedState {
    entries: NewsArticle[];
    isLoading: boolean;
    error: string | null;
    updatedAt: string | null;
    hasLoaded: boolean;
}

export function useNewsFeed(query: TokenNewsQuery) {
    const [state, setState] = useState<UseNewsFeedState>({
        entries: [],
        isLoading: false,
        error: null,
        updatedAt: null,
        hasLoaded: false,
    });

    const fetchNews = useCallback(async () => {
        setState((prev) => ({ ...prev, isLoading: true, error: null }));

        try {
            const result = await getTokenNews(query);
            setState({
                entries: result.entries || [],
                isLoading: false,
                error: null,
                updatedAt: result.updatedAt,
                hasLoaded: true,
            });
        } catch (err) {
            const message =
                err instanceof Error ? err.message : 'Failed to fetch news';
            setState((prev) => ({
                ...prev,
                isLoading: false,
                error: message,
                hasLoaded: true,
            }));
        }
    }, [query.address, query.symbol, query.name]);

    const refresh = useCallback(() => {
        fetchNews();
    }, [fetchNews]);

    return {
        ...state,
        fetchNews,
        refresh,
    };
}

import type { InferResponseType } from "hono/client";
import { useEffect, useState } from "react";
import client from "../api/main";

// Define backend API types
const $getChart = client.api.tokens.markets.chart[":address"].$get;
const $getMarket = client.api.tokens.markets[":addresses"].$get;
const $getMeta = client.api.tokens.meta[":addresses"].$get;
const $getHolders = client.api.tokens.holders[":address"].$get;
const $getTrades = client.api.tokens.pools.trades[":address"].$get;
const $getPools = client.api.tokens[":address"].pools.$get;
const $getHoldersStats = client.api.tokens.holders.stats[":addresses"].$get;

export type ChartData = InferResponseType<typeof $getChart, 200>;
export type MarketData =
  | InferResponseType<typeof $getMarket, 200>[number]
  | null;
export type MetaData = InferResponseType<typeof $getMeta, 200>[number] | null;
export type TopHoldersData = InferResponseType<typeof $getHolders, 200>;
export type TradesData = InferResponseType<typeof $getTrades, 200>;
export interface HoldersInfo {
  holders_count: number;
  top_10_percent: number;
}

export interface PoolData {
  name: string;
  address: string;
  source?: string; // e.g. "orca", "raydium"
  volume24h: number;
  volumeBuy24h?: number;
  volumeSell24h?: number;
  volumeNet24h?: number;
  priceQuoteToken?: number; // Price in quote token (e.g. SOL)
  quoteToken?: {
    symbol: string;
  };
  baseToken?: {
    name: string;
    symbol: string;
    address: string;
  };
  reserve: number;
  liquidity?: number;
  marketCap?: number;
  fdv?: number;
  priceUsd?: number;
  priceChange?: {
    m5: number;
    h1: number;
    h6: number;
    h24: number;
  };
  txns24h?: number;
  buys24h?: number;
  sells24h?: number;
  traders24h?: number;
  buyers24h?: number;
  sellers24h?: number;
}

export const useTokenPageData = (address: string | undefined) => {
  const [chartData, setChartData] = useState<ChartData>([]);
  const [marketData, setMarketData] = useState<MarketData>(null);
  const [metaData, setMetaData] = useState<MetaData>(null);
  const [poolsData, setPoolsData] = useState<PoolData[]>([]);
  const [topHolders, setTopHolders] = useState<TopHoldersData>([]);
  const [holdersInfo, setHoldersInfo] = useState<HoldersInfo | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!address) return;

    (async () => {
      setLoading(true);

      const fetchBackendData = async () => {
        try {
          const [chartResp, marketResp, metaResp, holdersResp, poolsResp, holdersStatsResp] =
            await Promise.all([
              $getChart({ param: { address } }),
              $getMarket({ param: { addresses: address } }),
              $getMeta({ param: { addresses: address } }),
              $getHolders({ param: { address } }),
              $getPools({ param: { address } }),
              $getHoldersStats({ param: { addresses: address } }),
            ]);

          if (chartResp.ok) setChartData(await chartResp.json());
          if (marketResp.ok) {
            const data = await marketResp.json();
            setMarketData(data[0]);
          }
          if (metaResp.ok) {
            const data = await metaResp.json();
            setMetaData(data[0]);
          }
          if (holdersResp.ok) {
            setTopHolders(await holdersResp.json());
          }
          if (poolsResp.ok) {
            const poolsData = await poolsResp.json();
            setPoolsData(
              poolsData.slice(0, 20).map((pool: any) => {
                const p = pool.data;
                return {
                  name: p.poolName || "Unknown Pool",
                  address: p.poolAddress || "",
                  source: p.dexId || "unknown",
                  volume24h: Number(p.volumeUsd24h || 0),
                  volumeBuy24h: Number(p.buyVolumeUsd24h || 0),
                  volumeSell24h: Number(p.sellVolumeUsd24h || 0),
                  reserve: Number(p.liquidityUsd || 0),
                  liquidity: Number(p.liquidityUsd || 0),
                  marketCap: Number(p.marketCapUsd || 0),
                  fdv: Number(p.fdvUsd || 0),
                  priceUsd: Number(p.baseTokenPriceUsd || 0),
                  priceQuoteToken: Number(p.quoteTokenPriceUsd || 0),
                  priceChange: {
                    m5: Number(p.priceChangePercentage5m || 0),
                    h1: Number(p.priceChangePercentage1h || 0),
                    h6: Number(p.priceChangePercentage6h || 0),
                    h24: Number(p.priceChangePercentage24h || 0),
                  },
                  txns24h: Number((p.buys24h || 0) + (p.sells24h || 0)),
                  buys24h: Number(p.buys24h || 0),
                  sells24h: Number(p.sells24h || 0),
                  traders24h: Number((p.buyers24h || 0) + (p.sellers24h || 0)),
                  buyers24h: Number(p.buyers24h || 0),
                  sellers24h: Number(p.sellers24h || 0),
                };
              }),
            );
          }
          if (holdersStatsResp.ok) {
            const statsData = await holdersStatsResp.json();
            if (statsData.length > 0) {
              setHoldersInfo({
                holders_count: statsData[0].holdersCount,
                top_10_percent: statsData[0].top10Percent,
              });
            }
          }
        } catch (error) {
          console.error("Failed to fetch backend data:", error);
        }
      };

      await fetchBackendData();

      setLoading(false);
    })();
  }, [address]);

  return {
    chartData,
    marketData,
    metaData,
    poolsData,
    topHolders,
    holdersInfo,
    loading,
  };
};

export const usePoolTrades = (
  network: string,
  poolAddress: string | undefined,
) => {
  const [trades, setTrades] = useState<TradesData>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!poolAddress || !network) return;

    (async () => {
      setLoading(true);
      try {
        const response = await $getTrades({
          param: { address: poolAddress },
        });
        if (response.ok) {
          setTrades(await response.json());
        }
      } catch (error) {
        console.error("Failed to fetch trades:", error);
      } finally {
        setLoading(false);
      }
    })();
  }, [network, poolAddress]);

  return { trades, loading };
};

// client/src/hooks/useTokenPageLogic.ts

import { useState, useEffect } from "react";
import { useNavigate } from "react-router";
import { useTokenPageData, usePoolTrades } from "./useTokenPageData";
import type { PoolData } from "./useTokenPageData";
import client from "@/api/main";

const $getPoolsDetails = client.api.tokens.pools[":addresses"].$get;

export const useTokenPageLogic = (
  address: string | undefined,
  poolAddress: string | undefined,
) => {
  const navigate = useNavigate();
  const {
    marketData: backendMarketData,
    metaData: backendMetaData,
    poolsData,
    topHolders,
    holdersInfo,
    loading: loadingData,
  } = useTokenPageData(address);

  // Fallback logic: If backend data is missing, try to use data from the top pool
  const hasBackendData = !!backendMarketData && !!backendMetaData;
  const fallbackPool = poolsData.length > 0 ? poolsData[0] : null;

  const marketData = hasBackendData
    ? backendMarketData
    : fallbackPool
      ? ({
          id: address || "unknown",
          symbol: fallbackPool.baseToken?.symbol || "Unknown",
          name: fallbackPool.baseToken?.name || "Unknown",
          image: "",
          currentPrice: fallbackPool.priceUsd || 0,
          marketCap: fallbackPool.marketCap || 0,
          marketCapRank: 0,
          fullyDilutedValuation: fallbackPool.fdv || 0,
          totalVolume: fallbackPool.volume24h || 0,
          high24h: 0,
          low24h: 0,
          priceChange24h: 0, // Absolute change not available in pool data
          priceChangePercentage1h: fallbackPool.priceChange?.h1 || 0,
          priceChangePercentage24h: fallbackPool.priceChange?.h24 || 0,
          priceChangePercentage7d: 0,
          circulatingSupply: 0,
          totalSupply: 0, // could estimate from FDV / Price if needed
          maxSupply: null,
          ath: 0,
          athChangePercentage: 0,
          athDate: "",
          atl: 0,
          atlChangePercentage: 0,
          atlDate: "",
          lastUpdated: new Date().toISOString(),
          // Add mapped fields for UI components that use camelCase or specific property names provided by the backend response
          priceUsd: fallbackPool.priceUsd || 0,
          // Ensure to matche the shape expected by MarketStats
        } as any)
      : null;

  const metaData = hasBackendData
    ? backendMetaData
    : fallbackPool
      ? ({
          address: address || "",
          symbol: fallbackPool.baseToken?.symbol || "Unknown",
          name: fallbackPool.baseToken?.name || "Unknown",
          imageUrl: null,
          description: "Data provided by On-chain Dex",
          coinGeckoId: null,
        } as any)
      : null;

  // 2. Local state for selected pool
  const [selectedPool, setSelectedPool] = useState<PoolData | null>(null);

  // 3. Auto-select logic
  useEffect(() => {
    // If URL has poolAddress, prioritize it!
    if (poolAddress) {
      // Check if it's already selected
      if (selectedPool?.address === poolAddress) return;

      // Try to find in loaded pools
      const found = poolsData.find((p) => p.address === poolAddress);
      if (found) {
        setSelectedPool(found);
        return;
      }

      // If not found in list, we MUST still select it to fetch details
      // Create a minimal placeholder
      setSelectedPool({
        address: poolAddress,
        name: "Loading...",
        volume24h: 0,
        reserve: 0,
        priceUsd: 0,
        priceChange: { m5: 0, h1: 0, h6: 0, h24: 0 },
      } as PoolData);
      return;
    }

    // Fallback to first pool if no selection or not found (and not already selected)
    if (poolsData.length > 0 && !selectedPool) {
      setSelectedPool(poolsData[0]);
    }
  }, [poolsData, poolAddress, selectedPool]);

  // 4. Fetch trades AND DETAILED STATS for selected pool
  const { trades } = usePoolTrades("solana", selectedPool?.address);

  // Fetch detailed stats (buy/sell volume) when pool is selected
  useEffect(() => {
    if (selectedPool?.address) {
      (async () => {
        try {
          const res = await $getPoolsDetails({
            param: { addresses: selectedPool.address },
            query: { refresh: "true" },
          });

          if (res.ok) {
            const pools = await res.json();
            if (pools.length > 0) {
              const p = pools[0];
              const detailedPool: PoolData = {
                name: p.poolName || "Unknown Pool",
                address: p.poolAddress || "",
                source: p.dexId || "unknown",
                volume24h: Number(p.volumeUsd24h || 0),
                volumeBuy24h: Number(p.buyVolumeUsd24h || 0),
                volumeSell24h: Number(p.sellVolumeUsd24h || 0),
                reserve: Number(p.liquidityUsd || 0),
                liquidity: Number(p.liquidityUsd || 0),
                marketCap: Number(p.marketCapUsd || 0),
                fdv: Number(p.fdvUsd || 0),
                priceUsd: Number(p.baseTokenPriceUsd || 0),
                priceQuoteToken: Number(p.quoteTokenPriceUsd || 0),
                priceChange: {
                  m5: Number(p.priceChangePercentage5m || 0),
                  h1: Number(p.priceChangePercentage1h || 0),
                  h6: Number(p.priceChangePercentage6h || 0),
                  h24: Number(p.priceChangePercentage24h || 0),
                },
                txns24h: Number((p.buys24h || 0) + (p.sells24h || 0)),
                buys24h: Number(p.buys24h || 0),
                sells24h: Number(p.sells24h || 0),
                traders24h: Number((p.buyers24h || 0) + (p.sellers24h || 0)),
                buyers24h: Number(p.buyers24h || 0),
                sellers24h: Number(p.sellers24h || 0),
              };

              setSelectedPool((prev) => ({ ...prev, ...detailedPool }));
            }
          }
        } catch (err) {
          console.error("Failed to fetch pool details", err);
        }
      })();
    }
  }, [selectedPool?.address]);

  // 5. Handlers
  const handlePoolChange = ({
    selectedItem,
  }: {
    selectedItem: PoolData | null;
  }) => {
    if (selectedItem) {
      setSelectedPool(selectedItem);
      // Update URL
      if (address) {
        navigate(`/tokens/${address}/${selectedItem.address}`);
      }
    }
  };

  return {
    // Data
    marketData,
    metaData,
    poolsData,
    topHolders,
    holdersInfo,
    selectedPool,
    trades,
    // Loading state
    loading: loadingData,
    // Actions
    handlePoolChange,
  };
};

