          followedTitle: "Followed wallets",
          followedDesc:
            "Quan ly danh sach vi Solana dang theo doi va giu Helius dong bo voi danh sach hien tai.",
          signInTitle: "Dang nhap de su dung Alert Center",
          signInDesc:
            "Ban can dang nhap de quan ly kenh nhan thong bao, tao quy tac canh bao va dong bo danh sach vi theo doi.",
          configured: "Configured",
          notConfigured: "Needs setup",
          enabled: "Enabled",
          disabled: "Disabled",
          ruleCreate: "Create alert rule",
        }
      : {
          eyebrow: "Alert Center",
          title: "Alert Center",
          subtitle:
            "Monitor wallets, token performance, and trading events from one place while keeping Discord, email, and webhook sync settings ready.",
          statWallets: "Followed wallets",
          statRules: "Active rules",
          statDelivery: "Delivery ready",
          featureWallets: "Wallet monitoring",
          featureTokens: "Token performance",
          featureTrading: "Trading events",
          discordDesc:
            "Send webhook alerts to Discord for fast operational monitoring of wallets and high-signal events.",
          emailDesc:
            "Control delivery to your registered email or an override inbox for demos and team workflows.",
          rulesTitle: "Active alert rules",
          rulesDesc:
            "Review live rules, expiration windows, and trigger logic without changing any server-side alert processing.",
          followedTitle: "Followed wallets",
          followedDesc:
            "Track Solana wallets, label them for triage, and keep Helius synced with the current list.",
          signInTitle: "Sign in to use Alert Center",
          signInDesc:
            "You need an account session to manage delivery channels, create alert rules, and sync followed wallets.",
          configured: "Configured",
          notConfigured: "Needs setup",
          enabled: "Enabled",
          disabled: "Disabled",
          ruleCreate: "Create alert rule",
        };

  // ── Settings state (Discord + email) ─────────────────────────
  const [discordUrl, setDiscordUrl] = useState("");
  const [discordLoading, setDiscordLoading] = useState(true);
  const [discordSaving, setDiscordSaving] = useState(false);
  const [discordInline, setDiscordInline] = useState<{
    kind: "success" | "error";
    title: string;
  } | null>(null);

  const [registeredEmail, setRegisteredEmail] = useState<string | null>(null);
  const [emailEnabled, setEmailEnabled] = useState(false);
  const [emailOverride, setEmailOverride] = useState("");
  const [emailSaving, setEmailSaving] = useState(false);
  const [emailInline, setEmailInline] = useState<{
    kind: "success" | "error" | "warning";
    title: string;
  } | null>(null);

  // ── Wallet list state ────────────────────────────────────────
  const [address, setAddress] = useState("");
  const [label, setLabel] = useState("");
  const [rows, setRows] = useState<FollowedWalletRow[]>([]);
  const [listLoading, setListLoading] = useState(true);
  const [listError, setListError] = useState<string | null>(null);
  const [submitting, setSubmitting] = useState(false);
  const [deletingId, setDeletingId] = useState<number | null>(null);
  const [inlineKind, setInlineKind] = useState<
    "success" | "error" | "warning" | null
  >(null);
  const [inlineTitle, setInlineTitle] = useState("");
  const [inlineSubtitle, setInlineSubtitle] = useState("");

  const [rulesRows, setRulesRows] = useState<AlertRuleApiRow[]>([]);
  const [rulesLoading, setRulesLoading] = useState(true);
  const [ruleModalOpen, setRuleModalOpen] = useState(false);
  const [deletingRuleId, setDeletingRuleId] = useState<number | null>(null);

  const hasDiscordConfigured = discordUrl.trim().length > 0;
  const hasEmailDestination = Boolean(emailOverride.trim() || registeredEmail);
  const deliveryReadyCount =
    Number(hasDiscordConfigured) + Number(hasEmailDestination);

  // ── Settings load/save ───────────────────────────────────────
  const loadSettings = useCallback(async () => {
    setDiscordLoading(true);
    try {
      const res = await (client.api.alerts as any).settings.$get();
      if (res.ok) {
        const data = (await res.json()) as AlertSettingsApiResponse;
        setDiscordUrl(data.discordWebhookUrl || "");
        setRegisteredEmail(data.registeredEmail);
        setEmailEnabled(Boolean(data.emailAlertsEnabled));
        setEmailOverride(data.emailAlertsAddress || "");
      }
    } catch {
      /* ignore */
    } finally {
      setDiscordLoading(false);
    }
  }, []);

  const onSaveDiscord = async (e: React.FormEvent) => {
    e.preventDefault();
    setDiscordInline(null);
    setDiscordSaving(true);
    try {
      const trimmed = discordUrl.trim();
      const res = await (client.api.alerts as any).settings.$patch({
        json: { discordWebhookUrl: trimmed || null },
      });
      if (res.ok) {
        const data = (await res.json()) as AlertSettingsApiResponse;
        setDiscordUrl(data.discordWebhookUrl || "");
        setRegisteredEmail(data.registeredEmail);
        setEmailEnabled(Boolean(data.emailAlertsEnabled));
        setEmailOverride(data.emailAlertsAddress || "");
        setDiscordInline({
          kind: "success",
          title: tr("alertsPage.discordSaved"),
        });
      } else {
        const body = (await res.json()) as { error?: string };
        setDiscordInline({
          kind: "error",
          title: body?.error || tr("alertsPage.discordSaveError"),
        });
        void loadSettings();
      }
    } catch {
      setDiscordInline({
        kind: "error",
        title: tr("alertsPage.discordSaveError"),
      });
      void loadSettings();
    } finally {
      setDiscordSaving(false);
    }
  };

  const onSaveEmail = async (e: React.FormEvent) => {
    e.preventDefault();
    setEmailInline(null);

    const overrideTrimmed = emailOverride.trim();
    const hasDestination = !!(overrideTrimmed || registeredEmail);

    if (emailEnabled && !hasDestination) {
      setEmailInline({
        kind: "warning",
        title: tr("alertsPage.emailNoDestination"),
      });
      return;
    }

    setEmailSaving(true);
    try {
      const res = await (client.api.alerts as any).settings.$patch({
        json: {
          emailAlertsEnabled: emailEnabled,
          emailAlertsAddress: overrideTrimmed || null,
        },
      });
      if (res.ok) {
        const data = (await res.json()) as AlertSettingsApiResponse;
        setDiscordUrl(data.discordWebhookUrl || "");
        setRegisteredEmail(data.registeredEmail);
        setEmailEnabled(Boolean(data.emailAlertsEnabled));
        setEmailOverride(data.emailAlertsAddress || "");
        setEmailInline({ kind: "success", title: tr("alertsPage.emailSaved") });
      } else {
        const body = (await res.json()) as { error?: string };
        setEmailInline({
          kind: "error",
          title: body?.error || tr("alertsPage.emailSaveError"),
        });
        void loadSettings();
      }
    } catch {
      setEmailInline({ kind: "error", title: tr("alertsPage.emailSaveError") });
      void loadSettings();
    } finally {
      setEmailSaving(false);
    }
  };

  // ── Wallet list load ─────────────────────────────────────────
  const loadList = useCallback(async () => {
    setListLoading(true);
    setListError(null);
    try {
      const res = await client.api.alerts.$get();
      if (!res.ok) throw new Error("list_failed");
      const data = (await res.json()) as FollowedWalletRow[];
      setRows(Array.isArray(data) ? data : []);
    } catch {
      setRows([]);
      setListError(tr("alertsPage.errorGeneric"));
    } finally {
      setListLoading(false);
    }
  }, [tr]);

  const loadRules = useCallback(async () => {
    setRulesLoading(true);
    try {
      const api = client.api.alerts as {
        rules: { $get: () => Promise<Response> };
      };
      const res = await api.rules.$get();
      if (!res.ok) throw new Error("rules_failed");
      const data = (await res.json()) as AlertRuleApiRow[];
      setRulesRows(Array.isArray(data) ? data : []);
    } catch {
      setRulesRows([]);
    } finally {
      setRulesLoading(false);
    }
  }, []);

  useEffect(() => {
    if (user) {
      void loadList();
      void loadSettings();
      void loadRules();
    } else {
      setListLoading(false);
      setDiscordLoading(false);
    }
  }, [user, loadList, loadSettings, loadRules]);

  // ── Wallet inline helpers ────────────────────────────────────
  const showInline = (
    kind: "success" | "error" | "warning",
    title: string,
    subtitle = "",
  ) => {
    setInlineKind(kind);
    setInlineTitle(title);
    setInlineSubtitle(subtitle);
  };

  const dismissInline = () => {
    setInlineKind(null);
    setInlineTitle("");
    setInlineSubtitle("");
  };

  // ── Wallet add ───────────────────────────────────────────────
  const onSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    dismissInline();
    const trimmed = address.trim();
    if (!isValidSolanaAddress(trimmed)) {
      showInline("error", tr("alertsPage.errorInvalidAddress"));
      return;
    }
    setSubmitting(true);
    try {
      const res = await client.api.alerts.$post({
        json: { address: trimmed, label: label.trim() || undefined },
      });
      const body = (await res.json()) as
        | PostAlertsResponse
        | { error?: string };

      if (res.status === 409) {
        showInline("warning", tr("alertsPage.errorDuplicate"));
        return;
      }
      if (!res.ok || !("wallet" in body)) {
        showInline(
          "error",
          "error" in body && typeof body.error === "string"
            ? body.error
            : tr("alertsPage.errorGeneric"),
        );
        return;
      }

      if (body.heliusSync.ok) {
        showInline(
          "success",
          tr("alertsPage.successHelius"),
          tr("alertsPage.successSaved"),
        );
      } else {
        showInline(
          "warning",
          tr("alertsPage.partialHelius"),
          body.heliusSync.error || "",
        );
      }

      setAddress("");
      setLabel("");
      await loadList();
    } catch {
      showInline("error", tr("alertsPage.errorGeneric"));
    } finally {
      setSubmitting(false);
    }
  };

  // ── Wallet delete ────────────────────────────────────────────
  const onDeleteRule = async (ruleId: number) => {
    dismissInline();
    setDeletingRuleId(ruleId);
    try {
      const res = await (client.api.alerts as any).rules[":ruleId"].$delete({
        param: { ruleId: String(ruleId) },
      });
      if (!res.ok) {
        showInline("error", tr("alertsPage.deleteFailed"));
        return;
      }
      showInline("success", tr("alertsPage.ruleDeleteSuccess"));
      await loadRules();
    } catch {
      showInline("error", tr("alertsPage.deleteFailed"));
    } finally {
      setDeletingRuleId(null);
    }
  };

  const onDelete = async (id: number) => {
    dismissInline();
    setDeletingId(id);
    try {
      const res = await (client.api.alerts as any)[":id"].$delete({
        param: { id: String(id) },
      });
      if (res.status === 404) {
        showInline("warning", tr("alertsPage.deleteNotFound"));
        await loadList();
        return;
      }
      if (!res.ok) {
        showInline("error", tr("alertsPage.deleteFailed"));
        return;
      }
      const body = (await res.json()) as DeleteAlertsResponse;
      if (body.heliusSync.ok) {
        showInline("success", tr("alertsPage.deleteSuccess"));
      } else {
        showInline(
          "warning",
          tr("alertsPage.deletePartial"),
          body.heliusSync.error || "",
        );
      }
      await loadList();
    } catch {
      showInline("error", tr("alertsPage.deleteFailed"));
    } finally {
      setDeletingId(null);
    }
  };

  // ── Render ───────────────────────────────────────────────────
  return (
    <PageWrapper noMarketTickers>
      <div className={styles.page}>
        <div className={styles.hero}>
          <div className={styles.heroEyebrow}>{ui.eyebrow}</div>
          <div className={styles.heroTop}>
            <div className={styles.heroCopy}>
              <h1 className={styles.title}>{ui.title}</h1>
              <p className={styles.subtitle}>{ui.subtitle}</p>
            </div>

            <div className={styles.heroStats}>
              <div className={styles.metricCard}>
                <span className={styles.metricValue}>
                  {user ? (listLoading ? "..." : String(rows.length)) : "--"}
                </span>
                <span className={styles.metricLabel}>{ui.statWallets}</span>
              </div>
              <div className={styles.metricCard}>
                <span className={styles.metricValue}>
                  {user ? (rulesLoading ? "..." : String(rulesRows.length)) : "--"}
                </span>
                <span className={styles.metricLabel}>{ui.statRules}</span>
              </div>
              <div className={styles.metricCard}>
                <span className={styles.metricValue}>
                  {user ? `${deliveryReadyCount}/2` : "--"}
                </span>
                <span className={styles.metricLabel}>{ui.statDelivery}</span>
              </div>
            </div>
          </div>

          <div className={styles.heroPills}>
            <span className={styles.heroPill}>{ui.featureWallets}</span>
            <span className={styles.heroPill}>{ui.featureTokens}</span>
            <span className={styles.heroPill}>{ui.featureTrading}</span>
          </div>
        </div>

        {!user ? (
          <section className={`${styles.panelCard} ${styles.signInCard}`}>
            <div className={styles.panelHeader}>
              <div className={styles.panelHeading}>
                <h2 className={styles.sectionTitle}>{ui.signInTitle}</h2>
                <p className={styles.sectionCopy}>{ui.signInDesc}</p>
              </div>
            </div>

            <div className={styles.emptyState}>
              <p className={styles.emptyStateTitle}>
                {tr("alertsPage.signInRequired")}
              </p>
            </div>
          </section>
        ) : (
          <>
            <div className={styles.settingsGrid}>
              <section className={styles.panelCard}>
                <div className={styles.panelHeader}>
                  <div className={styles.panelHeading}>
                    <h2 className={styles.sectionTitle}>
                      {tr("alertsPage.discordSectionTitle")}
                    </h2>
                    <p className={styles.sectionCopy}>{ui.discordDesc}</p>
                  </div>
                  <span
                    className={styles.statusPill}
                    data-tone={hasDiscordConfigured ? "success" : "muted"}
                  >
                    {hasDiscordConfigured ? ui.configured : ui.notConfigured}
                  </span>
                </div>

                <div className={styles.panelBody}>
                  {discordInline && (
                    <InlineNotification
                      kind={discordInline.kind}
                      title={discordInline.title}
                      onClose={() => setDiscordInline(null)}
                      lowContrast
                      className={styles.notice}
                    />
                  )}

                  {discordLoading ? (
                    <div className={styles.loadingRow}>
                      <InlineLoading description="Loading..." />
                    </div>
                  ) : (
                    <form onSubmit={onSaveDiscord}>
                      <div className={styles.discordRow}>
                        <TextInput
                          id="discord-webhook-url"
                          labelText={tr("alertsPage.discordLabel")}
                          placeholder={tr("alertsPage.discordPlaceholder")}
                          value={discordUrl}
                          onChange={(ev) => setDiscordUrl(ev.target.value)}
                          disabled={discordSaving}
                          autoComplete="off"
                        />
                        <div className={styles.formActions}>
                          {discordSaving ? <InlineLoading /> : null}
                          <Button
                            type="submit"
                            kind="primary"
                            disabled={discordSaving}
                          >
                            {tr("alertsPage.discordSaveButton")}
                          </Button>
                        </div>
                      </div>
                    </form>
                  )}
                </div>
              </section>

              <section className={styles.panelCard}>
                <div className={styles.panelHeader}>
                  <div className={styles.panelHeading}>
                    <h2 className={styles.sectionTitle}>
                      {tr("alertsPage.emailSectionTitle")}
                    </h2>
                    <p className={styles.sectionCopy}>{ui.emailDesc}</p>
                  </div>
                  <span
                    className={styles.statusPill}
                    data-tone={emailEnabled ? "success" : "muted"}
                  >
                    {emailEnabled ? ui.enabled : ui.disabled}
                  </span>
                </div>

                <div className={styles.panelBody}>
                  {emailInline && (
                    <InlineNotification
                      kind={emailInline.kind}
                      title={emailInline.title}
                      onClose={() => setEmailInline(null)}
                      lowContrast
                      className={styles.notice}
                    />
                  )}

                  {discordLoading ? (
                    <div className={styles.loadingRow}>
                      <InlineLoading description="Loading..." />
                    </div>
                  ) : (
                    <form onSubmit={onSaveEmail}>
                      <div className={styles.toggleRow}>
                        <Toggle
                          id="email-alerts-enabled"
                          labelText={tr("alertsPage.emailToggleLabel")}
                          labelA="Off"
                          labelB="On"
                          toggled={emailEnabled}
                          onToggle={(checked: boolean) =>
                            setEmailEnabled(checked)
                          }
                          disabled={emailSaving}
                        />
                      </div>

                      <p className={styles.fieldHint}>
                        {registeredEmail
                          ? tr("alertsPage.emailRegisteredHint", {
                              email: registeredEmail,
                            })
                          : tr("alertsPage.emailNoRegistered")}
                      </p>

                      <div className={styles.discordRow}>
                        <TextInput
                          id="email-override"
                          type="email"
                          labelText={tr("alertsPage.emailOverrideLabel")}
                          placeholder={tr(
                            "alertsPage.emailOverridePlaceholder",
                          )}
                          value={emailOverride}
                          onChange={(ev) => setEmailOverride(ev.target.value)}
                          disabled={emailSaving}
                          autoComplete="off"
                        />
                        <div className={styles.formActions}>
                          {emailSaving ? <InlineLoading /> : null}
                          <Button
                            type="submit"
                            kind="primary"
                            disabled={emailSaving}
                          >
                            {tr("alertsPage.emailSaveButton")}
                          </Button>
                        </div>
                      </div>
                    </form>
                  )}
                </div>
              </section>
            </div>

            <section className={styles.panelCard}>
              <div className={styles.panelHeader}>
                <div className={styles.panelHeading}>
                  <h3 className={styles.sectionTitle}>{ui.rulesTitle}</h3>
                  <p className={styles.sectionCopy}>{ui.rulesDesc}</p>
                </div>

                <div className={styles.panelHeaderActions}>
                  <span className={styles.countPill}>
                    {rulesLoading ? "..." : rulesRows.length}
                  </span>
                  <Button
                    kind="tertiary"
                    onClick={() => setRuleModalOpen(true)}
                  >
                    {ui.ruleCreate}
                  </Button>
                </div>
              </div>

              <div className={styles.panelBody}>
                {rulesLoading ? (
                  <div className={styles.loadingRow}>
                    <InlineLoading description={tr("alertsPage.ruleLoading")} />
                  </div>
                ) : rulesRows.length === 0 ? (
                  <div className={styles.emptyState}>
                    <p className={styles.emptyStateTitle}>
                      {tr("alertsPage.ruleTableEmpty")}
                    </p>
                  </div>
                ) : (
                  <div className={styles.tableWrap}>
                    <Table size="md" useZebraStyles>
                      <TableHead>
                        <TableRow>
                          <TableHeader>
                            {tr("alertsPage.ruleTableName")}
                          </TableHeader>
                          <TableHeader>
                            {tr("alertsPage.ruleTableWallet")}
                          </TableHeader>
                          <TableHeader>
                            {tr("alertsPage.ruleTableAction")}
                          </TableHeader>
                          <TableHeader>
                            {tr("alertsPage.ruleTableVolume")}
                          </TableHeader>
                          <TableHeader>
                            {tr("alertsPage.ruleTableTrigger")}
                          </TableHeader>
                          <TableHeader>
                            {tr("alertsPage.ruleTableExpires")}
                          </TableHeader>
                          <TableHeader className={styles.actionsCell}>
                            {tr("alertsPage.tableActions")}
                          </TableHeader>
                        </TableRow>
                      </TableHead>
                      <TableBody>
                        {rulesRows.map((r) => {
                          const min = Number(r.minVolume);
                          const max =
                            r.maxVolume != null && r.maxVolume !== ""
                              ? Number(r.maxVolume)
                              : null;
                          const volLabel =
                            max != null && Number.isFinite(max)
                              ? `${min} - ${max} ${r.volumeUnit}`
                              : `${min}+ ${r.volumeUnit}`;
                          return (
                            <TableRow key={r.id}>
                              <TableCell>
                                <span className={styles.primaryCell}>
                                  {r.name?.trim() || "-"}
                                </span>
                              </TableCell>
                              <TableCell>
                                <span className={styles.addressValue}>
                                  {r.walletAddress}
                                </span>
                              </TableCell>
                              <TableCell>
                                <span
                                  className={styles.tableTag}
                                  data-tone="primary"
                                >
                                  {r.actionType}
                                </span>
                              </TableCell>
                              <TableCell>{volLabel}</TableCell>
                              <TableCell>
                                <span
                                  className={styles.tableTag}
                                  data-tone="accent"
                                >
                                  {r.triggerType}
                                </span>
                              </TableCell>
                              <TableCell>
                                {fmt.datetime.datetime(
                                  new Date(r.expiryDate),
                                )}
                              </TableCell>
                              <TableCell className={styles.actionsCell}>
                                {deletingRuleId === r.id ? (
                                  <InlineLoading />
                                ) : (
                                  <Button
                                    kind="ghost"
                                    size="sm"
                                    hasIconOnly
                                    iconDescription="Delete rule"
                                    renderIcon={TrashCan}
                                    className={styles.iconAction}
                                    disabled={deletingRuleId !== null}
                                    onClick={() => void onDeleteRule(r.id)}
                                  />
                                )}
                              </TableCell>
                            </TableRow>
                          );
                        })}
                      </TableBody>
                    </Table>
                  </div>
                )}
              </div>
            </section>

            <section className={styles.panelCard}>
              <div className={styles.panelHeader}>
                <div className={styles.panelHeading}>
                  <h3 className={styles.sectionTitle}>{ui.followedTitle}</h3>
                  <p className={styles.sectionCopy}>{ui.followedDesc}</p>
                </div>
                <span className={styles.countPill}>
                  {listLoading ? "..." : rows.length}
                </span>
              </div>

              <div className={styles.panelBody}>
                {inlineKind && (
                  <InlineNotification
                    kind={inlineKind}
                    title={inlineTitle}
                    subtitle={inlineSubtitle}
                    onClose={dismissInline}
                    lowContrast
                    className={styles.notice}
                  />
                )}

                <form onSubmit={onSubmit}>
                  <div className={styles.formRow}>
                    <TextInput
                      id="follow-address"
                      labelText={tr("alertsPage.addressLabel")}
                      placeholder={tr("alertsPage.addressPlaceholder")}
                      value={address}
                      onChange={(ev) => setAddress(ev.target.value)}
                      disabled={submitting}
                      autoComplete="off"
                    />
                    <TextInput
                      id="follow-label"
                      labelText={tr("alertsPage.labelOptional")}
                      placeholder={tr("alertsPage.labelPlaceholder")}
                      value={label}
                      onChange={(ev) => setLabel(ev.target.value)}
                      disabled={submitting}
                      autoComplete="off"
                    />
                    <div className={styles.formActions}>
                      {submitting ? (
                        <InlineLoading
                          description={tr("alertsPage.followButton")}
                        />
                      ) : null}
                      <Button
                        type="submit"
                        kind="primary"
                        disabled={submitting}
                      >
                        {tr("alertsPage.followButton")}
                      </Button>
                    </div>
                  </div>
                </form>

                {listError ? (
                  <InlineNotification
                    kind="error"
                    title={listError}
                    lowContrast
                    onClose={() => setListError(null)}
                    className={styles.notice}
                  />
                ) : null}

                {listLoading ? (
                  <div className={styles.loadingRow}>
                    <InlineLoading description={tr("alertsPage.loadingList")} />
                  </div>
                ) : rows.length === 0 ? (
                  <div className={styles.emptyState}>
                    <p className={styles.emptyStateTitle}>
                      {tr("alertsPage.emptyList")}
                    </p>
                  </div>
                ) : (
                  <div className={styles.tableWrap}>
                    <Table size="md" useZebraStyles>
                      <TableHead>
                        <TableRow>
                          <TableHeader>
                            {tr("alertsPage.tableAddress")}
                          </TableHeader>
                          <TableHeader>
                            {tr("alertsPage.tableLabel")}
                          </TableHeader>
                          <TableHeader>
                            {tr("alertsPage.tableAdded")}
                          </TableHeader>
                          <TableHeader className={styles.actionsCell}>
                            {tr("alertsPage.tableActions")}
                          </TableHeader>
                        </TableRow>
                      </TableHead>
                      <TableBody>
                        {rows.map((row) => (
                          <TableRow key={row.id}>
                            <TableCell>
                              <span className={styles.addressValue}>
                                {row.address}
                              </span>
                            </TableCell>
                            <TableCell>
                              {row.label ? (
                                <span className={styles.labelPill}>
                                  {row.label}
                                </span>
                              ) : (
                                <span className={styles.mutedValue}>-</span>
                              )}
                            </TableCell>
                            <TableCell>
                              {fmt.datetime.datetime(new Date(row.createdAt))}
                            </TableCell>
                            <TableCell className={styles.actionsCell}>
                              {deletingId === row.id ? (
                                <InlineLoading />
                              ) : (
                                <Button
                                  kind="ghost"
                                  size="sm"
                                  hasIconOnly
                                  iconDescription="Delete"
                                  renderIcon={TrashCan}
                                  className={styles.iconAction}
                                  disabled={deletingId !== null}
                                  onClick={() => onDelete(row.id)}
                                />
                              )}
                            </TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </div>
                )}
              </div>
            </section>
          </>
        )}
      </div>

      <CreateAlertRuleModal
        open={ruleModalOpen}
        onClose={() => setRuleModalOpen(false)}
        onSaved={() => {
          void loadRules();
          showInline("success", tr("alertsPage.ruleCreateSuccess"));
        }}
      />
    </PageWrapper>
  );

}

import client from "@/api/main";
import { ProfitableTradersView } from "@/components/market/ProfitableTradersView";
import {
    DexTable,
    INITIAL_FILTERS,
    SortKey,
    TableFilters,
} from "@/components/market/DexTable";
import { Txt } from "@/components/Txt";
import { PageWrapper } from "@/components/wrapper";
import { useLocalization } from "@/contexts/LocalizationContext";
import { useGet } from "@/hooks/useGet";
import overwriteStyles from "@/styles/_overwrite.module.scss";
import {
    ArrowUp,
    ChartBar,
    Checkmark,
    ChevronDown,
    Close,
    Growth,
    SettingsAdjust,
    Star,
    Trophy,
} from "@carbon/icons-react";
import { Column, Grid, Section, Stack } from "@carbon/react";
import classNames from "classnames";
import { useEffect, useMemo, useRef, useState } from "react";
import styles from "./index.module.scss";

type PoolMainTab =
  | "trending"
  | "top"
  | "gainers"
  | "newPairs"
  | "profitableTraders";
type PoolDuration = "5m" | "1h" | "6h" | "24h";
type TopSort = "volume" | "txns";
type TraderType = "today" | "1W" | "30d" | "90d";

const MAIN_TABS: Array<{ key: PoolMainTab }> = [
  { key: "trending" },
  { key: "top" },
  { key: "gainers" },
  { key: "newPairs" },
  { key: "profitableTraders" },
];

const TRADER_PERIODS: TraderType[] = ["today", "1W", "30d", "90d"];
const POOL_DURATIONS: PoolDuration[] = ["5m", "1h", "6h", "24h"];
const TOP_SORTS: TopSort[] = ["volume", "txns"];

function traderPeriodLabel(period: TraderType) {
  switch (period) {
    case "today":
      return "1D";
    case "1W":
      return "7D";
    case "30d":
      return "30D";
    case "90d":
      return "90D";
  }
}

export default function MarketPage() {
  const { tr } = useLocalization();
  const [activeTabIndex, setActiveTabIndex] = useState(0);
  const [trendingDuration, setTrendingDuration] =
    useState<PoolDuration>("5m");
  const [topSort, setTopSort] = useState<TopSort>("volume");
  const [traderType, setTraderType] = useState<TraderType>("1W");

  const [sortKey, setSortKey] = useState<SortKey>("5m");
  const [sortDirection, setSortDirection] = useState<"asc" | "desc">("desc");
  const [filters, setFilters] = useState<TableFilters>(INITIAL_FILTERS);
  const [tempFilters, setTempFilters] =
    useState<TableFilters>(INITIAL_FILTERS);

  const [isRankOpen, setIsRankOpen] = useState(false);
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  const activeTab = MAIN_TABS[activeTabIndex]?.key ?? "trending";

  const rankRef = useRef<HTMLDivElement>(null);
  const filterRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (rankRef.current && !rankRef.current.contains(event.target as Node)) {
        setIsRankOpen(false);
      }
      if (
        filterRef.current &&
        !filterRef.current.contains(event.target as Node)
      ) {
        setIsFilterOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    if (activeTab === "gainers" || activeTab === "trending") {
      setSortKey(trendingDuration as SortKey);
      setSortDirection("desc");
    }
  }, [trendingDuration, activeTab]);

  const getTabLabel = (tab: PoolMainTab) => {
    switch (tab) {
      case "trending":
        return tr("marketPage.trending");
      case "top":
        return tr("marketPage.top");
      case "gainers":
        return tr("marketPage.topGainers");
      case "newPairs":
        return tr("marketPage.newPairs");
      case "profitableTraders":
        return tr("marketPage.profitableTraders");
    }
  };

  const handleSort = (key: SortKey) => {
    if (sortKey === key) {
      setSortDirection((prev) => (prev === "desc" ? "asc" : "desc"));
    } else {
      setSortKey(key);
      setSortDirection("desc");
    }

    if (["5m", "1h", "6h", "24h"].includes(key)) {
      setTrendingDuration(key as PoolDuration);
    }
    if (["volume", "txns"].includes(key)) {
      setTopSort(key as TopSort);
    }
  };

  const handleApplyFilters = () => {
    setFilters(tempFilters);
    setIsFilterOpen(false);
  };

  const handleResetFilters = () => {
    setFilters(INITIAL_FILTERS);
    setTempFilters(INITIAL_FILTERS);
  };

  const updateTempFilter = (
    key: keyof TableFilters,
    field: "min" | "max",
    val: string,
  ) => {
    setTempFilters((prev) => ({
      ...prev,
      [key]: { ...prev[key], [field]: val },
    }));
  };

  const sortOptions: Array<{ key: SortKey; label: string }> = [
    { key: "5m", label: tr("marketPage.trending5m") },
    { key: "1h", label: tr("marketPage.trending1h") },
    { key: "6h", label: tr("marketPage.trending6h") },
    { key: "24h", label: tr("marketPage.trending24h") },
    { key: "txns", label: tr("marketPage.txns") },
    { key: "volume", label: tr("marketPage.volume") },
    { key: "marketCap", label: tr("marketPage.marketCap") },
    { key: "price", label: tr("marketPage.price") },
    { key: "liquidity", label: tr("marketPage.liquidity") },
    { key: "age", label: tr("marketPage.pairAge") },
  ];

  const filterOptions: Array<{
    label: string;
    key: keyof TableFilters;
    unit: string;
  }> = [
    { label: tr("marketPage.liquidity"), key: "liquidity", unit: "$" },
    { label: tr("marketPage.marketCap"), key: "mcap", unit: "$" },
    { label: tr("marketPage.volume24h"), key: "volume", unit: "$" },
    { label: tr("marketPage.txns24h"), key: "txns", unit: "" },
    { label: tr("marketPage.pairAgeHours"), key: "age", unit: "" },
    { label: tr("marketPage.change24h"), key: "change24h", unit: "%" },
  ];


  const trendingPools = useGet(
    client.api.tokens["market-pools"].trending,
    200,
    { query: { duration: trendingDuration } },
  );

  const topPools = useGet(client.api.tokens["market-pools"].top, 200, {
    query: { sortBy: topSort },
  });

  const topGainerPools = useGet(client.api.tokens["market-pools"].gainers, 200);
  const newPairs = useGet(client.api.tokens["market-pools"]["new-pairs"], 200);

  const headings = useMemo(() => {
    switch (activeTab) {
      case "trending":
        return {
          title: tr("marketPage.trendingPools"),
          subtitle: tr("marketPage.trendingPoolsSubtitle"),
        };
      case "top":
        return {
          title: tr("marketPage.topPools"),
          subtitle: tr("marketPage.topPoolsSubtitle"),
        };
      case "gainers":
        return {
          title: tr("marketPage.topGainerPools"),
          subtitle: tr("marketPage.topGainerPoolsSubtitle"),
        };
      case "newPairs":
        return {
          title: tr("marketPage.newPairs"),
          subtitle: tr("marketPage.newPairsSubtitle"),
        };
      case "profitableTraders":
        return {
          title: tr("marketPage.profitableTraders"),
          subtitle: tr("marketPage.profitableTradersPoolsSubtitle"),
        };
      default:
        return {
          title: tr("marketPage.marketPools"),
          subtitle: tr("marketPage.marketPoolsSubtitle"),
        };
    }
  }, [activeTab, tr]);

  const dataToRender = useMemo(() => {
    switch (activeTab) {
      case "trending":
        return trendingPools.data;
      case "top":
        return topPools.data;
      case "gainers":
        return topGainerPools.data;
      case "newPairs":
        return newPairs.data;
      default:
        return [];
    }
  }, [
    activeTab,
    trendingPools.data,
    topPools.data,
    topGainerPools.data,
    newPairs.data,
  ]);

  const currentSortLabel =
    sortOptions.find((option) => option.key === sortKey)?.label ?? "";

  return (
    <PageWrapper>
      <Section className={styles.marketPage}>
        <Grid className={overwriteStyles.wdGrd}>
          <Column sm={2} md={8} lg={16}>
            <Stack className={styles.marketStack} gap={4}>
              <header className={styles.marketHero}>
                <div className={styles.radarEyebrow}>
                  <span className={styles.radarPulse} aria-hidden="true" />
                  Market Radar
                </div>
                <Txt block bold className={styles.marketTitle} size="lg">
                  {headings.title}
                </Txt>
                <Txt block className={styles.marketSubtitle}>
                  {headings.subtitle}
                </Txt>
              </header>

              <div className={styles.dexBar}>
                {MAIN_TABS.map((tab) => {
                  const isActive = activeTab === tab.key;

                  if (isActive) {
                    const hasSubfilters =
                      tab.key === "trending" ||
                      tab.key === "top" ||
                      tab.key === "gainers" ||
                      tab.key === "profitableTraders";

                    return (
                      <div
                        key={tab.key}
                        className={`${styles.activeTabContainer} ${
                          !hasSubfilters ? styles.noSubfilters : ""
                        }`}
                      >
                        <span className={styles.activeTabText}>
                          {tab.key === "trending" && <Growth size={16} />}
                          {tab.key === "top" && <ChartBar size={16} />}
                          {tab.key === "gainers" && <ArrowUp size={16} />}
                          {tab.key === "newPairs" && <Star size={16} />}
                          {tab.key === "profitableTraders" && (
                            <Trophy size={16} />
                          )}
                          {getTabLabel(tab.key)}
                        </span>

                        {tab.key === "profitableTraders" && (
                          <div className={styles.inlineFilters}>
                            {TRADER_PERIODS.map((period) => (
                              <button
                                key={period}
                                className={`${styles.inlineFilterBtn} ${
                                  traderType === period ? styles.active : ""
                                }`}
                                onClick={() => setTraderType(period)}
                              >
                                {traderPeriodLabel(period)}
                              </button>
                            ))}
                          </div>
                        )}

                        {(tab.key === "trending" || tab.key === "gainers") && (
                          <div className={styles.inlineFilters}>
                            {POOL_DURATIONS.map((duration) => (
                              <button
                                key={duration}
                                className={`${styles.inlineFilterBtn} ${
                                  trendingDuration === duration
                                    ? styles.active
                                    : ""
                                }`}
                                onClick={() => {
                                  setTrendingDuration(duration);
                                  setSortKey(duration);
                                  setSortDirection("desc");
                                }}
                              >
                                {duration}
                              </button>
                            ))}
                          </div>
                        )}

                        {tab.key === "top" && (
                          <div className={styles.inlineFilters}>
                            {TOP_SORTS.map((sort) => (
                              <button
                                key={sort}
                                className={`${styles.inlineFilterBtn} ${
                                  topSort === sort ? styles.active : ""
                                }`}
                                onClick={() => {
                                  setTopSort(sort);
                                  setSortKey(sort);
                                  setSortDirection("desc");
                                }}
                              >
                                {sort === "volume"
                                  ? tr("marketPage.volume")
                                  : tr("marketPage.txns")}
                              </button>
                            ))}
                          </div>
                        )}
                      </div>
                    );
                  }

                  return (
                    <button
                      key={tab.key}
                      className={styles.tabBtn}
                      onClick={() => {
                        const newIndex = MAIN_TABS.findIndex(
                          (candidate) => candidate.key === tab.key,
                        );
                        setActiveTabIndex(newIndex);

                        if (tab.key === "gainers" || tab.key === "trending") {
                          setSortKey(trendingDuration as SortKey);
                          setSortDirection("desc");
                        } else if (tab.key === "top") {
                          setSortKey(topSort as SortKey);
                          setSortDirection("desc");
                        } else if (tab.key === "newPairs") {
                          setSortKey("age");
                          setSortDirection("desc");
                        }
                      }}
                    >
                      {getTabLabel(tab.key)}
                    </button>
                  );
                })}

                <div className={styles.toolbarWrapper}>
                  {activeTab !== "profitableTraders" && (
                    <>
                      <div className={styles.rankContainer} ref={rankRef}>
                        <button
                          className={classNames(styles.toolbarBtn, {
                            [styles.active]: isRankOpen,
                          })}
                          onClick={() => setIsRankOpen(!isRankOpen)}
                        >
                          <Trophy size={16} />
                          <span>
                            {tr("marketPage.rankBy")}:{" "}
                            {`${
                              sortDirection === "desc" ? "↓" : "↑"
                            } ${currentSortLabel}`}
                          </span>
                          <ChevronDown size={16} />
                        </button>

                        {isRankOpen && (
                          <div className={styles.dropdown}>
                            <div className={styles.dropdownSection}>
                              <div className={styles.sectionTitle}>
                                {tr("marketPage.order")}
                              </div>
                              <div
                                className={styles.option}
                                onClick={() => {
                                  setSortDirection("desc");
                                  setIsRankOpen(false);
                                }}
                              >
                                {sortDirection === "desc" && (
                                  <Checkmark size={14} />
                                )}
                                <span>{tr("marketPage.descending")}</span>
                              </div>
                              <div
                                className={styles.option}
                                onClick={() => {
                                  setSortDirection("asc");
                                  setIsRankOpen(false);
                                }}
                              >
                                {sortDirection === "asc" && (
                                  <Checkmark size={14} />
                                )}
                                <span>{tr("marketPage.ascending")}</span>
                              </div>
                            </div>
                            <div className={styles.dropdownSection}>
                              <div className={styles.sectionTitle}>
                                {tr("marketPage.rankBy")}
                              </div>
                              {sortOptions.map((option) => (
                                <div
                                  key={option.key}
                                  className={styles.option}
                                  onClick={() => {
                                    handleSort(option.key);
                                    setIsRankOpen(false);
                                  }}
                                >
                                  {sortKey === option.key && (
                                    <Checkmark size={14} />
                                  )}
                                  <span>{option.label}</span>
                                </div>
                              ))}
                            </div>
                          </div>
                        )}
                      </div>

                      <div className={styles.filterContainer} ref={filterRef}>
                        <button
                          className={classNames(styles.toolbarBtn, {
                            [styles.active]: isFilterOpen,
                          })}
                          onClick={() => {
                            setIsFilterOpen(!isFilterOpen);
                            setTempFilters(filters);
                          }}
                        >
                          <SettingsAdjust size={16} />
                          <span>{tr("marketPage.filters")}</span>
                        </button>

                        {isFilterOpen && (
                          <div className={styles.filterPopup}>
                            <div className={styles.popupHeader}>
                              <span>{tr("marketPage.customizeFilters")}</span>
                              <Close
                                size={20}
                                className={styles.closeIcon}
                                onClick={() => setIsFilterOpen(false)}
                              />
                            </div>
                            <div className={styles.popupContent}>
                              {filterOptions.map((filter) => (
                                <div
                                  key={filter.key}
                                  className={styles.filterRow}
                                >
                                  <label>{filter.label}:</label>
                                  <div className={styles.inputGroup}>
                                    <div className={styles.inputWithUnit}>
                                      {filter.unit && (
                                        <span className={styles.unit}>
                                          {filter.unit}
                                        </span>
                                      )}
                                      <input
                                        type="number"
                                        placeholder={tr("marketPage.min")}
                                        value={tempFilters[filter.key].min || ""}
                                        onChange={(event) =>
                                          updateTempFilter(
                                            filter.key,
                                            "min",
                                            event.target.value,
                                          )
                                        }
                                      />
                                    </div>
                                    <div className={styles.inputWithUnit}>
                                      {filter.unit && (
                                        <span className={styles.unit}>
                                          {filter.unit}
                                        </span>
                                      )}
                                      <input
                                        type="number"
                                        placeholder={tr("marketPage.max")}
                                        value={tempFilters[filter.key].max || ""}
                                        onChange={(event) =>
                                          updateTempFilter(
                                            filter.key,
                                            "max",
                                            event.target.value,
                                          )
                                        }
                                      />
                                    </div>
                                  </div>
                                </div>
                              ))}
                            </div>
                            <div className={styles.popupFooter}>
                              <button
                                className={styles.resetBtn}
                                onClick={handleResetFilters}
                              >
                                {tr("marketPage.reset")}
                              </button>
                              <button
                                className={styles.applyBtn}
                                onClick={handleApplyFilters}
                              >
                                {tr("marketPage.apply")}
                              </button>
                            </div>
                          </div>
                        )}
                      </div>
                    </>
                  )}
                </div>
              </div>

              <Section className={styles.tableSection}>
                {activeTab === "profitableTraders" ? (
                  <ProfitableTradersView traderType={traderType} />
                ) : (
                  <DexTable
                    loading={
                      trendingPools.isLoading ||
                      trendingPools.isValidating ||
                      topPools.isLoading ||
                      topPools.isValidating ||
                      newPairs.isLoading
                    }
                    data={dataToRender as any}
                    sortKey={sortKey}
                    sortDirection={sortDirection}
                    filters={filters}
                    onSort={handleSort}
                  />
                )}
              </Section>
            </Stack>
          </Column>
        </Grid>
      </Section>
    </PageWrapper>
  );
}

import ProfileActivityTab from "@/components/profile/activity/ProfileActivityTab";
import ProfileAlertTab from "@/components/profile/alerts/ProfileAlertTab";
import ProfileDashboardTab from "@/components/profile/dashboard/ProfileDashboardTab";
import ProfilePortfolioTab from "@/components/profile/portfolio/ProfilePortfolioTab";
import { ProfileSubscriptionsTab } from "@/components/profile/ProfileSubscriptionsTab";
import ProfileUnavailableState from "@/components/profile/shared/ProfileUnavailableState";
import ProfileLoadingState from "@/components/profile/shared/ProfileLoadingState";
import ProfileWalletTab from "@/components/profile/wallets/ProfileWalletTab";
import ProfileWatchlistTab from "@/components/profile/watchlist/ProfileWatchlistTab";
import {
    PROFILE_TABS,
    type ProfileTabId,
} from "@/components/profile/shared/profile.constants";
import ProfileSettingsTab from "@/components/profile/settings";
import TabContainer from "@/components/tabContainer/tabContainer";
import { PageWrapper } from "@/components/wrapper";
import { useProfilePageData } from "@/hooks/profile/useProfilePageData";
import { useProfileSharedData } from "@/hooks/profile/useProfileSharedData";
import styles from "./index.module.scss";
import type { TimePeriod } from "@/types/chart-filters.types";
import {
    Activity,
    ChartLine,
    Notification,
    Receipt,
    Settings,
    StarFilled,
    User,
    Wallet,
} from "@carbon/react/icons";
import { ReactNode, useEffect, useMemo, useState } from "react";

export default function ProfilePage() {
  const [period, setPeriod] = useState<TimePeriod>("30D");
  const [activeTab, setActiveTab] = useState(0);
  const { data: profileData, loading: profileLoading } = useProfilePageData({
    period,
  });
  const [loading, setLoading] = useState(false);
  const { walletAddresses, linkedWallets } = useProfileSharedData({
    setLoading,
  });

  const tabsConfig = useMemo(() => {
    const allTabs: Array<{ id: ProfileTabId; node: ReactNode }> = [
      {
        id: "overview",
        node: (
          <ProfilePortfolioTab
            linkedWallets={linkedWallets}
            period={period}
            onPeriodChange={setPeriod}
          />
        ),
      },
      {
        id: "dashboard",
        node: <ProfileDashboardTab walletAddresses={walletAddresses} />,
      },
      {
        id: "alerts",
        node: profileData ? (
          <ProfileAlertTab data={profileData.alerts} />
        ) : (
          <ProfileUnavailableState
            title="Alerts unavailable"
            description="No alert data is available right now."
          />
        ),
      },
      {
        id: "wallets",
        node: (
          <ProfileWalletTab walletAddresses={walletAddresses} period={period} />
        ),
      },
      {
        id: "watchlist",
        node: <ProfileWatchlistTab />,
      },
      {
        id: "activity",
        node: (
          <ProfileActivityTab
            walletAddresses={walletAddresses}
            period={period}
          />
        ),
      },
      {
        id: "subscriptions",
        node: <ProfileSubscriptionsTab />,
      },
      {
        id: "settings",
        node: <ProfileSettingsTab />,
      },
    ];

    const visibleTabs = allTabs;

    return {
      names: visibleTabs.map(
        (tab) =>
          PROFILE_TABS.find((item) => item.id == tab.id)?.label ?? tab.id,
      ),
      icons: visibleTabs.map((tab) => {
        if (tab.id == "overview") return <User size={16} />;
        if (tab.id == "dashboard") return <ChartLine size={16} />;
        if (tab.id == "alerts") return <Notification size={16} />;
        if (tab.id == "wallets") return <Wallet size={16} />;
        if (tab.id == "watchlist") return <StarFilled size={16} />;
        if (tab.id == "subscriptions") return <Receipt size={16} />;
        if (tab.id == "settings") return <Settings size={16} />;
        return <Activity size={16} />;
      }),
      nodes: visibleTabs.map((tab) => tab.node),
    };
  }, [walletAddresses, period, profileData]);

  useEffect(() => {
    if (activeTab <= tabsConfig.names.length - 1) return;
    setActiveTab(0);
  }, [activeTab, tabsConfig.names.length]);

  return (
    <PageWrapper wideContent>
      {loading || profileLoading ? (
        <ProfileLoadingState />
      ) : (
        <div className={styles.profileTabsShell}>
          <TabContainer
            activeTab={activeTab}
            names={tabsConfig.names}
            tabIcons={tabsConfig.icons}
            tabs={tabsConfig.nodes}
            onTabChange={setActiveTab}
            orientation="vertical"
            variant="profile"
            style={{ height: "100%" }}
          />
        </div>
      )}
    </PageWrapper>
  );
}

import client from "@/api/main";
import {
  GlobalPrices,
  NewsTab,
  TokenAIChat,
  TokenHeader,
  TokenInsightTabs,
  TokenMarketsTable,
  TokenOverviewChart,
  TokenOverviewStats,
  TokenTabs,
} from "@/components/token";
import { PageWrapper } from "@/components/wrapper/PageWrapper";
import { useLocalization } from "@/contexts/LocalizationContext";
import { useGet } from "@/hooks/useGet";
import { useRef, useState } from "react";
import { useParams } from "react-router";
import styles from "./index.module.scss";

function useTokenOverviewData(address: string) {
  const tokenDetails = useGet(
    client.api.tokens.details[":addresses"],
    200,
    {
      param: {
        addresses: address,
      },
    },
    {
      select: (data) => ({
        ...data[0].meta,
        ...data[0].details,
      }),
    },
  );

  const holders = useGet(client.api.tokens.holders[":address"], 200, {
    param: { address },
  });

  const marketData = useGet(client.api.tokens.markets[":addresses"], 200, {
    param: { addresses: address },
  });

  const isLoading = tokenDetails.isLoading || marketData.isLoading;
  const error = tokenDetails.error || marketData.error;

  if (!tokenDetails.data || !marketData.data) {
    return {
      isLoading,
      isFirstLoad: true,
      error,
      data: null as null,
    };
  }

  const details = Array.isArray(tokenDetails.data)
    ? tokenDetails.data[0] ?? null
    : tokenDetails.data ?? null;

  return {
    isLoading,
    isFirstLoad: false,
    error: null,
    data: {
      details,
      holders: holders.data ?? [],
      market: marketData.data?.[address] ?? null,
    },
  };
}

