          walletAddress: r.wallet,
          buyVolume: buyVol,
          sellVolume: sellVol,
          totalVolume: total,
          buyTransactionCount: buyTx,
          sellTransactionCount: sellTx,
          totalTransactionCount: totalTx,
        };
      })
    : [];

  return { wallets, metadata: { currency: "USD", timestamp: Date.now() } };
}

