      render(<SolanaPaymentFlow {...defaultProps} />);

      fireEvent.click(screen.getByRole("button", { name: /confirm payment with sol/i }));

      await waitFor(() => {
        expect(defaultProps.onError).toHaveBeenCalledWith(
