        success: true,
        subscriptionId: "sub-123",
        status: "active",
        txId: MOCK_TX_SIG,
      });

      render(<SolanaPaymentFlow {...defaultProps} />);

      fireEvent.click(screen.getByRole("button", { name: /confirm payment with sol/i }));

      await waitFor(() => {
        expect(mockSimulateTransaction).toHaveBeenCalledWith(
